    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '이론 윤리학', '이론 윤리학은 도덕 판단의 기준이 되는 도덕 원리가 중요하다고 주장한다.', true, '이론 윤리학은 도덕을 판단하는 기준을 설정하고 정당화하는 작업을 주요 과제로 삼는다.'),
    (gen_random_uuid()::text, set_id, 2, '이론 윤리학', '이론 윤리학은 도덕 판단을 위한 도덕규범의 필요성을 중시한다.', true, '이론 윤리학은 도덕 규범 설정을 핵심 과제로 삼으므로 도덕규범의 필요성을 중시한다.'),
    (gen_random_uuid()::text, set_id, 3, '이론 윤리학', '이론 윤리학은 도덕적 삶의 지침이 되는 보편적 원리를 제시한다.', true, '보편적 원리나 보편적 도덕법칙을 세우고자 하는 시도는 전통적인 의무론, 공리주의, 덕 윤리 등에서 공통적으로 찾을 수 있는 규범 윤리학의 핵심 과제이다.'),
    (gen_random_uuid()::text, set_id, 4, '이론 윤리학', '이론 윤리학은 도덕 판단의 준거와 행위의 정당성 확보를 강조한다.', true, '어떤 행위가 정당하고 바람직한지 판별하기 위해서는 그 근거가 필요하며, 이를 정립하고 정당화하는 것이 이론 윤리학이 추구하는 목표 중 하나이다.'),
    (gen_random_uuid()::text, set_id, 5, '이론 윤리학', '이론 윤리학은 행위의 옳고 그름을 구분하는 도덕 법칙을 제시한다.', true, '의무론, 공리주의, 덕 윤리 등 전형적인 이론 윤리학은 이를 제시하려 한다.'),
    (gen_random_uuid()::text, set_id, 6, '이론 윤리학', '이론 윤리학은 도덕적 실천을 위해 맥락적 사고의 배제가 중요하다고 주장한다.', false, '이론 윤리학의 입장이 아니다. 이론 윤리학에서도 맥락을 고려해야 한다는 이론도 존재한다.'),
    (gen_random_uuid()::text, set_id, 7, '이론 윤리학', '이론 윤리학은 도덕적 규범들의 체계를 구축하고 정당화하고자 한다.', true, '전통적인 규범 윤리학의 주요 학설은 모두 도덕성의 기초를 설명하기 위한 이론들이며, 이를 통해 근거를 밝히고 도덕 규범 체계를 이론적으로 구성하는 것이 규범 윤리학의 전형적인 작업이다.'),
    (gen_random_uuid()::text, set_id, 8, '이론 윤리학', '이론 윤리학은 도덕 추론의 논리적 구조를 밝히는 데 주력해야 한다.', false, '도덕 추론의 논리적 구조를 밝히는 데 주력하는 윤리학은 메타 윤리학이다.'),
    (gen_random_uuid()::text, set_id, 9, '이론 윤리학', '이론 윤리학은 도덕 법칙이 시공을 초월한 보편타당성을 지녀야 한다.', true, '이론 윤리학은 대개 보편적이거나 일반적인 도덕 법칙이나 원리의 존재를 탐색하고 정당화하는 데 초점을 맞춘다.'),
    (gen_random_uuid()::text, set_id, 10, '이론 윤리학', '이론 윤리학은 도덕 원리의 정립보다 타 문화에 대한 이해가 중요하다.', false, '타 문화에 대한 이해가 중요하다고 보는 것은 기술 윤리학이다. 이론 윤리학은 도덕 원리의 정립에 초점을 둔다.'),
    (gen_random_uuid()::text, set_id, 11, '이론 윤리학', '이론 윤리학은 어떻게 행동해야 하는가에 대한 규범적 원리를 정립한다.', true, '이론 윤리학의 핵심 과제이다.'),
    (gen_random_uuid()::text, set_id, 12, '이론 윤리학', '이론 윤리학은 도덕 규범과 의무의 근거가 되는 보편적 원리를 정립한다.', true, '규범 윤리학의 과제에 해당한다.'),
    (gen_random_uuid()::text, set_id, 13, '이론 윤리학', '이론 윤리학은 도덕적 행위에 대한 이론적 분석과 정당화 문제를 해결해야 한다.', true, '이론 윤리학의 목표이다.'),
    (gen_random_uuid()::text, set_id, 14, '이론 윤리학', '이론 윤리학은 도덕 문제 해결을 위한 규범 윤리 이론의 응용 가능성을 부정한다.', false, '규범 윤리학은 윤리 이론을 통해 실제 도덕 문제 해결에 도움을 줄 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 15, '이론 윤리학', '이론 윤리학은 윤리 이론을 정립할 때 메타윤리학의 연구 결과를 활용할 수 있다.', true, '도덕 추론의 논리 구조 분석, 의미 분석, 타당성 평가 등을 메타 윤리학에서 중점적으로 다루지만, 그 결과는 이론 윤리학에서 규범을 정립할 때 활용될 수 있다.'),
    (gen_random_uuid()::text, set_id, 16, '이론 윤리학', '이론 윤리학은 의무, 공리, 덕성 등의 이론적 근거를 통해 도덕성의 기초를 정립한다.', true, '이론 윤리학(의무론, 공리주의, 덕 윤리)의 대표적 과제이다.'),
    (gen_random_uuid()::text, set_id, 17, '실천 윤리학', '실천 윤리학은 보편적인 도덕 법칙의 규명을 핵심 과제로 삼는다.', false, '보편적이고 추상적인 원리의 정립은 주로 이론 윤리학에서 다루며, 실천 윤리학은 구체적 상황과 문제 해결에 중점을 둔다.'),
    (gen_random_uuid()::text, set_id, 18, '실천 윤리학', '실천 윤리학은 윤리학과 인접 학문들의 학제적인 연계를 중시한다.', true, '실천 윤리학은 의료, 법학, 경제학 등 다양한 영역과 협력하여 실제 쟁점을 다루므로 학제적 접근을 강조한다.'),
    (gen_random_uuid()::text, set_id, 19, '실천 윤리학', '실천 윤리학은 도덕 언어의 분석을 윤리학적 탐구의 본질로 간주한다.', false, '도덕 개념이나 언어 분석은 메타윤리학의 주된 영역이므로, 실천 윤리학의 현실 문제 해결과는 주요 과제로 삼지 않는다.'),
    (gen_random_uuid()::text, set_id, 20, '실천 윤리학', '실천 윤리학은 현실적 도덕 문제의 구체적인 해결책 모색을 중시한다.', true, '현실에서 발생하는 윤리적 갈등이나 딜레마에 대한 실천적 해답을 찾는 것이 실천 윤리학의 핵심 목표이다.'),
    (gen_random_uuid()::text, set_id, 21, '실천 윤리학', '실천 윤리학은 윤리학은 도덕 언어의 의미 분석을 중점 과제로 삼는다.', false, '이는 메타 윤리학의 과제이다.'),
    (gen_random_uuid()::text, set_id, 22, '실천 윤리학', '실천 윤리학은 보편적 도덕 원리를 현실의 개별 상황에 적용해야 한다.', true, '보편적이고 추상적인 도덕 원리를 현실의 구체적인 문제에 적용해 해결하는 것이 실천 윤리학의 핵심 목표이다.'),
    (gen_random_uuid()::text, set_id, 23, '실천 윤리학', '실천 윤리학은 윤리적 문제의 해결은 가치를 분별하는 과정과 무관하다.', false, '윤리 문제 해결에서는 가치 판단과 우선순위 설정이 필수적이므로, 가치를 분별하는 과정과 분리될 수 없다.'),
    (gen_random_uuid()::text, set_id, 24, '실천 윤리학', '실천 윤리학은 도덕 원리를 응용하여 구체적 삶의 도덕 문제를 해결한다.', true, '실천 윤리학은 규범 윤리학이나 메타윤리학 등 전통적 토대를 참조하여 구체적 쟁점을 해결할 방안을 마련한다.'),
    (gen_random_uuid()::text, set_id, 25, '실천 윤리학', '실천 윤리학은 현실 문제에 대한 도덕 원리의 적용을 핵심 과제로 삼는다.', true, '실천 윤리학의 과제이다.'),
    (gen_random_uuid()::text, set_id, 26, '실천 윤리학', '실천 윤리학은 현실의 윤리 문제 해결을 위해 이론 윤리학을 필요로 한다.', true, '현대 사회의 다양한 새로운 윤리 문제(인공지능, 생명공학 등)를 다루는 실천 윤리학은 이론 윤리학의 도움을 받는다.'),
    (gen_random_uuid()::text, set_id, 27, '실천 윤리학', '실천 윤리학은 도덕규범의 현실적인 적용과 구체적인 대안의 실천을 강조한다.', true, '실천 윤리학의 특징이다.'),
    (gen_random_uuid()::text, set_id, 28, '실천 윤리학', '실천 윤리학은 기후 변화 등 새로운 쟁점에 대한 윤리적 해법을 모색해야 한다.', true, '현대 사회의 새로운 윤리 문제(인공지능, 생명공학, 기후 변화 등)가 실천 윤리학의 주요 연구 대상이다.'),
    (gen_random_uuid()::text, set_id, 29, '실천 윤리학', '실천 윤리학은 윤리학의 학문적 성립 가능성을 논리적으로 엄밀하게 검토해야 한다.', false, '윤리학 자체의 학문적 성립 가능성을 검토하는 작업은 메타윤리학의 영역이며 실천 윤리학의 직접적 과제가 아니다.'),
    (gen_random_uuid()::text, set_id, 30, '실천 윤리학', '실천 윤리학은 인접 학문 영역과는 분리된 윤리학의 학문적 정체성을 정립해야 한다.', false, '실천 윤리학은 타 학문과의 융합이나 협력을 통해 구체적 문제 해결을 추구한다. 이러한 성격을 학제적이라고 한다.'),
    (gen_random_uuid()::text, set_id, 31, '실천 윤리학', '실천 윤리학은 윤리학은 구체적 삶의 도덕적 딜레마를 가치 개입적으로 해결해야 한다.', true, '실제 문제 해결을 위해서는 가치 중립보다는 가치 판단과 선택이 필수적이며, 이를 통해 도덕적 갈등을 조정한다.'),
    (gen_random_uuid()::text, set_id, 32, '메타 윤리학', '메타 윤리학은 도덕적 추론에 대한 가치중립적 분석이 중요하다.', true, '메타 윤리학은 특정 도덕적 입장을 옹호하거나 반대하기보다, 도덕 추론 자체가 어떻게 가능한지를 가치중립적으로 분석하는 학문이다.'),
    (gen_random_uuid()::text, set_id, 33, '메타 윤리학', '메타 윤리학은 도덕적 지식의 성립 가능성에 대한 탐구가 필요하다.', true, '도덕 판단이 과연 지식일 수 있는가에 대해 탐구하는 의미의 명제이다. 이는 메타 윤리학의 주요 탐구 과제이다.'),
    (gen_random_uuid()::text, set_id, 34, '메타 윤리학', '메타 윤리학은 선하다, 옳다 등과 같은 도덕적 언어의 의미를 분석한다.', true, '메타 윤리학은 대표적으로 도덕적 개념(좋다, 나쁘다, 옳다, 그르다 등)의 의미가 무엇인지, 이 말들이 지칭하는 바가 있는지를 분석하는 학문 분야이다.'),
    (gen_random_uuid()::text, set_id, 35, '메타 윤리학', '메타 윤리학은 언어 분석을 통해 윤리적 딜레마를 해소해야 함을 강조한다.', true, '메타 윤리학은 많은 윤리적 논쟁이 언어 사용의 혼동에서 비롯된다고 보았다. 이들은 도덕 언어 자체를 분석함으로써 모호하거나 중의적 표현에서 비롯된 윤리적 딜레마를 해소할 수 있다고 보았다.'),
    (gen_random_uuid()::text, set_id, 36, '메타 윤리학', '메타윤리학은 윤리학이 학문적으로 성립 가능한지 검증하고자 한다.', true, '메타 윤리학은 윤리학 자체가 학문이 될 수 있는지, 만약 그렇다면 어떤 조건에서 가능한지를 다룬다.'),
    (gen_random_uuid()::text, set_id, 37, '메타 윤리학', '메타 윤리학은 도덕 추론의 논증 가능성과 논리적 타당성을 규명하는 것이 주요 과제이다.', true, '도덕 명제가 논리적으로 추론될 수 있는가, 혹은 당위 명제가 사실 명제로부터 어떻게 도출되는가 같은 질문으로 도덕 추론의 논증 가능성과 논리적 타당성을 따져보는 것이 메타 윤리학의 대표적 쟁점이다.'),
    (gen_random_uuid()::text, set_id, 38, '메타 윤리학', '메타 윤리학은 인간의 바람직한 삶의 방향을 제시하는 것이다.', false, '이는 규범 윤리학의 과제에 해당한다. 메타윤리학은 특정 가치관이나 행동 지침을 직접적으로 제시하는 데 관심이 있지 않다.'),
    (gen_random_uuid()::text, set_id, 39, '메타 윤리학', '메타 윤리학은 윤리학의 본질적 성격은 당위의 학문이라는 것이다.', false, '윤리학을 당위 명제를 다루는 학문이라고 하는 것은 흔히 규범 윤리학에 쓰이는 정의이다. 메타 윤리학은 정말 윤리가 당위를 다루는지, 그 자체를 분석 대상으로 삼는다.'),
    (gen_random_uuid()::text, set_id, 40, '메타 윤리학', '메타 윤리학은 도덕 문제 탐구에 사회 자연 과학적 지식이 필요하다.', false, '도덕 문제 탐구에 사회 자연과학적 지식이 필요하다는 주장은 실천 윤리학의 학제적 특징을 말해 준다고도 할 수 있다.'),
    (gen_random_uuid()::text, set_id, 41, '메타 윤리학', '메타 윤리학은 도덕 현상은 과학적으로 기술해야 할 사실의 집합이다.', false, '도덕을 사회 과학이나 자연 과학적으로 기술해야 할 사실의 집합으로 보는 것은 기술 윤리학의 관점이다.'),
    (gen_random_uuid()::text, set_id, 42, '메타 윤리학', '메타 윤리학은 특정 시대의 관습에 대해 조사하고 객관적으로 기술한다.', false, '도덕 현상과 그 인과 관계를 객관적으로, 경험적으로, 가치 평가 없이 기술하는 것은 기술 윤리학의 탐구 과제에 해당한다.'),
    (gen_random_uuid()::text, set_id, 43, '메타 윤리학', '메타 윤리학은 도덕 현상의 인과 관계를 경험과학적으로 설명하는 것이다.', false, '기술 윤리학의 관점이다.'),
    (gen_random_uuid()::text, set_id, 44, '메타 윤리학', '메타 윤리학은 윤리학의 핵심 과제는 경험적 연구를 통한 도덕성의 검증이다.', false, '경험적 검증은 기술 윤리학의 과제이다.'),
    (gen_random_uuid()::text, set_id, 45, '메타 윤리학', '메타 윤리학은 도덕 현상에 대한 객관적 서술과 인과 관계의 설명을 강조한다.', false, '기술 윤리학의 관점이다.'),
    (gen_random_uuid()::text, set_id, 46, '메타 윤리학', '메타 윤리학은 특정 문화권의 도덕 현상을 가치 평가 없이 설명하는 것이 주요 과제이다.', false, '기술 윤리학의 과제이다.'),
    (gen_random_uuid()::text, set_id, 47, '기술 윤리학', '기술 윤리학은 도덕적 관습을 실증적으로 연구해야 한다.', true, '기술 윤리학은 도덕적 관습을 실증적, 경험적 방식으로 조사하고 연구하는 것을 핵심 과제로 삼는다.'),
    (gen_random_uuid()::text, set_id, 48, '기술 윤리학', '기술 윤리학은 현실적 도덕에 대한 가치 중립적 설명이 필요하다.', true, '기술 윤리학은 어떤 도덕이 옳다, 그르다를 규정하기보다는, 그 도덕적 현상이 어떠한지 가치 중립적으로 기술하고 설명하려 한다.'),
    (gen_random_uuid()::text, set_id, 49, '기술 윤리학', '기술 윤리학은 도덕 관행의 발생 과정을 객관적으로 설명해야 한다.', true, '기술 윤리학은 도덕 관행이 언제, 어떤 배경에서, 어떻게 생겨나는지, 또 그것이 어떠한 사회 심리 역사적 맥락에서 비롯되었는지를 인과적으로 추적하고 설명하는 데 관심이 있다.'),
    (gen_random_uuid()::text, set_id, 50, '기술 윤리학', '기술 윤리학은 도덕적 문제의 발생에 대한 인과적 설명이 중요하다.', true, '기술 윤리학은 도덕 문제와 그 발생 배경을 인과적이고 경험적으로 서술한다.'),
    (gen_random_uuid()::text, set_id, 51, '기술 윤리학', '기술 윤리학은 인간의 가치 판단을 배제하여 객관성을 확보해야 한다.', true, '기술 윤리학은 어떤 것이 옳다고 믿는 바를 개입시키지 말고, 가치 중립적으로 현상을 기술하려고 노력해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 52, '기술 윤리학', '기술 윤리학은 도덕 법칙이 시공을 초월한 보편타당성을 지녀야 한다.', false, '주로 규범 윤리학에서 도덕 법칙이 보편타당성을 지녀야 한다고 주장한다. 기술 윤리학은 보편타당성을 주장하거나 반박하기보다, 사람들이 실제로 어떻게 행동하는가를 기술하는 데 집중한다.'),
    (gen_random_uuid()::text, set_id, 53, '기술 윤리학', '기술 윤리학은 도덕 이론과 도덕 문제 간의 유기적 상관성을 강조한다.', false, '도덕 이론과 도덕 문제의 유기적 상관성은 규범 윤리학이 강조한다. 즉 실제 문제를 해결하기 위해 이론을 적용해야 한다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 54, '기술 윤리학', '기술 윤리학은 도덕 문제를 해결하기 위해 실천적 지침을 제공해야 한다.', false, '도덕 문제 해결을 위한 실천 방안 제시는 전형적으로 실천 윤리학에서 하는 역할이다.'),
    (gen_random_uuid()::text, set_id, 55, '기술 윤리학', '기술 윤리학은 도덕 추론에 대한 논리 구조 분석의 필요성을 주장한다.', false, '도덕 추론의 논리 구조, 의미 분석, 타당성 평가는 메타 윤리학에서 중점적으로 다루는 것이다.'),
    (gen_random_uuid()::text, set_id, 56, '기술 윤리학', '기술 윤리학은 도덕적 관습에 관한 경험적 서술이 갖는 의의를 중시한다.', true, '기술 윤리학은 도덕적 관습에 대한 경험적 조사와 서술을 가장 핵심적인 과제로 삼는다.'),
    (gen_random_uuid()::text, set_id, 57, '기술 윤리학', '기술 윤리학은 도덕 언어의 개념 분석과 도덕 논증의 타당성 입증을 중시한다.', false, '도덕 언어(선, 옳음, 의무 등)의 개념 분석과 도덕 논증의 논리적 타당성 여부에 초점을 두는 것은 메타 윤리학에서 하는 일이다.'),
    (gen_random_uuid()::text, set_id, 58, '기술 윤리학', '기술 윤리학은 도덕규범이 형성된 인과 관계에 대한 경험적인 탐구를 중시한다.', true, '규범이 어떠한 사회 심리적 과정을 거쳐 형성되는지를 경험적으로 연구하는 것은 기술 윤리학이 하는 작업이다.'),
    (gen_random_uuid()::text, set_id, 59, '기술 윤리학', '기술 윤리학은 각 문화권의 도덕 현상을 조사하고 객관적으로 기술하는 것이다.', true, '기술 윤리학은 문화인류학적 연구, 사회학적 조사 등을 통해 이 문화권에서는 이런 가치나 규범이 어떻게 작동하는가 등을 연구하고 객관적으로 서술하는 학문이다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '유교', '유교는 인위적인 가치를 버려야 한다고 주장한다.', false, '인위적 가치를 버리라는 것은 유교가 아니라 도가의 입장이다.'),
    (gen_random_uuid()::text, set_id, 2, '유교', '유교는 오로지 예만 듣고 보아야 한다고 주장한다.', true, '유교의 입장으로 적절하다. 공자는 예가 아니면 보지 말고, 예가 아니면 듣지 말고, 예가 아니면 말하지 말고, 예가 아니면 움직이지도 말아야 한다고 말했다(극기복례).'),
    (gen_random_uuid()::text, set_id, 3, '유교', '유교는 사사로운 마음을 비워야 한다고 주장한다.', true, '사욕을 극복하라는 입장은 유교의 극기복례에서 말하는 극기에 해당한다. 마음을 비워라는 표현만 보고 도가의 수양법인 허심으로 생각하기 쉽지만, 이 선지는 수능에서 유교의 입장으로 출제된 바 있다.'),
    (gen_random_uuid()::text, set_id, 4, '유교', '유교는 타고난 사단을 확충해야 한다고 주장한다.', true, '지학사 교과서에 따르면 모든 인간이 본래부터 가지고 있는 선천적인 것으로, 남을 불쌍히 여기는 마음, 옳지 못한 일을 부끄러워하고 미워하는 마음, 양보하고 공경하는 마음, 옳고 그름을 구별하는 마음이 사단이다.'),
    (gen_random_uuid()::text, set_id, 5, '유교', '유교는 거경으로 덕을 함양해야 한다고 주장한다.', true, '거경은 마음을 한곳으로 모아 흐트러짐이 없게 하는 수양 방법이다.'),
    (gen_random_uuid()::text, set_id, 6, '유교', '유교는 사욕을 극복하고 예를 회복해야 한다고 주장한다.', true, '유교의 극기복례에 해당한다.'),
    (gen_random_uuid()::text, set_id, 7, '유교', '유교는 효의 실천 범위를 가정에서 사회로 점차 확대해야 한다고 주장한다.', true, '유교에서 효제란 부모와 자식 사이의 효와 형제와 어른들에 대한 공경을 의미한다. 공자는 인의 확장을 주장하며 천하까지 확장하면 천하가 태평해진다고 보았다. 인이 천하로 확장된 것이 공자의 이상 사회인 대동사회이다.'),
    (gen_random_uuid()::text, set_id, 8, '유교', '유교는 개인적 이익보다 공동체에 대한 책임을 우선시해야 한다고 주장한다.', true, '유교에서는 자기 욕심을 극복하고 인과 의를 실천함으로써 공동체를 도모해야 한다고 보았다. 사사로운 이익보다는 사회와 백성을 위해 헌신하는 자세를 강조하는 것이다.'),
    (gen_random_uuid()::text, set_id, 9, '유교', '유교는 유능한 인재가 선발되는 도덕 공동체를 지향해야 한다고 주장한다.', true, '공자의 대동사회는 유능한 인재가 선발되는 도덕 공동체이다.'),
    (gen_random_uuid()::text, set_id, 10, '유교', '유교는 인의 시작은 모든 사람에 대한 차별 없는 사랑이라고 주장한다.', false, '유교의 인은 모든 사람에 대한 차별 없는 사랑이 아니라, 친족을 비롯하여 가족에서 사회로 확대되는 사랑이다. 차별 없는 사랑은 묵가(겸애)의 입장이다.'),
    (gen_random_uuid()::text, set_id, 11, '유교', '유교는 자신의 직분과 지위에 걸맞게 예법을 충실히 따라야 한다고 주장한다.', true, '공자는 개인이 맡은 사회적 역할에 걸맞는 내실을 갖추어야 한다고 주장한다. 가령, 임금은 임금답게, 신하는 신하답게, 아버지는 아버지답게, 자식은 자식답게 그 본분과 의무를 다하게 되면, 사회가 질서정연하게 정립될 것이라고 본다(정명).'),
    (gen_random_uuid()::text, set_id, 12, '유교', '유교는 시비선악을 구분하여 질서를 바로 세워야 한다고 주장한다.', true, '공자의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 13, '유교', '유교는 이상적 인간은 수양을 통해 백성의 편안함을 도모해야 한다고 주장한다.', true, '수기치인 사상에 따라, 도덕적 수양을 쌓은 지도자가 백성을 편안히 다스릴 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 14, '유교', '유교는 이상적 인간은 자신의 명예를 소중히 여기는 삶을 살아야 한다고 주장한다.', true, '유교에서는 살신성인의 자세를 강조하며, 비록 죽는 한이 있더라도 자신의 의로움과 명예를 지키며 살아가는 태도를 강조한다.'),
    (gen_random_uuid()::text, set_id, 15, '유교', '유교는 내가 하기 싫은 일을 남에게 시키지 않는 서를 행해야 한다고 주장한다.', true, '공자의 서에 해당하는 선지이다. 서는 내 마음으로 다른 사람을 헤아린다는 뜻으로 내가 하기 싫은 일을 다른 사람에게 시키지 말라는 논어의 구절을 통해 잘 드러난다.'),
    (gen_random_uuid()::text, set_id, 16, '유교', '유교는 이상적 인간은 하늘의 명을 도덕적 실천의 근거로 삼는다고 주장한다.', true, '유교에서는 하늘을 도덕과 질서의 궁극적 근거로 여기며, 군자는 천명에 따라 올바른 길을 실천해야 한다고 주장한다. 맹자 역시 하늘이 부여한 본성을 확충하고 도덕적 실천을 하는 것이 곧 천명을 따르는 것이라고 보았다.'),
    (gen_random_uuid()::text, set_id, 17, '유교', '유교는 분별적 지혜를 발휘하여 도덕 질서를 확립해야 한다고 주장한다.', true, '유교 사상가 공자는 존비친소와 선악을 분별하는 분별적 지혜를 추구한다. 이처럼 유교에서는 시비를 엄격히 구분하여 질서를 바로잡아야 한다고 본다. 공자가 주장하는 인도 시비선악을 분별하여 실천하는 사랑이다.'),
    (gen_random_uuid()::text, set_id, 18, '유교', '유교는 인의의 강조는 사회 혼란의 원인이 될 수 있다고 주장한다.', false, '유교가 아니라 도가의 입장이다.'),
    (gen_random_uuid()::text, set_id, 19, '유교', '유교는 인륜의 규범에서 벗어나야 이상적 인간이 될 수 있다고 주장한다.', false, '맹자는 인륜의 규범을 따라야 이상적 인간에 도달할 수 있다고 주장하므로 유교의 입장으로 적절하지 않다.'),
    (gen_random_uuid()::text, set_id, 20, '유교', '유교는 하늘이 부여한 순선한 본성을 따르는 삶을 살아가야 한다고 주장한다.', true, '유교의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 21, '유교', '유교는 서의 실천을 통해 진정한 인다움을 이룰 수 있다고 주장한다.', true, '서는 주로 공자가 강조하지만, 서의 실천을 통해 인을 실천할 수 있다는 내용은 공자를 계승한 맹자를 비롯한 유교 사상가들이 동의할 내용이다.'),
    (gen_random_uuid()::text, set_id, 22, '유교', '유교는 나쁜 환경에 처한 사람은 반드시 자신의 본성을 잃게 된다고 주장한다.', false, '유교에 따르면 나쁜 환경에 처한 사람이 반드시 자신의 본성을 잃는다고 보지 않는다. 맹자는 도덕적 인격인 선비, 대장부는 어려운 상황에서도 자신의 도덕적 본성을 잃지 않을 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 23, '유교', '유교는 군자는 항산이 있어야만 항심을 유지할 수 있다고 주장한다.', false, '유교 사상가 맹자에 따르면 항산이 있어야만 항심을 유지할 수 있는 것은 일반 백성이다. 맹자는 선비(군자)만이 안정된 생업이 없으면서도 안정된 마음을 가질 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 24, '유교', '유교는 이상적 인간은 시비를 판별하여 도를 따라야 한다고 주장한다.', true, '유교에서는 분별적 지혜를 바탕으로 시비와 선악을 구분하여 도에 따라 살아가는 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 25, '유교', '유교는 이상적 인간은 수양을 통해 백성의 편안함을 도모해야 한다고 주장한다.', true, '유교는 기본적으로 수양을 쌓은 후에야 비로소 다른 사람을 편안하게 할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 26, '유교', '유교는 이상적 인간은 모든 분별에서 벗어나 자연을 따르는 사람이라고 주장한다.', false, '유교가 아니라 도가의 입장이다.'),
    (gen_random_uuid()::text, set_id, 27, '유교', '유교는 다른 사람을 편안하게 한 후에야 비로소 자기 수양이 가능하다고 주장한다.', false, '순서가 반대이다. 유교는 수기(자기 수양)가 먼저이고 치인(타인 편안)이 그 다음이다.'),
    (gen_random_uuid()::text, set_id, 28, '유교', '유교는 자신을 구속하는 일체의 것을 잊어버리고 자유롭게 살아야 한다고 주장한다.', false, '유교가 아니라 도가의 입장(좌망)에 해당한다.'),
    (gen_random_uuid()::text, set_id, 29, '유교', '유교는 수오의 마음은 의로운 행위를 꾸준히 실천해야만 생겨난다고 주장한다.', false, '맹자에 따르면 수오지심은 선천적으로 타고난 사단 중 하나이다. 수오지심은 자신의 잘못을 부끄러워하고 타인의 잘못을 미워하는 마음으로서 의의 단이다. 맹자는 이러한 수오지심을 비롯하여 측은지심, 사양지심, 시비지심 등의 사단을 인간이 선천적으로 갖고 있는 본래적인 마음으로 규정한다. 후천적으로 배워서 생기는 것이 아니라 내면에서 자연스럽게 생기는 것으로 본다.'),
    (gen_random_uuid()::text, set_id, 30, '유교', '유교는 오륜의 참된 실천은 반드시 수기가 바탕이 되어야 한다고 주장한다.', true, '유교 사상가 맹자는 도덕적 행동을 실천하고 도덕적인 삶을 살기 위해서는 수양을 통해 자기 자신을 닦아야 한다고 주장한다. 따라서 오륜이라는 도덕규범의 실천을 위해서 맹자는 수기가 필요하다고 본다.'),
    (gen_random_uuid()::text, set_id, 31, '유교', '유교는 이상적 인간은 하늘의 명을 도덕적 실천의 근거로 삼아야 한다고 주장한다.', true, '유교는 하늘을 도덕적 실천의 근거로 간주하고, 하늘이 도덕적 삶의 근거가 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 32, '불교', '불교는 일체의 탐욕과 집착을 버려야 한다고 주장한다.', true, '불교에서는 탐욕과 집착으로 인해 인간의 삶이 고통스러워진다고 본다. 부처는 괴로움의 원인으로 탐욕, 분노, 무지의 번뇌를 들고, 이를 삼독이라고 설명했다.'),
    (gen_random_uuid()::text, set_id, 33, '불교', '불교는 연기의 법칙을 깨달아야 한다고 주장한다.', true, '불교에서는 세상 모든 현상과 존재들이 원인과 조건에 의해 생기고 일어나며 인연이 없으면 결과도 없다고 주장한다'),
    (gen_random_uuid()::text, set_id, 34, '불교', '불교는 자타를 한몸으로 여겨야 한다고 주장한다.', true, '불교에 따르면, 너와 내가 둘이 아니라는 자타불이는 만물에 대한 자비심을 낳게 하는 것이다.'),
    (gen_random_uuid()::text, set_id, 35, '불교', '불교는 만물은 서로 관련되고 상호 의존한다고 주장한다.', true, '연기의 핵심 내용으로 불교의 입장에 부합한다.'),
    (gen_random_uuid()::text, set_id, 36, '불교', '불교는 고정불변의 실체가 있음을 깨달아야 한다고 주장한다.', false, '불교는 만물이 고정된 독립적 실체라는 것을 부정하며, 이처럼 고정불변의 실체가 없음을 통찰해 괴로움에서 벗어나 열반에 이를 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 37, '불교', '불교는 연기의 법칙을 깨달아 자비의 정신을 실천해야 한다고 주장한다.', true, '불교에 따르면 자타불이는 만물에 대한 자비심을 낳게 하는 것이다.'),
    (gen_random_uuid()::text, set_id, 38, '불교', '불교는 해탈에 이르기 위한 바라밀의 실천을 중시해야 한다고 주장한다.', true, '해탈은 번뇌의 얽매임에서 풀리고 괴로움에서 벗어난 경지를 말한다.'),
    (gen_random_uuid()::text, set_id, 39, '불교', '불교는 삼독을 제거하여 자신의 본성을 깨우쳐야 한다고 주장한다.', true, '불교에 따르면, 삼독을 제거함으로 자신의 본성을 깨우치고 무명에서 벗어나 모든 번뇌와 고통이 사라진 상태에 이르면, 깨달음을 얻고 고요한 본성을 깨우칠 수 있다.'),
    (gen_random_uuid()::text, set_id, 40, '불교', '불교는 사랑의 실천이 모든 사람에게까지 이르는 것이 중요하다고 주장한다.', true, '불교에 따르면 자비라는 사랑이 모든 사람에게 차별 없이 적용되어야 한다.'),
    (gen_random_uuid()::text, set_id, 41, '불교', '불교는 내 마음의 참된 진리를 깨닫기 위해 참선해야 한다고 주장한다.', true, '참선은 불교의 수행 방법 중 하나이다. 불교에서는 참선을 통해 내면을 성찰하며, 집착과 번뇌에서 벗어나 불성을 깨달을 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 42, '불교', '불교는 만물의 상호 의존성을 깨달아 열반을 지향해야 한다고 주장한다.', true, '만물이 상호 의존하고 있음을 깨달아 열반에 이르면 모든 고통에서 벗어날 수 있으며 고요하고 청정한 마음 상태를 가질 수 있다. 삶의 무상함을 깨닫고 고정불변의 실체가 없음을 통찰하면 괴로움에서 벗어나 열반에 이를 수 있다.'),
    (gen_random_uuid()::text, set_id, 43, '불교', '불교는 연기를 깨닫고 대중을 구제하는 삶을 지향해야 한다고 주장한다.', true, '불교의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 44, '불교', '불교는 모든 이들을 평등하게 대하는 자비의 마음을 지녀야 한다고 주장한다.', true, '자비는 불교 사상의 개념이다. 자비란 나와 남이 다르지 않다는 의식에서 나온 불교의 사랑으로 이해할 수 있다.'),
    (gen_random_uuid()::text, set_id, 45, '불교', '불교는 세상 모든 존재의 생멸은 연기에 의한 것으로 보아야 한다고 주장한다.', true, '연기법의 핵심 내용이다.'),
    (gen_random_uuid()::text, set_id, 46, '불교', '불교는 자아에 대한 집착이 괴로움의 원인이라고 주장한다.', true, '불교에서는 자아에 대한 집착이 괴로움의 원인이라고 본다. 왜냐하면, 연기에 의한 만물은 끊임없이 변화하기 때문에 변하지 않는 것이 없기 때문이다.'),
    (gen_random_uuid()::text, set_id, 47, '불교', '불교는 자아의식은 변하지 않는 실체임을 알아야 한다고 주장한다.', false, '불교는 무아를 주장하므로 자아의식이 변하지 않는 실체라고 주장할 수 없다.'),
    (gen_random_uuid()::text, set_id, 48, '불교', '불교는 차별하는 마음을 버려야 진리를 깨달을 수 있다고 주장한다.', true, '불교에 따르면 차별하는 마음이 없어야 진리를 깨달을 수 있다. 불교 윤리는 모든 것들이 의존적으로 존재한다고 본다.'),
    (gen_random_uuid()::text, set_id, 49, '불교', '불교는 정신에는 집착해도 물질에는 집착해서는 안 된다고 주장한다.', false, '불교에 따르면 모든 변화하는 무상한 것에 집착할 때 고통이 발생한다고 보고, 집착에서 벗어날 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 50, '불교', '불교는 내세를 위해 현실에서 도덕적 삶을 추구해야 한다고 주장한다.', true, '불교에서는 현세에서 지은 업에 따라 내세가 정해진다고 본다. 즉, 현세의 도덕적 실천이 내세의 삶을 결정한다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 51, '불교', '불교는 집착과 번뇌의 제거를 위한 수행이 반드시 필요하다고 주장한다.', true, '불교에 따르면 집착과 번뇌의 제거는 열반이라는 상태에 반드시 필요하다고 본다. 집착과 번뇌를 제거하고 깨달음을 얻기 위해서는 수행을 해야 한다.'),
    (gen_random_uuid()::text, set_id, 52, '불교', '불교는 팔정도의 수행을 통해 열반에 이르러야 한다고 주장한다.', true, '불교에 따르면 불법의 수행을 통해 열반에 이르러야 한다. 팔정도는 불교의 열반에 이르기 위해 강조된 수행 방법이다.'),
    (gen_random_uuid()::text, set_id, 53, '불교', '불교는 끊임없이 변화하는 세계에서 영원한 실체를 찾아야 한다고 주장한다.', false, '불교에 따르면 모든 것은 변화하는 무상한 것이다. 불교는 현상계에서 집착과 번뇌를 제거하기 위한 수행이 필요하다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 54, '불교', '불교는 개별 사물이 본질적으로 독립적 실체임을 자각해야 한다고 주장한다.', false, '불교에 따르면 모든 것이 고정불변의 실체가 없는 무상한 존재이며, 연기에 따라 상호 의존적으로 존재한다.'),
    (gen_random_uuid()::text, set_id, 55, '불교', '불교는 탐욕으로 생긴 번뇌는 깨달음을 얻더라도 소멸될 수 없다고 주장한다.', false, '불교에 따르면 불법의 수행을 통해 열반에 이르면 모든 해탈, 열반에 이르러 삼독, 번뇌, 집착 등의 고통의 원인들이 모두 소멸된다고 본다.'),
    (gen_random_uuid()::text, set_id, 56, '불교', '불교는 바른 수행으로 만물이 서로 독립하여 존재함을 깨달아야 한다고 주장한다.', false, '불교의 입장에서 세계의 영원히 변하는 것은 모두 영원한 실체는 존재하지 않고, 모든 것은 상호 의존적으로 존재한다.'),
    (gen_random_uuid()::text, set_id, 57, '불교', '불교는 나와 남이 둘이 아니라는 자각에서 만물에 대한 사랑이 생긴다고 주장한다.', true, '불교에 따르면 자타불이의 자각에서 자비심이 나온다고 본다. 자비는 불교의 자비 사랑으로 이해할 수 있다. 자비란 나와 남이 다르지 않다는 의식에서 나온 불교의 사랑으로 이해할 수 있다.'),
    (gen_random_uuid()::text, set_id, 58, '불교', '불교는 연기법에 대한 자각을 통해 변하지 않는 자아를 깨달아야 한다고 주장한다.', false, '불교에 따르면 연기의 법칙을 깨달아 되면 모든 것에 대하여 자비의 마음이 저절로 생길 뿐이며 고통의 근본적인 원인이 집착에서 벗어날 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 59, '도가', '도가는 인위에 얽매이지 않고 도에 따라야 한다고 주장한다.', true, '도가에서는 예법과 같은 인위적인 것을 멀리하고 천지만물의 근원인 도에 따라 자연스러운 삶을 살 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 60, '도가', '도가는 사회적 지위에 따른 예의와 규범을 중시해야 한다고 주장한다.', false, '예의와 규범을 중요시하는 것은 유교의 입장이지, 도가의 입장이 아니다.'),
    (gen_random_uuid()::text, set_id, 61, '도가', '도가는 인위적인 통치가 없는 소박한 사회를 지향해야 한다고 주장한다.', true, '노자는 통치자가 인위적 통치를 하지 않는 무위의 통치를 해야 한다고 본다. 또한 노자는 소국과민이라는 자연과 더불어 소박하게 사는 이상 사회를 주장한다.'),
    (gen_random_uuid()::text, set_id, 62, '도가', '도가는 분별적 지혜를 발휘하여 도덕 질서를 확립해야 한다고 주장한다.', false, '노자는 분별적 지혜를 버리라고 주장하며, 인위적 지혜와 도덕 질서가 오히려 사회 혼란의 원인이 된다고 본다. 따라서, 노자는 인위적인 분별적 지혜를 발휘하여 자연스러운 상태로 돌아가는 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 63, '도가', '도가는 성인의 다스림은 백성을 저절로 소박하게 한다고 주장한다.', true, '노자의 무위의 통치를 의미한다. 노자의 무위란 인위적인 행동을 하지 않고 자연의 흐름을 따르는 것을 의미한다. 이는 아무것도 하지 않는다는 뜻이 아니라 자연스러운 상태를 유지한다는 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 64, '도가', '도가는 예법을 통해 본래의 자연스러운 삶으로 돌아가야 한다고 주장한다.', false, '도가 사상은 노자는 자연스러운 삶으로 돌아가야 한다고 주장하지만, 이를 위해서 예법을 통해야 한다고 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 65, '도가', '도가는 인위를 버리고 상선약수의 도를 따라야 한다고 주장한다.', true, '노자는 무위자연의 삶을 물에 비유하여, 최고의 선은 물과 같다고 설명했다. 왜냐하면, 물은 만물을 이롭게 해주고, 다투지 않으며, 사람들이 싫어하는 낮은 곳에 머물기 때문이라고 기억해 두자.'),
    (gen_random_uuid()::text, set_id, 66, '도가', '도가는 예법에 집착하지 말고 자연의 흐름에 따라 살아야 한다고 주장한다.', true, '도가의 입장으로 적절하다. 도가에서는 유교의 인위적인 예법 같은 것을 부정하고 자연으로 돌아가자고 주장한다.'),
    (gen_random_uuid()::text, set_id, 67, '도가', '도가는 무위의 삶을 통해 타고난 본성을 변화시켜야 한다고 주장한다.', false, '무위의 삶을 통해 타고난 본성을 변화시켜야 한다는 것은 도가의 입장에 부합하지 않는다. 노자는 무위자연에 따르는 삶을 추구하였고, 타고난 자연적 본성을 실현해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 68, '도가', '도가는 물과 같은 겸허와 부쟁의 삶을 지향해야 한다고 주장한다.', true, '노자는 도에 따르는 것이 타고난 생명력과 자연성을 보존할 수 있으며, 본성을 따르는 사람이라고 본다.'),
    (gen_random_uuid()::text, set_id, 69, '도가', '도가는 도를 따르는 사람은 곧 본성을 따르는 사람이라 할 수 있다고 주장한다.', true, '도가의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 70, '도가', '도가는 이기적인 마음에서 벗어나기 위해 선정을 닦아야 한다고 주장한다.', false, '선정은 불교의 수행 방법이므로 도가가 아니다.'),
    (gen_random_uuid()::text, set_id, 71, '도가', '도가는 무위의 원리를 실천하여 도덕적 본성을 확충해야 한다고 주장한다.', false, '노자는 타고난 소박한 본성을 되찾아 그것을 유지해야 한다고 본다. 노자가 말한 본성은 텅 빈 것이고, 그 안에는 선악도 없다. 따라서, 노자가 말한 본성은 확충할 수 있는 것이 아니다.'),
    (gen_random_uuid()::text, set_id, 72, '도가', '도가는 이상적인 정치는 스스로 그러함의 원리에 어긋나지 않는다고 주장한다.', true, '노자는 이상적인 정치 방법으로 무위지치를 제시하였다. 무위지치는 무위를 근본으로 하여 인위적인 다스림이 없는 정치를 의미한다.'),
    (gen_random_uuid()::text, set_id, 73, '도가', '도가는 성인의 도를 본받아 겸허하고 다툼 없는 덕을 지녀야 한다고 주장한다.', true, '노자는 으뜸이 되는 선은 물과 같다고 주장하면서, 물과 같은 삶이 이상적인 삶이자 도와 합일된 성인의 모습이라고 본다. 이상적 인간상인 성인은 이러한 물의 모습과 같이 항상 스스로를 낮추고 다투지 않는 덕을 지니고 있다.'),
    (gen_random_uuid()::text, set_id, 74, '도가', '도가는 차별하는 마음을 버려야 진리를 깨달을 수 있다고 주장한다.', true, '도가 윤리는 평등적 세계관을 강조한다. 장자는 도의 관점에서 볼 때 무엇을 귀하게 여기고, 무엇을 천하게 여기겠는가라고 하여, 세상 만물은 평등한 가치를 지닌다고 주장하였다.'),
    (gen_random_uuid()::text, set_id, 75, '도가', '도가는 자기중심적 고정관념과 선입견에서 벗어나야 한다고 주장한다.', true, '장자는 인간의 자기 중심적 고정 관념, 편견, 선입견에서 벗어나 도의 관점을 취해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 76, '도가', '도가는 분별적 지혜를 발휘하여 도덕 질서를 확립해야 한다고 주장한다.', false, '도가에서는 분별적 지혜에 대해 비판한다. 도가는 분별적 지혜를 버리면 백성의 이익이 증가된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 77, '도가', '도가는 인의의 강조는 사회 혼란의 원인이 될 수 있다고 주장한다.', true, '도가는 인의와 같은 인위적인 규범을 사회 혼란의 원인으로 본다. 도가는 인위적인 규범에서 벗어나 도와 합일하여 자연에 따르는 무위자연의 삶을 강조한다.'),
    (gen_random_uuid()::text, set_id, 78, '도가', '도가는 하늘이 부여한 순선한 본성을 따르는 삶을 살아가야 한다고 주장한다.', false, '하늘이 부여한 순선한 본성을 따르는 삶을 살아가야 한다는 것은 유교에 해당하는 선지로, 도가나 불교에서는 하늘이 인간에게 선한 본성을 부여한다고 주장하지는 않는다.'),
    (gen_random_uuid()::text, set_id, 79, '도가', '도가는 옳고 그름을 가릴 줄 아는 마음으로 사욕을 제거해야한다고 주장한다.', false, '도가가 사욕의 제거를 주장한 것은 맞으나, 옳고 그름을 가리는 분별적인 마음, 지혜가 없어야 도와 합일될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 80, '도가', '도가는 진정한 자유를 위해 만물의 근원인 도에서 벗어나야 한다고 주장한다.', false, '도가는 기본적으로 도에 따르는 도와 합일된 삶을 지향한다.'),
    (gen_random_uuid()::text, set_id, 81, '도가', '도가는 이상적 인간은 모든 분별에서 벗어나 자연을 따르는 사람이라고 주장한다.', true, '도가에 따르면 도의 관점에서 세상 만물은 평등한 가치를 지니므로 귀천, 인위, 시비 등을 분별하는 태도에서 벗어나 자연을 따라야 한다.'),
    (gen_random_uuid()::text, set_id, 82, '도가', '도가는 백성의 수를 늘리면 자연스럽게 무위의 다스림을 이룰 수 있다고 주장한다.', false, '노자는 나라의 크기가 작고 백성의 수가 적은 소국과민을 이상 국가로 제시한다. 노자는 백성의 수가 많으면 무위의 다스림이 실현되기 어렵고 결국 사회를 혼란에 빠트리게 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 83, '도가', '도가는 자신을 구속하는 일체의 것을 잊어버리고 자유롭게 살아야 한다고 주장한다.', true, '도가에 따르면 좌망과 심재의 수양을 통해 외물에도 얽매이지 않고 자유로운 경지에 도달할 수 있다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '칸트', '칸트는 보편적 도덕 원리를 행위의 기준으로 삼아야 한다고 주장한다.', true, '칸트의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 2, '칸트', '칸트는 이해 당사자들의 쾌락을 최대화하도록 행동해야 한다고 주장한다.', false, '이해 당사자들의 쾌락 최대화는 공리주의(벤담)의 입장이다. 칸트는 결과가 아닌 동기를 중시한다.'),
    (gen_random_uuid()::text, set_id, 3, '칸트', '칸트는 좋은 결과를 산출한 행위도 옳지 않은 행위일 수 있다고 주장한다.', true, '칸트는 행위의 결과가 아니라 선의지를 동기로 취하며, 의무 의식에 따른 행위이어야 도덕적이라고 본다. 결과가 좋더라도 의무가 아닌 경향성에 따른 행위는 도덕적이지 않을 수 있다.'),
    (gen_random_uuid()::text, set_id, 4, '칸트', '칸트는 그 자체로 선한 의지에서 비롯된 행위는 옳은 행위라고 주장한다.', true, '칸트는 선의지가 그 자체로 선한 것이며, 선의지로부터 비롯된 행위가 도덕적으로 옳은 행위라고 본다.'),
    (gen_random_uuid()::text, set_id, 5, '칸트', '칸트는 인간은 타고난 덕을 실천해야 도덕적 행위를 할 수 있다고 주장한다.', false, '타고난 덕을 실천해야 한다는 것은 덕 윤리(아리스토텔레스)의 입장이다. 칸트는 선의지와 의무 의식을 도덕적 행위의 동력으로 본다.'),
    (gen_random_uuid()::text, set_id, 6, '칸트', '칸트는 당신의 자연적 성향에 따라 사람들을 정직하게 대해야 한다고 주장한다.', false, '칸트는 자연적 경향성에 따라 행위하라고 주장하지 않는다. 칸트의 도덕적 근거는 자연적 성향이 아니라 선의지이다.'),
    (gen_random_uuid()::text, set_id, 7, '칸트', '칸트는 모두의 이익을 증진시킬 수 있도록 정직하게 행동해야 한다고 주장한다.', false, '칸트는 이익 증진과 같은 결과를 도덕의 근거로 삼지 않는다. 칸트에 따르면 행위의 도덕성은 결과적 이익과 무관하고, 오직 선의지라는 동기에서 그 근거를 찾을 수 있다.'),
    (gen_random_uuid()::text, set_id, 8, '칸트', '칸트는 당신의 정직한 행위가 도덕적 의무에 맞기만 하면 된다고 주장한다.', false, '칸트는 단지 도덕적 의무에 맞는 행위가 아니라, 도덕적 의무로부터 일어난 행위가 도덕적 가치를 지닌다고 본다. 비록 의무에 맞는 행위라도 이기적인 동기에 의해 행한 것이라면 그것은 도덕적이지 않은 행위이다.'),
    (gen_random_uuid()::text, set_id, 9, '칸트', '칸트는 자연적 경향성에서 비롯된 준칙에 따라 행위해야 한다고 주장한다.', false, '칸트는 자연적 경향성을 극복하고 선의지에 따라 행동해야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 10, '칸트', '칸트는 선한 목적을 위해 조건적인 명령에 따라 행위해야 한다고 주장한다.', false, '칸트는 조건적 명령(가언 명령)이 아니라 무조건적 명령(정언 명령)을 도덕 판단의 기준으로 삼는다.'),
    (gen_random_uuid()::text, set_id, 11, '칸트', '칸트는 자신의 감정이 아니라 보편적 도덕 법칙에 따라 행위해야 한다고 주장한다.', true, '칸트는 수동적 감정이 아니라 오직 도덕 법칙을 따르려는 의무 의식에 따라 행위해야 한다고 주장했다.'),
    (gen_random_uuid()::text, set_id, 12, '칸트', '칸트는 경향성이 섞이지 않은 순수한 도덕적 동기에 따라 행동해야 한다고 주장한다.', true, '칸트는 경향성이 섞이지 않은 순수한 의무 의식(선의지)에 따라 행동해야 정당하다고 본다.'),
    (gen_random_uuid()::text, set_id, 13, '칸트', '칸트는 도덕적 행위자는 도덕 법칙보다 상황과 맥락을 중시해야 한다고 주장한다.', false, '칸트는 상황과 맥락 같은 가변적인 것이 아니라, 도덕 법칙과 같은 불변적인 것을 중시하여 행위해야 한다고 본다. 상황 맥락 중시는 덕 윤리의 입장이다.'),
    (gen_random_uuid()::text, set_id, 14, '칸트', '칸트는 도덕 법칙은 이성적 존재인 인간에게 구속력이 있다고 주장한다.', true, '칸트에 따르면 인간은 실천 이성을 지니므로 보편적인 도덕 법칙을 인식하고 수립할 수 있으며, 인간이 자율적으로 수립한 보편적 도덕 법칙은 이성적 존재자인 인간에게 구속력이 있다.'),
    (gen_random_uuid()::text, set_id, 15, '칸트', '칸트는 도덕 판단의 기준은 행위의 동기가 아닌 결과라고 주장한다.', false, '칸트는 의무론자로서 행위의 결과가 아니라 행위의 동기에서 도덕 판단의 기준을 찾는다.'),
    (gen_random_uuid()::text, set_id, 16, '칸트', '칸트는 행위의 옳고 그름을 규정하는 보편적 원칙은 존재한다고 주장한다.', true, '칸트의 입장이다. 칸트는 정언 명령의 형식을 띠는 보편적 도덕 법칙이 존재하며, 이성적 존재인 인간은 이러한 보편적 도덕 법칙에 따를 수 있는 존재라고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '칸트', '칸트는 선한 성품에서 나온 행위가 곧 도덕적 행위임을 강조한다고 주장한다.', false, '칸트는 성품과 같은 개개인의 특유한 기질을 도덕적 행위의 근거로 보지 않는다. 칸트는 오직 선의지만이 그 자체로 선한 것이므로, 선의지에 따르는 행위가 곧 도덕적 행위라고 본다. 성품 강조는 덕 윤리의 입장이다.'),
    (gen_random_uuid()::text, set_id, 18, '칸트', '칸트는 인간이 보편적인 도덕 법칙을 인식할 수 없음을 강조한다고 주장한다.', false, '칸트는 인간이 이성을 통해 보편적 도덕 법칙을 인식할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 19, '칸트', '칸트는 행위의 도덕성 평가에서 동기와 감정은 배제되어야 한다고 주장한다.', false, '칸트는 도덕성 평가에서 동기를 강조하는 동기주의자이다. 그는 행위의 도덕성 평가에서 동기를 배제하지 않는다.'),
    (gen_random_uuid()::text, set_id, 20, '칸트', '칸트는 이성적 행위자인 개개인이 도덕 법칙의 수립자임을 강조한다고 주장한다.', true, '칸트는 이성적 인격체 개개인이 도덕 법칙의 수립자이며, 존엄한 가치를 지닌다고 본다. 이러한 인격체의 가치를 존중해 주는 것이 곧 목적으로 대우하는 것이다.'),
    (gen_random_uuid()::text, set_id, 21, '칸트', '칸트는 어떤 행위가 인간을 목적으로 대우하는 것인지 고려해야 한다고 주장한다.', true, '칸트의 인간성 정식이다. 칸트는 어떤 행위를 할 때 그 행위가 인간을 목적으로 대우하는지를 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 22, '칸트', '칸트는 어떤 상황에서도 예외 없이 도덕적 의무를 지키도록 해야 한다고 주장한다.', true, '칸트의 도덕 의무는 어떠한 상황에서도 예외 없이 무조건적으로 지켜야 하는 정언 명령이다.'),
    (gen_random_uuid()::text, set_id, 23, '칸트', '칸트는 최대 다수의 최대 행복이라는 도덕 원리를 고려하여 판단해야 한다고 주장한다.', false, '최대 다수의 최대 행복은 공리주의의 도덕 원리이지 칸트의 도덕 원리가 아니다.'),
    (gen_random_uuid()::text, set_id, 24, '칸트', '칸트는 도덕이 사회적 역사적 맥락 속에서 도출되어야 함을 강조한다고 주장한다.', false, '칸트가 말하는 도덕의 기준은 사회적 역사적 맥락 속에 있는 것이 아니라, 인간이 자율적으로 수립한 도덕 법칙에 있다. 맥락 강조는 덕 윤리 공동체주의이다.'),
    (gen_random_uuid()::text, set_id, 25, '칸트', '칸트는 행동을 결정할 때는 발생할 결과의 유용성을 측정해 판단해야 한다고 주장한다.', false, '칸트는 행동을 결정할 때에는 개인의 준칙이 도덕 법칙에 부합하는지를 고려하여 행위해야 한다고 본다. 결과의 유용성을 측정해 행동을 결정해야 한다는 것은 공리주의자의 입장이다.'),
    (gen_random_uuid()::text, set_id, 26, '칸트', '칸트는 행위에 따르는 보상을 기대하고 행동해야 한다고 주장한다.', false, '칸트의 입장에 따르면, 보상, 동정심, 경제적 피해와 같은 것들은 가변적 요소에 해당한다. 이러한 가변적 요소들은 도덕 판단의 근거가 될 수 없다.'),
    (gen_random_uuid()::text, set_id, 27, '칸트', '칸트는 행위자가 느끼는 동정심에 따라 행동해야 한다고 주장한다.', false, '가변적 요소인 동정심(감정)이 아닌 의무 의식에 따라야 한다.'),
    (gen_random_uuid()::text, set_id, 28, '칸트', '칸트는 거짓 약속은 친구의 인격을 존중하는 것이 아니라고 주장한다.', true, '칸트에 따르면 거짓 약속은 친구의 인격을 한낱 수단으로 대우하는 것이다. 따라서 거짓 약속은 인간을 목적으로 대우하라는 인간성 정식에 어긋난 행위이므로 도덕적으로 정당화될 수 없다.'),
    (gen_random_uuid()::text, set_id, 29, '칸트', '칸트는 약속을 어긴 사람은 목적으로 대우받아서는 안 된다고 주장한다.', false, '약속을 어긴 사람이더라도 목적으로 대우받아야 한다는 것이 칸트의 입장이다.'),
    (gen_random_uuid()::text, set_id, 30, '칸트', '칸트는 약속 준수의 의무는 자기 행복에 대한 열망에 근거한다고 주장한다.', false, '칸트는 약속 준수의 의무가 자기 행복에 대한 열망이 아니라 오로지 의무로부터 순수하게 따르려는 의지인 선의지에 근거해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 31, '칸트', '칸트는 약속은 친구의 돈독한 정서적 유대를 위해 지켜야 한다고 주장한다.', false, '칸트에 따르면 친구의 돈독한 정서적 유대는 자연적 경향성이므로 도덕적 행위의 근거가 될 수 없다.'),
    (gen_random_uuid()::text, set_id, 32, '칸트', '칸트는 친구에게 무해하다면 거짓 약속도 도덕적으로 정당화된다고 주장한다.', false, '칸트는 오직 도덕 법칙을 지키기 위해 경향성의 영향을 완전히 제거해야 한다고 본다. 결과와 무관하게 거짓 약속은 보편화 가능성에 어긋나므로 정당화될 수 없다.'),
    (gen_random_uuid()::text, set_id, 33, '칸트', '칸트는 친구들 사이에서 더 인정받을 수 있는 행위를 선택해야 한다고 주장한다.', false, '인정받기를 원함은 경향성이므로 도덕적 기준이 될 수 없다.'),
    (gen_random_uuid()::text, set_id, 34, '칸트', '칸트는 구체적인 상황을 고려하여 중용에 따른 행위를 선택해야 한다고 주장한다.', false, '칸트가 아니라 아리스토텔레스의 덕 윤리에 해당한다. 아리스토텔레스의 덕 윤리는 추상적 도덕 원리보다 구체적 상황에서 덕을 함양한 사람이 할 법한 판단과 행위를 중시할 것을 주장한다.'),
    (gen_random_uuid()::text, set_id, 35, '칸트', '칸트는 친구와 함께하고자 하는 마음이 이끄는 행위를 선택해야 한다고 주장한다.', false, '마음이 이끄는 행위는 경향성이다.'),
    (gen_random_uuid()::text, set_id, 36, '칸트', '칸트는 가능한 행위 중에서 의무로부터 비롯된 행위를 선택해야 한다고 주장한다.', true, '칸트 의무론의 핵심이다. 오직 의무로부터 비롯된 행위만이 도덕적 가치를 지닌다.'),
    (gen_random_uuid()::text, set_id, 37, '칸트', '칸트는 더 많은 쾌락을 가져올 것으로 예상되는 행위를 선택해야 한다고 주장한다.', false, '쾌락을 기준으로 삼는 것은 공리주의의 입장이다. 더 많은 쾌락 산출을 기준으로 한 것은 벤담과 밀의 공리주의이다.'),
    (gen_random_uuid()::text, set_id, 38, '칸트', '칸트는 행위자의 고통보다 타인의 고통이 크게 되지 않도록 해야 한다고 주장한다.', false, '공리주의적 관점이다. 칸트는 결과가 아닌 동기를 기준으로 삼는다.'),
    (gen_random_uuid()::text, set_id, 39, '칸트', '칸트는 거짓 약속을 해서라도 행위자의 경제적 피해를 최소화해야 한다고 주장한다.', false, '결과에 관계없이 거짓 약속은 도덕 법칙에 위배된다.'),
    (gen_random_uuid()::text, set_id, 40, '칸트', '칸트는 모두가 거짓 약속을 시도한다면 과연 약속하는 것이 가능할지 판단해야 한다고 주장한다.', true, '칸트는 거짓 약속이 보편화될 수 있는지 검토해 보면, 거짓 약속은 보편 법칙 수립의 원칙에 어긋남을 알 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '벤담', '벤담은 행위자의 품성보다 행위의 유용성이 중요하다고 주장한다.', true, '벤담의 도덕 판단의 유일한 기준은 행위가 산출하는 유용성의 총량의 극대화 여부이다. 즉 행위자의 품성은 벤담의 고려 사항이 아니다.'),
    (gen_random_uuid()::text, set_id, 42, '벤담', '벤담은 보편적 도덕 원리를 행위의 기준으로 삼아야 한다고 주장한다.', true, '벤담에게 보편적 도덕 원리란 공리의 원리를 의미한다. 따라서 벤담은 공리의 원리에 부합하는 행위가 옳은 행위라고 본다.'),
    (gen_random_uuid()::text, set_id, 43, '벤담', '벤담은 도덕 판단의 기준이 행위의 동기가 아닌 결과라고 주장한다.', true, '벤담은 도덕 판단의 기준을 행위의 동기가 아닌 결과에 둔다. 도덕 판단의 기준을 행위의 동기에 두는 이론은 대표적으로 칸트의 의무론이 있다.'),
    (gen_random_uuid()::text, set_id, 44, '벤담', '벤담은 이해 당사자들의 쾌락을 최대화하도록 행동해야 한다고 주장한다.', true, '이해 당사자들의 쾌락의 최대화라는 표현은 공리주의에서 긍정하는 표현이다.'),
    (gen_random_uuid()::text, set_id, 45, '벤담', '벤담은 유용성의 합리적 계산보다 공동체의 전통이 중요하다고 주장한다.', false, '공리주의는 유용성의 합리적 계산을 공동체의 전통보다 중요하게 본다. 공동체 전통 중시는 덕 윤리이다.'),
    (gen_random_uuid()::text, set_id, 46, '벤담', '벤담은 인간은 고통을 피하고 쾌락을 추구하는 존재라고 본다.', true, '공리주의는 인간을 고통을 피하고 쾌락을 추구하는 존재로 가정한다.'),
    (gen_random_uuid()::text, set_id, 47, '벤담', '벤담은 어떤 행위가 공리를 극대화하는 것인지 고려해야 한다고 주장한다.', true, '공리주의는 올바른 행위는 공리를 극대화하는 행위라고 본다.'),
    (gen_random_uuid()::text, set_id, 48, '벤담', '벤담은 행위의 옳고 그름을 판단하는 척도는 결과의 유용성이라고 주장한다.', true, '벤담은 공리주의자로서 결과의 유용성으로 행위의 옳고 그름을 판단한다. 즉 어떤 행위가 이해관계가 걸려 있는 당사자의 행복을 증가시키면 좋은 행위이고, 그 행복을 감소시키면 좋은 행위가 아닌 것이다.'),
    (gen_random_uuid()::text, set_id, 49, '벤담', '벤담은 행위의 옳고 그름을 규정하는 보편적 원칙은 존재한다고 주장한다.', true, '벤담은 공리의 원리를 보편적 도덕 원칙으로 삼는다.'),
    (gen_random_uuid()::text, set_id, 50, '벤담', '벤담은 어떤 행위가 자연법에 부합하는 것인지 고려해야 한다고 주장한다.', false, '어떤 행위의 도덕성은 자연법이 아니라 그 행위로 인해 산출되는 공리를 통해 판단된다. 자연법은 자연법 윤리(아퀴나스)의 기준이다.'),
    (gen_random_uuid()::text, set_id, 51, '벤담', '벤담은 공익은 사익의 총합보다 크다는 것을 고려해야 한다고 주장한다.', false, '공리주의에서 공동체의 행복은 공동체 구성원들의 행복의 총합이다. 즉 공익이 사익의 총합보다 크다가 아니라 공익이 사익의 총합과 같다이다.'),
    (gen_random_uuid()::text, set_id, 52, '벤담', '벤담은 최대 다수의 최대 행복의 원리가 도덕적 행위의 기준이라고 주장한다.', true, '공리주의에서 말하는 공리의 원리가 바로 최대 다수의 최대 행복의 원리이다.'),
    (gen_random_uuid()::text, set_id, 53, '벤담', '벤담은 정신적 쾌락은 감각적 쾌락과 달리 양적 계산이 불가능하다고 주장한다.', false, '벤담의 입장으로 적절하지 않다. 벤담은 모든 쾌락이 질적으로 같으며, 그것들을 양적으로 계산할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 54, '벤담', '벤담은 도덕 판단에서 역사적 특수성보다 행위 결과를 고려해야 한다고 주장한다.', true, '공리주의자는 도덕 판단에 있어서 역사적 특수성보다는 행위 결과를 고려한다.'),
    (gen_random_uuid()::text, set_id, 55, '벤담', '벤담은 모든 상황에 적용되는 보편적 도덕 원리는 없다고 주장한다.', false, '벤담은 보편적 도덕 원리로 최대 다수의 최대 행복이라는 공리의 원리를 인정한다. 보편적 도덕 원리를 강조하는 것은 칸트, 벤담, 밀의 공통점이다. 다만 칸트의 입장에서는 보편적 도덕 원리가 공리의 원리가 아니다.'),
    (gen_random_uuid()::text, set_id, 56, '벤담', '벤담은 행위가 산출할 타인의 이익에 가중치를 두어야 한다고 주장한다.', false, '벤담은 구성원의 이익을 총체적으로 고려한 것이지, 타인의 이익에 가중치를 두어야 한다고 주장하지 않는다. 오히려 벤담은 구성원의 이익을 평등하게 고려해야 한다는 입장에 가깝다.'),
    (gen_random_uuid()::text, set_id, 57, '벤담', '벤담은 행위가 산출할 쾌락의 질적 차이를 고려하여야 한다고 주장한다.', false, '쾌락의 질적 차이를 고려해야 한다는 것은 밀의 입장이다. 벤담은 쾌락의 질적 차이를 인정하지 않고, 쾌락의 양만을 고려해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 58, '벤담', '벤담은 행위자에게 가져올 이익만을 고려하여 행위해야 한다고 주장한다.', false, '벤담은 구성원의 이익을 총체적으로 고려하는 사상가이다. 따라서 행위자에게 가져올 이익만을 고려하라는 것은 벤담의 사상에 맞지 않다.'),
    (gen_random_uuid()::text, set_id, 59, '벤담', '벤담은 행위의 결과와 무관하게 선한 것인지 숙고하여야 한다고 주장한다.', false, '공리주의에 반대되는 입장이다. 공리주의는 최대 다수의 최대 행복이라는 결과를 가져오는 행동이 선한 행동이라고 본다. 한편 결과와 무관하게 선을 강조한 것은 동기주의(칸트)의 입장이다.'),
    (gen_random_uuid()::text, set_id, 60, '벤담', '벤담은 행위가 가져올 해악과 편익의 총합을 계산하여야 한다고 주장한다.', true, '벤담은 공동체가 구성원들의 총합이라고 본다. 따라서 벤담은 구성원들의 이익의 총합이 곧 공동체의 이익이라고 주장한다. 그러므로 벤담은 어떤 행위가 가져올 해악과 편익의 총합을 계산하여 행위를 결정해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 61, '벤담', '벤담은 행위가 자연법의 제1원리에 부합하는지 판단해야 한다고 주장한다.', false, '자연법의 제1원리를 제시한 학자는 의무론적 접근의 자연법 윤리 학자 아퀴나스이다. 의무론적 접근은 공리주의자인 벤담의 입장에 부적절하다.'),
    (gen_random_uuid()::text, set_id, 62, '벤담', '벤담은 질적으로 우월한 쾌락을 산출하는 행위를 선택해야 한다고 주장한다.', false, '쾌락의 질을 비교하는 것은 공리주의자 밀의 입장이다. 양적 공리주의자인 벤담은 밀과 달리 쾌락의 질적 차이를 인정하지 않는다.'),
    (gen_random_uuid()::text, set_id, 63, '벤담', '벤담은 신체의 고통은 양적으로 계산될 수 없음을 고려해야 한다고 주장한다.', false, '벤담은 쾌락과 고통을 양적으로 계산할 수 있다고 본다. 참고로 질적 공리주의자인 밀 또한 쾌락의 양적 계산을 부정한 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 64, '벤담', '벤담은 행위가 산출할 쾌락의 양을 쾌락 계산법에 따라 계산해야 한다고 주장한다.', true, '벤담이 제시할 주장으로 적절하다. 제시문에서도 알 수 있듯 벤담의 입장에서는 쾌락의 양을 쾌락 계산법에 따라 계산하여 쾌락의 양이 가장 큰 경우를 선택해야 한다.'),
    (gen_random_uuid()::text, set_id, 65, '벤담', '벤담은 유덕한 행위자가 행할 만한 것을 그 결과에 상관없이 행해야 한다고 주장한다.', false, '벤담은 결과론적 사상가로서 행위의 결과가 유용성을 산출해야 도덕적 가치를 갖는다고 본다. 따라서 결과를 상관하지 말라는 선지의 내용도 벤담의 입장에 부합하지 않는다.'),
    (gen_random_uuid()::text, set_id, 66, '벤담', '벤담은 행위가 선의지에서 비롯된 행위여야 도덕적 행위임을 명심해야 한다고 주장한다.', false, '선의지에서 비롯된 행위가 도덕적이라고 주장한 학자는 칸트이다.'),
    (gen_random_uuid()::text, set_id, 67, '벤담', '벤담은 쾌락의 양뿐만 아니라 질적 차이까지 고려하여 행위를 선택해야 한다고 주장한다.', false, '벤담이 아닌 밀의 주장이다. 밀은 벤담과 달리 쾌락의 질적 차이를 인정하며 행위 선택에서 쾌락의 양과 질을 모두 고려할 것을 강조한다. 주의할 점은 밀이 쾌락의 질적 차이만을 고려하는 것이 아니라 양과 질을 모두 고려한다는 점이다. 따라서 쾌락의 양을 고려하는 것은 벤담과 밀의 공통점이다.'),
    (gen_random_uuid()::text, set_id, 68, '매킨타이어', '매킨타이어는 행위자의 품성보다 행위의 유용성이 중요하다고 주장한다.', false, '현대 덕 윤리 학자 맥킨타이어는 행위자의 품성을 중시한다. 행위의 유용성을 강조하는 것은 공리주의(벤담, 밀)의 입장이다.'),
    (gen_random_uuid()::text, set_id, 69, '매킨타이어', '매킨타이어는 공동체가 개인의 단순한 집합체로 간주될 수 없다고 주장한다.', true, '맥킨타이어는 공동체가 역사와 전통의 의미를 갖는다고 보았으며, 공동체를 단순한 개인들의 집합으로 보지 않았다.'),
    (gen_random_uuid()::text, set_id, 70, '매킨타이어', '매킨타이어는 꾸준한 도덕적 실천으로 얻어진 덕에 따라 행동해야 한다고 주장한다.', true, '덕 윤리는 꾸준한 도덕적 실천의 결과인 습관화된 덕을 통해 덕을 함양할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 71, '매킨타이어', '매킨타이어는 공동체의 전통과 덕목에 부합하도록 행위해야 한다고 주장한다.', true, '덕 윤리는 공동체주의와 일맥상통한다. 공동체의 전통과 덕목에 부합하는 행위를 바람직한 것으로 본다.'),
    (gen_random_uuid()::text, set_id, 72, '매킨타이어', '매킨타이어는 어떤 행위가 덕성 함양에 기여하는 것인지 고려해야 한다고 주장한다.', true, '덕 윤리학자 맥킨타이어는 공동체 안에서 더불어 살아가는 인간이 덕을 습득하지 못하면 사회 공동체의 선을 이룰 수 없다고 본다. 따라서 맥킨타이어는 반복적인 도덕적 행위를 통해 덕성을 함양해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 73, '매킨타이어', '매킨타이어는 덕은 사회적 실천을 통해 선을 이루는 데 필요한 성품이라고 주장한다.', true, '맥킨타이어의 덕 정의이다. 덕은 공동체의 전통과 덕목에 부합하는 행위가 바람직한 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 74, '매킨타이어', '매킨타이어는 도덕 판단에서 역사적 특수성보다 행위 결과를 고려해야 한다고 주장한다.', false, '덕 윤리학자는 역사적 특수성을 고려하여 행위해야 한다고 본다. 맥킨타이어는 역사적 특수성보다 행위 결과를 중시하지 않는다.'),
    (gen_random_uuid()::text, set_id, 75, '매킨타이어', '매킨타이어는 도덕이 사회적 역사적 맥락 속에서 도출되어야 함을 강조한다고 주장한다.', true, '맥킨타이어는 덕 윤리학자로서 덕성이 함양되기 위한 사회적 역사적 배경을 중시한다. 따라서 덕성의 함양은 고립되고 단절된 이성적 개인의 내면이 아니라, 역사적 전통이라는 구체적 맥락을 갖는 공동체 안에서만 가능하다.'),
    (gen_random_uuid()::text, set_id, 76, '매킨타이어', '매킨타이어는 도덕적 행위자는 도덕 법칙보다 상황과 맥락을 중시해야 한다고 주장한다.', true, '맥킨타이어는 덕 윤리의 입장에서 도덕적 행위자가 상황과 맥락을 고려하여 유덕한 행위를 해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 77, '매킨타이어', '매킨타이어는 사회 구성원으로서 갖추어야 할 훌륭한 인품에 비추어 도덕 판단을 해야 한다고 주장한다.', true, '덕 윤리는 사회 구성원으로서 품성을 갖춰야 한다고 보는 입장이다.'),
    (gen_random_uuid()::text, set_id, 78, '갑(아리스토텔레스)/을(매킨타이어)', '아리스토텔레스는 인간의 고유한 본성을 실현해야 한다고 주장한다.', true, '아리스토텔레스는 인간이 자신의 고유한 본성을 발현해야 최고선인 행복에 이를 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 79, '갑(아리스토텔레스)/을(매킨타이어)', '아리스토텔레스는 습관화를 통해 도덕적 품성을 함양하여야 한다고 주장한다.', true, '아리스토텔레스는 지적 덕은 교육기관을 통해 기를 수 있고, 도덕적 덕(도덕적 품성)은 습관화를 통해 기를 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 80, '갑(아리스토텔레스)/을(매킨타이어)', '아리스토텔레스는 행복은 곧 옳고 그름에 관한 앎임을 알아야 한다고 주장한다.', false, '아리스토텔레스에 따르면 인간에게 행복이란 덕에 따른 영혼의 활동이다. 따라서 행복은 옳고 그름에 관한 앎이 아니라, 인간의 고유한 본성인 이성에 따른 영혼의 활동을 통해서 도달할 수 있는 것이다.'),
    (gen_random_uuid()::text, set_id, 81, '갑(아리스토텔레스)/을(매킨타이어)', '아리스토텔레스는 어떠한 상황에서도 두려움의 감정을 갖지 않는 용기 있는 사람이 되어야 한다고 주장한다.', false, '아리스토텔레스의 입장에서 두려움을 느껴야 마땅한 상황에서 두려움의 감정을 가지 않는 것은 무모함이지 용기로서의 중용이 아니므로 틀린입장이다.'),
    (gen_random_uuid()::text, set_id, 82, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 공동체의 선보다 보편적인 도덕 원칙을 더 중시해야 한다고 주장한다.', false, '맥킨타이어는 공동체의 선, 공동선을 추구해야 한다고 본다. 맥킨타이어는 공동체적인 덕이 중요하다고 보며, 공동체의 전통과 역사를 중시한다.'),
    (gen_random_uuid()::text, set_id, 83, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 도덕 판단을 할 때 행위자보다 행위 자체를 중시해야 한다고 주장한다.', false, '맥킨타이어가 주장할 내용으로 적절하지 않다. 덕 윤리는 행위자의 품성에 초점을 두며 도덕적 행동이 행위자의 내면에 따라 정해진다고 보는 관점이다.'),
    (gen_random_uuid()::text, set_id, 84, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 관습을 따르기보다 자율적 준칙에 따라 소신 있게 행동하라고 주장한다.', false, '맥킨타이어는 자율적 준칙에 따른 행동보다는 공동체의 관습과 전통에 따를 것을 강조한다. 자율적 준칙 강조는 칸트의 입장이다.'),
    (gen_random_uuid()::text, set_id, 85, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 개인은 공동체를 벗어나면 덕을 실천하는 방법을 배울 수 없다고 주장한다.', true, '맥킨타이어는 공동체로부터 주어진 것이 개인의 도덕적 출발점을 구성한다고 본다. 맥킨타이어는 개인의 도덕적 정체성이 사회적 역사적 맥락 속에서 형성된다고 보며, 덕목의 실천도 공동체 안에서 가능하다고 본다.'),
    (gen_random_uuid()::text, set_id, 86, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 자신이 속한 공동체의 공유된 핵심 가치를 실현하도록 행동해야 한다고 주장한다.', true, '맥킨타이어는 공동체의 공동의 역사와 전통을 중시하며, 따라서 자신이 속한 공동체의 핵심 가치를 실현해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 87, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 개인의 도덕적 정체성은 사회적 역사적 맥락 속에서 형성되어야 한다고 주장한다.', true, '맥킨타이어의 서사적 자아 개념이다. 공동체의 역사와 전통 속에서 개인의 도덕적 정체성이 형성된다.'),
    (gen_random_uuid()::text, set_id, 88, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 유용한 결과를 기준으로 삼아 공동체 이익을 증진하도록 행동해야 한다고 주장한다.', false, '유용한 결과를 기준으로 삼는 것은 공리주의의 입장이다. 맥킨타이어는 덕 윤리학자로서 결과보다 행위자의 품성과 공동체의 덕을 중시한다.'),
    (gen_random_uuid()::text, set_id, 89, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 공동체의 도덕적 전통에 구애됨 없이 도구적 이성에 따라 행동해야 한다고 주장한다.', false, '맥킨타이어는 공동체 전통을 중요시하며, 도구적 이성에만 따라 행동하는 것에 반대한다. 맥킨타이어는 덕을 함양시켜야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 90, '갑(아리스토텔레스)/을(매킨타이어)', '매킨타이어는 공동선에 순응하기보다는 자신만의 고유한 선 관념에 따라 행동해야 한다고 주장한다.', false, '맥킨타이어는 공동체주의 사상가로 자신만의 고유한 선 관념보다 공동선을 중시한다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '유교', '유교는 생사는 차별해서는 안 되는 순환의 과정이라고 주장한다.', false, '유교에서는 생사를 차별해서는 안 되는 순환의 과정이라고 보지 않는다. 이는 교육과정상 불교와 도가의 입장이다.'),
    (gen_random_uuid()::text, set_id, 2, '유교', '유교는 죽음은 인간이 윤회의 과정에서 겪는 괴로움이라고 주장한다.', false, '유교의 입장이 아니라 불교의 입장이다. 유교는 윤회를 인정하지 않는다.'),
    (gen_random_uuid()::text, set_id, 3, '유교', '유교는 현실적 삶을 긍정하고 제사 의례를 근절해야 한다고 주장한다.', false, '유교 사상은 제사 의례를 근절하자는 입장이 아니다. 제사는 유교에서 강조된다.'),
    (gen_random_uuid()::text, set_id, 4, '유교', '유교는 죽음은 반복되는 윤회에서 벗어날 수 있는 방법이라고 주장한다.', false, '윤회를 인정하는 동양 사상은 유교가 아니라 불교의 입장이다. 그런데 해당 선지는 불교의 입장도 아니다. 불교에서 윤회에서 벗어나는 방법은 죽음이 아니라 깨달음을 통해 해탈 열반의 상태에 이르는 것이기 때문이다. 즉 깨달음 없는 단순한 죽음으로는 윤회에서 벗어날 수 없다.'),
    (gen_random_uuid()::text, set_id, 5, '유교', '유교는 죽음은 모든 만물의 근원인 도와 연관된 현상이라고 주장한다.', false, '유교가 아니라 도가의 입장이다. 유교에서는 모든 만물의 근원을 도라고 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 6, '유교', '유교는 죽음은 인간의 삶에 일어나는 자연스러운 현상이라고 주장한다.', true, '유교는 죽음을 자연스러운 현상으로 본다. 참고로 교육과정상 죽음관 관련 모든 사상가들이 죽음을 인간의 삶에서 일어나는 자연스러운 현상이라고 본다.'),
    (gen_random_uuid()::text, set_id, 7, '유교', '유교는 현세에서의 도덕적 실천이 내세에서의 삶을 결정한다고 주장한다.', false, '교육과정상 유교, 불교, 도가 사상 중에서 내세를 설정하는 것은 불교뿐이며, 유교와 도가는 내세를 설정하지 않는다.'),
    (gen_random_uuid()::text, set_id, 8, '유교', '유교는 죽음은 내세에서의 도덕적 완성을 위한 과정이라고 주장한다.', false, '교육과정상 유교는 내세를 설정하지 않는다.'),
    (gen_random_uuid()::text, set_id, 9, '유교', '유교는 죽음은 윤회의 일부이며 현생의 업보가 내생을 결정한다고 주장한다.', false, '업보에 따른 윤회를 주장하는 것은 유교가 아니라 불교이다.'),
    (gen_random_uuid()::text, set_id, 10, '유교', '유교는 죽음보다는 인의에 충실한 삶에 관심을 가져야 한다고 주장한다.', true, '유교는 죽음에 집중하기보다는 인의에 충실한 삶을 강조한다. 선지에 등장한 인의는 교육과정상 유교 사상에서 강조하는 덕목이다.'),
    (gen_random_uuid()::text, set_id, 11, '유교', '유교는 연기의 이치를 깨달아 고락에서 벗어나야 한다고 주장한다.', false, '연기는 유교가 아니라 불교가 강조하는 내용이다.'),
    (gen_random_uuid()::text, set_id, 12, '유교', '유교는 죽음이 아쉽지 않도록 도덕적으로 충실하게 살아야만 한다고 주장한다.', true, '유교는 죽음이 아쉽지 않도록 현실에서 도덕적으로 충실하게 살아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 13, '유교', '유교는 삶과 죽음의 이치를 깨달아 인의의 삶에 힘써야 한다고 주장한다.', true, '교육과정상 인의의 개념은 주로 유교 사상의 특징이다. 선지에서 표현된 삶과 죽음의 이치는 죽음에 집중하기보다는 현실의 삶에서 윤리적 실천을 행하라는 이치로 이해하면 된다.'),
    (gen_random_uuid()::text, set_id, 14, '유교', '유교는 죽음은 자연의 과정이지만 상례를 통해 애도해야 한다고 주장한다.', true, '유교에서는 죽음을 자연의 과정이라고 보며, 마땅히 상장례 등을 통해서 예에 부합하게 애도해야 하는 일이라고 본다. 참고로 도가는 죽음을 자연스러운 과정으로 보지만 애도해야 할 대상으로 보지는 않는다.'),
    (gen_random_uuid()::text, set_id, 15, '유교', '유교는 생 그 자체가 어떤 가치보다도 더 소중하다고 주장한다.', false, '유교에 따르면 의로움을 위해서라면 생명을 희생할 수도 있다(사생취의, 살신성인). 이를 통해 유교의 입장에서 생보다 더 추구할 만한 가치가 있을 수 있다고 보는 것이 적절하다.'),
    (gen_random_uuid()::text, set_id, 16, '유교', '유교는 죽음에 집착하지 않는 삶의 태도를 지녀야 한다고 주장한다.', true, '유교에서는 죽음에 집착하기보다 현세에서의 도덕적 실천을 하기 위해 노력해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '유교', '유교는 태어남과 죽음은 본래 자연스러운 과정일 뿐이라고 주장한다.', true, '유교는 죽음을 자연의 과정으로 받아들이고 애도하는 것을 마땅하게 여긴다.'),
    (gen_random_uuid()::text, set_id, 18, '유교', '유교는 삶과 죽음은 운명에 따라 주기적으로 순환한다고 주장한다.', false, '삶과 죽음이 운명에 따라 주기적으로 순환한다고 보는 관점은 유교의 입장이 아니라 도가의 입장에 해당한다. 유교는 삶과 죽음을 운명으로 보기는 하지만 죽음 이후의 삶에 대해 크게 언급하지는 않는다.'),
    (gen_random_uuid()::text, set_id, 19, '유교', '유교는 도덕적 가치가 삶과 죽음의 선택 기준이 될 수 있다고 주장한다.', true, '유교는 도덕적 가치를 위해 죽음을 택할 수 있다고 본다(살신성인).'),
    (gen_random_uuid()::text, set_id, 20, '유교', '유교는 죽음 이후를 대비하여 도덕적 이치를 탐구해야 한다고 주장한다.', false, '교육과정상 유교는 내세를 설정하지 않는다. 죽음 이후의 세상은 없다. 교육과정상 동양에서 내세를 설정하는 사상은 불교뿐이다.'),
    (gen_random_uuid()::text, set_id, 21, '유교', '유교는 죽음은 다른 존재로 윤회하는 고리가 단절된 상태라고 주장한다.', false, '유교의 입장도 불교의 입장도 아니다. 불교에서 주장하는 윤회는 죽은 뒤 또 다른 삶으로 이어지는 것이지 윤회가 단절되는 것이 아니다.'),
    (gen_random_uuid()::text, set_id, 22, '유교', '유교는 죽음을 슬퍼하는 것은 자연의 순리를 회피하는 것이라고 주장한다.', false, '유교에서는 죽음을 자연의 과정으로 받아들이고 애도하는 것을 마땅히 여긴다. 유교에서는 또한 죽음에 집착하기보다는 현세의 인륜적 삶에 충실하는 것이 중요하다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 23, '유교', '유교는 죽음 이후에 관한 지식이 삶에 관한 지식보다 중요하다고 주장한다.', false, '유교에서는 죽음 이후의 세계에 대해서는 관심을 가지지 않으며 오히려 현세에서의 도덕적 삶을 강조하는 입장이다. 따라서 삶에 관한 지식이 죽음 이후에 관한 지식보다 중요하다고 본다.'),
    (gen_random_uuid()::text, set_id, 24, '유교', '유교는 인의를 위해 목숨을 바치는 것은 어리석은 일이라고 주장한다.', false, '유교는 인의를 위해서 목숨을 바칠 수 있다고 본다. 즉 인의 구현을 위해서 자신의 생명을 희생할 수 있다고 보는 것이다(살신성인).'),
    (gen_random_uuid()::text, set_id, 25, '유교', '유교는 죽음을 맞이하는 한이 있더라도 도를 추구해야 한다고 주장한다.', true, '유교에서는 인의와 같은 도, 즉 도덕성을 위해 죽음을 맞이할 수 있다고 본다(사생취의).'),
    (gen_random_uuid()::text, set_id, 26, '유교', '유교는 죽음에 관심을 가지기보다는 인륜적 삶에 충실해야 한다고 주장한다.', true, '유교는 사후, 즉 죽음 이후의 삶이 아니라 현세의 도덕적 실천(인의 구현)을 강조한다.'),
    (gen_random_uuid()::text, set_id, 27, '유교', '유교는 사람이 죽음에 임해서는 자기 삶을 성찰하게 되는 법이라고 주장한다.', true, '유교는 죽음 앞에서 자기 삶을 성찰하는 것을 중시한다.'),
    (gen_random_uuid()::text, set_id, 28, '유교', '유교는 사후의 평온보다 현세에서 인을 실천하는 것이 중요하다고 주장한다.', true, '유교는 사후보다 현세에서 인을 실천하는 것을 중시한다.'),
    (gen_random_uuid()::text, set_id, 29, '유교', '유교는 죽음은 마땅히 애도해야 하는 일인 동시에 자연에 순응하는 과정이라고 주장한다.', true, '유교는 죽음을 자연스러운 과정으로 받아들이며, 동시에 상례를 통해 애도하는 것을 마땅한 일로 본다. 단, 지나친 슬픔은 경계한다.'),
    (gen_random_uuid()::text, set_id, 30, '불교', '불교는 죽음은 삶의 모든 번뇌가 소멸한 상태라고 주장한다.', false, '불교의 윤회설에 따르면 깨닫지 못한 중생에게 죽음은 또 다른 삶의 시작을 의미하며, 현생의 업과 번뇌가 덜 소멸한 경우 다음 생에 그 과보를 다시 겪게 된다. 따라서 불교에서 말하는 죽음이란 삶의 모든 번뇌가 소멸한 상태가 아니며, 오히려 극복해야 할 대상이다.'),
    (gen_random_uuid()::text, set_id, 31, '불교', '불교는 삶과 죽음을 분별하여 고통에서 벗어나야 한다고 주장한다.', false, '불교는 삶과 죽음을 분별하지 말 것을 강조한다. 왜냐하면 삶과 죽음이 같다고 보기 때문이다. 이를 생사일여라고 한다. 불교의 수행 방법인 심재는 분별심을 없애고 진리를 있는 그대로 보는 것을 의미한다.'),
    (gen_random_uuid()::text, set_id, 32, '불교', '불교는 생사는 차별해서는 안 되는 순환의 과정이라고 주장한다.', true, '불교 사상은 생사를 차별하지 않는 하나(생사일여)로 바라보며, 연기설의 관점에서 상호 연결된 순환 과정으로 본다.'),
    (gen_random_uuid()::text, set_id, 33, '불교', '불교는 연기의 이치를 깨달아 고락에서 벗어나야 한다고 주장한다.', true, '불교는 진리를 깨달아 고락에서 벗어나야 한다고 보는데, 연기의 이치는 불교의 진리에 해당한다.'),
    (gen_random_uuid()::text, set_id, 34, '불교', '불교는 삶과 죽음의 순환인 윤회는 인간에게만 적용된다고 주장한다.', false, '불교는 깨닫지 못한 중생이 죽은 뒤에는 그 업에 따라 또 다른 세계에 태어난다고 본다. 이때 모든 중생은 인간뿐만 아니라 의식 감정을 지닌 생물을 의미한다.'),
    (gen_random_uuid()::text, set_id, 35, '불교', '불교는 현세의 삶에서 죽음의 이치를 깨닫는 것은 불가능하다고 주장한다.', false, '불교는 현세의 삶에서 수행을 통해 연기에 대한 깨달음을 얻고, 나에 대한 집착을 끊고, 나와 만물이 하나임을 깨달을 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 36, '불교', '불교는 해탈하여 세속의 삶과 죽음의 고통에서 벗어나야 한다고 주장한다.', true, '불교는 해탈의 경지에 도달하면 세속의 삶과 죽음의 고통에서 벗어날 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 37, '불교', '불교는 죽음은 깨달음을 통해 벗어나야 할 고통들 중 하나라고 주장한다.', true, '불교에 따르면 죽음을 포함한 생로병사는 고통이며, 깨달음을 통해 열반에 이르면 그러한 고통의 윤회에서 벗어날 수 있다.'),
    (gen_random_uuid()::text, set_id, 38, '불교', '불교는 죽음은 윤회의 일부이며 현생의 업보가 내생을 결정한다고 주장한다.', true, '불교는 윤회설을 바탕으로 현생의 업이 내생을 결정한다고 본다.'),
    (gen_random_uuid()::text, set_id, 39, '불교', '불교는 내세의 행복을 위해 선업을 쌓는 삶을 살아야 한다고 주장한다.', true, '불교는 현세에 선하고 도덕적인 실천을 함으로써 선업을 쌓으면 내세에서 더 나은 삶을 살 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 40, '불교', '불교는 죽음에 집착하지 않는 삶의 태도를 지녀야 한다고 주장한다.', true, '불교에서는 집착을 버리고 깨달음을 얻어야 한다고 본다. 불교에서 삶과 죽음은 생멸의 과정에서 반복되는 것이므로 삶과 죽음에 집착할 필요는 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '불교', '불교는 죽음은 오온의 해체이기 때문에 괴로움이 아니라고 주장한다.', false, '불교는 인간이 색, 수, 상, 행, 식의 오온으로 구성되어 있다고 본다. 불교의 입장에서 죽음은 인간이 겪는 고통이자 오온의 해체이다. 즉 죽음은 오온의 해체이면서 동시에 괴로움이다.'),
    (gen_random_uuid()::text, set_id, 42, '불교', '불교는 삶과 죽음의 영원한 반복은 연기법의 지배를 받지 않는다고 주장한다.', false, '불교는 팔정도를 실천함으로써 생사의 순환, 윤회에서 벗어날 수 있다고 본다. ''영원한 반복''이라는 표현은 불교의 입장과 차이가 있으며, 생사윤회도 연기법의 지배를 받는다.'),
    (gen_random_uuid()::text, set_id, 43, '불교', '불교는 죽음은 고통이 없는 생으로 이어지는 윤회의 과정이라고 주장한다.', false, '불교 사상에서 죽음이란 생·노·병과 더불어 대표적인 인간의 고통 중 하나이며, 끝이 아니라 현실에서 벗어나 또 다른 세계로 윤회하는 것을 의미한다. 업에 따라 고통 없는 생이 보장되지 않는다.'),
    (gen_random_uuid()::text, set_id, 44, '불교', '불교는 도를 얻음으로써 생사의 얽매임에서 벗어날 수 있다고 주장한다.', true, '불교는 도를 얻음으로써 생사의 얽매임에서 벗어날 수 있다고 본다. 불교는 열반에 이르는 방법인 도성제를 주장하며, 지나치게 쾌락에 빠지지 않고 지나치게 계율이나 고행에 빠지지도 않는 수행 방법인 중도를 강조한다.'),
    (gen_random_uuid()::text, set_id, 45, '불교', '불교는 죽음은 원인과 조건에 의한 관계의 법칙에서 벗어난 것이라고 주장한다.', false, '원인과 조건에 의한 관계의 법칙이란 연기법을 의미한다. 불교의 입장에서 죽음은 연기의 법칙에 따르는 것이다. 죽음이란 인생에서 겪는 네 가지 고통 중 하나이기도 하다.'),
    (gen_random_uuid()::text, set_id, 46, '불교', '불교는 죽음 이후의 새로운 삶을 받지 않도록 열반에 도달해야 한다고 주장한다.', true, '불교는 깨달음의 경지에 올라 열반에 들지 않는다면 반복되는 윤회의 굴레 속에서 죽음 이후 새로운 삶이 반복된다고 본다. 따라서 열반에 도달하여 새로운 삶을 받지 않도록 해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 47, '불교', '불교는 삶과 죽음을 서로 다르지 않은 하나로 여겨야 한다고 주장한다.', true, '불교는 삶과 죽음이 윤회의 과정 중에 나타나는 서로 다른 양상일 뿐 서로 다르지 않다고 파악한다. 이와 같은 진리를 깨닫는다면 삶과 죽음이 서로 다르지 않은 하나라는 ''생사일여''의 관점을 지닐 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 48, '불교', '불교는 죽음의 참모습을 자각하면 업을 짓지 않고 윤회하게 된다고 주장한다.', false, '불교에서는 모든 존재와 현상이 독립적이지 않고 상호 의존한다는 연기를 깨달아 죽음의 참모습을 자각하면 업을 짓지 않고 윤회에서 벗어날 수 있다고 본다. 즉 업을 짓지 않으면 윤회하지 않는다.'),
    (gen_random_uuid()::text, set_id, 49, '불교', '불교는 열반에 이르기 위해서는 삶과 죽음의 의존관계를 부정해야 한다고 주장한다.', false, '열반에 이르기 위해서는 삶과 죽음의 의존관계(연기)를 부정하는 것이 아니라, 연기를 깨닫고 초월해야 한다.'),
    (gen_random_uuid()::text, set_id, 50, '불교', '불교는 깨닫지 못한 중생에게 죽음은 다음 생으로 이어지는 윤회의 과정이라고 주장한다.', true, '불교는 윤회설을 바탕으로 무명을 깨닫지 못한 중생에게 죽음은 다음 생으로 이어지는 윤회의 과정이라고 본다.'),
    (gen_random_uuid()::text, set_id, 51, '도가', '도가는 죽음은 흩어져 있던 기가 모인 상태라고 주장한다.', false, '도가에서의 죽음은 기의 모임이 아니라 흩어짐에 해당한다.'),
    (gen_random_uuid()::text, set_id, 52, '도가', '도가는 생사는 차별해서는 안 되는 순환의 과정이라고 주장한다.', true, '도가에서는 생사를 사계절의 순환에 비유한다. 그러나 이를 불교의 윤회 개념으로 생각해서는 안 된다. 불교 또한 생사를 차별해서는 안 되는 순환의 과정으로 보는 것은 동일하지만, 도가가 죽고 난 후에 다음 생으로 윤회한다고 보는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 53, '도가', '도가는 삶과 죽음은 좋아하거나 싫어할 대상이 아니라고 주장한다.', true, '교육과정상 도가 사상은 삶을 좋아할 것으로 여기지 않고 죽음을 싫어할 것으로 여기지도 않는다.'),
    (gen_random_uuid()::text, set_id, 54, '도가', '도가는 삶과 죽음을 분별하여 고통에서 벗어나야 한다고 주장한다.', false, '도가는 삶과 죽음을 분별해야 한다고 주장하지 않는다. 도가에 삶과 죽음은 차별이 없는 것이고, 사계절의 변화와 같은 것이다.'),
    (gen_random_uuid()::text, set_id, 55, '도가', '도가는 삶과 죽음은 사계절의 운행처럼 필연적인 과정이라고 주장한다.', true, '도가는 삶과 죽음을 사계절의 운행에 비유하여 주로 도가 사상에서 사계절의 비유는 자연스러움을 나타낼 때 많이 쓰인다.'),
    (gen_random_uuid()::text, set_id, 56, '도가', '도가는 삶과 죽음의 분별에서 벗어나야 도에 일치할 수 있다고 주장한다.', true, '교육과정상의 도가 사상은 삶과 죽음을 차별하지도 분별하지도 않는다.'),
    (gen_random_uuid()::text, set_id, 57, '도가', '도가는 죽음은 인간의 삶에 일어나는 자연스러운 현상이라고 주장한다.', true, '죽음을 자연스러운 것이라고 보는 관점은 유교, 불교, 도가 모두 공통된다.'),
    (gen_random_uuid()::text, set_id, 58, '도가', '도가는 현세에서의 도덕적 실천이 내세에서의 삶을 결정한다고 주장한다.', false, '교육과정상 도가 사상은 내세를 설정하지 않는다. 교육과정상 동양 사상 중 내세를 설정하는 것은 불교만이라고 보면 된다.'),
    (gen_random_uuid()::text, set_id, 59, '도가', '도가는 죽음의 공포를 극복하기 위해서 의로움에 힘써야 한다고 주장한다.', false, '도가는 죽음의 공포를 극복하기 위해서 의로움에 힘써야 한다고 주장하지 않는다. 도가에 따르면 죽음은 자연적인 과정이므로 죽음에 초연해야 한다.'),
    (gen_random_uuid()::text, set_id, 60, '도가', '도가는 삶에 얽매이지도 말고 죽음을 걱정하지도 말아야 한다고 주장한다.', true, '도가에 따르면 삶에 얽매이지도 말고 죽음에 대해서도 처음부터 걱정하지 말아야 한다.'),
    (gen_random_uuid()::text, set_id, 61, '도가', '도가는 죽음에 대한 성찰과 애도의 의무를 이행해야 한다고 주장한다.', false, '교육과정상 도가 사상에서는 죽음에 대해 애도할 의무가 있다고 보지 않는다. 장자는 죽음에 임하여 너무 슬퍼하지 말며, 삶에 지나치게 집착하지 말라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 62, '도가', '도가는 죽음은 기가 흩어지는 것이므로 슬퍼할 이유가 없다고 주장한다.', true, '도가는 죽음을 기의 흩어짐으로 보며, 슬퍼할 이유가 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 63, '도가', '도가는 죽음은 깨달음을 통해 벗어나야 할 고통들 중 하나라고 주장한다.', false, '도가 사상은 죽음을 고통이라고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 64, '도가', '도가는 죽음은 상례를 통해 애도해야만 하는 슬픈 일이라고 주장한다.', false, '도가가 아니라 유교의 입장에 해당한다. 도가에서는 생사에 초연할 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 65, '도가', '도가는 삶과 죽음은 사계절의 운행과 같이 기가 정기적으로 순환하는 과정이라고 주장한다.', true, '교육과정상 삶과 죽음을 봄 여름 가을 겨울의 순환, 사계절에 비유한다.'),
    (gen_random_uuid()::text, set_id, 66, '도가', '도가는 죽음은 기가 모이고 흩어지는 과정의 일부라고 주장한다.', true, '도가 사상에 따르면, 기가 모이면 삶이 되고 흩어지면 죽음이 된다. 따라서 죽음은 기가 모이고 흩어지는 변화 과정의 일부이다.'),
    (gen_random_uuid()::text, set_id, 67, '도가', '도가는 삶과 죽음은 운명에 따라 주기적으로 순환한다고 주장한다.', true, '도가는 삶과 죽음이 사계절의 변화처럼 주기적으로 순환한다고 본다.'),
    (gen_random_uuid()::text, set_id, 68, '도가', '도가는 죽음은 괴로운 인간 삶에서 벗어난 지극한 경지라고 주장한다.', false, '도가에 있어서 죽음은 모였던 기가 흩어지는 자연스러운 현상이다. 괴로운 인간 삶에서 벗어난 지극한 경지가 아니다.'),
    (gen_random_uuid()::text, set_id, 69, '도가', '도가는 죽음은 모든 만물의 근원인 도와 연관된 현상이라고 주장한다.', true, '도가에 따르면 삶과 죽음의 분별에서 벗어나 도에 일치할 수 있다. 즉 죽음은 도와 연관된 자연스러운 현상이다.'),
    (gen_random_uuid()::text, set_id, 70, '도가', '도가는 삶에 집착하지 않고 자연스러운 도를 따라야 한다고 주장한다.', true, '장자의 사상에 부합하는 내용이다. 장자는 삶과 죽음은 모두 운명으로 받아들인 일이므로 삶을 기뻐하지도, 죽음을 미워하지도 말아야 한다고 본다. 장자는 삶과 죽음은 다른 것이 아니니, 삶에 집착할 필요가 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 71, '도가', '도가는 죽음은 기가 모였다가 흩어진 자연스러운 현상이라고 주장한다.', true, '교육과정상 기의 취산에 의한 현상으로 보는 관점은 도가의 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 72, '도가', '도가는 삶과 죽음의 변화는 계절의 변화처럼 자연스러운 것이라고 주장한다.', true, '장자에 따르면 삶과 죽음의 변화는 계절의 변화처럼 자연스러운 것이다. 즉 도가 사상가 장자는 도에 의해서 우주 만물이 생성되고, 다시 소멸하는 것처럼, 사물도 태어나고 늙어 죽는 것은 자연스러운 것이라고 보았다.'),
    (gen_random_uuid()::text, set_id, 73, '도가', '도가는 죽음을 거부하면서 도덕을 실천하는 삶을 추구해야 한다고 주장한다.', false, '도가 사상은 죽음을 거부해야 한다고 주장하지 않는다. 장자의 덕은 타고난 것을 온전히 보전하는 상태를 의미하며, 인위적 규범을 배제하고 자연을 보전하는 것을 의미한다.'),
    (gen_random_uuid()::text, set_id, 74, '도가', '도가는 죽음을 의식하지 말고 인의예지를 행해야 한다고 주장한다.', false, '도가 사상가 장자는 인의예지를 행해야 한다고 주장하지 않는다. 인의예지는 유교에서 강조하는 덕에 해당한다.'),
    (gen_random_uuid()::text, set_id, 75, '도가', '도가는 삶과 죽음의 악순환을 끊는 것이 이상적 인간의 경지라고 주장한다.', false, '도가에 따르면 삶과 죽음의 이치가 범상치 않은 변화이고 그 변화가 도래했다고 해서 싫어하지 않는다고 하였다. 따라서 도가는 삶과 죽음의 순환 변화를 악순환으로 여기지 않는다.'),
    (gen_random_uuid()::text, set_id, 76, '도가', '도가는 죽음은 인간의 자연스러운 운명이므로 슬퍼할 이유가 없다고 주장한다.', true, '도가 사상가 장자는 운명에 대해 긍정한다. 장자는 사계절이 변하듯이 기의 변화 과정에서 삶과 죽음이 바뀌는 것일 뿐이니 슬퍼할 필요가 없다라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 77, '도가', '도가는 진인이라 해도 그의 삶과 죽음은 기의 변화에 의한 것이라고 주장한다.', true, '장자는 기가 생겨 그것이 변하여 형체가 되고 생명이 되고 죽음이 된 것이라 하였다. 이러한 우주의 변화는 누구에게나 적용되는 것이다.'),
    (gen_random_uuid()::text, set_id, 78, '도가', '도가는 삶과 죽음은 낮과 밤처럼 순환하므로 초연하게 대해야 한다고 주장한다.', true, '장자는 죽음을 낮과 밤, 사계절의 변화와 같이 자연스러운 것으로 받아들여야 하는 순명이자 안명이라고 본다. 따라서 삶과 죽음에 대해 기뻐할 필요나 슬퍼할 필요도 없고 초연한 태도를 지녀야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 79, '도가', '도가는 인의 구현을 위해서라면 나의 생명을 희생할 수 있어야 한다고 주장한다.', false, '도가가 아니라 유교의 입장에 해당한다. 살신성인이다.'),
    (gen_random_uuid()::text, set_id, 80, '도가', '도가는 죽음은 자신의 업에 의해 또 다른 삶을 결정짓는 윤회의 과정이라고 주장한다.', false, '업으로 인해 윤회하는 것은 교육과정상 도가가 아닌 불교 사상의 내용에 해당한다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '에피쿠로스', '에피쿠로스는 죽음 이후에 비로소 선의 본질이 드러난다고 주장한다.', false, '에피쿠로스는 죽으면 육체와 영혼을 구성한 원자들이 흩어져서 더 이상 어떤 감각도 느끼지 못한다고 주장한다. 즉 에피쿠로스는 살아 있을 때 선을 경험할 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 2, '에피쿠로스', '에피쿠로스는 현세의 삶은 사후의 영혼의 삶에 영향을 준다고 주장한다.', false, '유물론자인 에피쿠로스는 인간의 육체와 영혼이 원자로 구성되어 있으며 죽음 이후에 우리가 이미 존재하지 않는다고 보며, 사후의 영혼의 삶을 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 3, '에피쿠로스', '에피쿠로스는 지혜로운 사람에게 죽음은 두려움의 대상이 아니라고 주장한다.', true, '에피쿠로스는 지혜로운 사람은 죽음에 대해서 올바르게 인식할 수 있다고 본다. 죽음은 곧 감각의 상실이기 때문에 고통을 느낄 수 없다는 사실을 아는 지혜로운 사람은 죽음을 두려움의 대상으로 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 4, '에피쿠로스', '에피쿠로스는 죽음을 통해 인간의 쾌락과 고통의 감각이 소멸된다고 주장한다.', true, '에피쿠로스에 따르면, 죽으면 감각 능력이 상실되므로 쾌락이나 고통에 대한 감각 능력도 자연히 소멸된다.'),
    (gen_random_uuid()::text, set_id, 5, '에피쿠로스', '에피쿠로스는 참된 지혜는 육체의 구속에서 벗어난 사후에만 얻어진다고 주장한다.', false, '사후에도 영혼이 존재한다고 보는 입장은 플라톤의 입장이지 에피쿠로스의 입장이 아니다.'),
    (gen_random_uuid()::text, set_id, 6, '에피쿠로스', '에피쿠로스는 불멸에 대한 욕망에서 벗어날 근거는 내세의 행복에 있다고 주장한다.', false, '에피쿠로스는 영혼 불멸, 내세라는 죽음에 대한 생각이 잘못되었다고 보고, 그러한 잘못된 생각 때문에 삶에서 고통을 받게 된다고 주장했다.  즉, 에피쿠로스는 현생에서 불멸에 대한 열망을 추구하지 않는다.'),
    (gen_random_uuid()::text, set_id, 7, '에피쿠로스', '에피쿠로스는 불멸에 대한 열망을 통해 죽음의 불안에서 벗어나야 한다고 주장한다.', false, '에피쿠로스에 따르면 죽음의 불안에서 벗어나기 위해서는 죽음이 아무것도 아니라는 것을 인식해야 한다.'),
    (gen_random_uuid()::text, set_id, 8, '에피쿠로스', '에피쿠로스는 죽음 이후에는 인간을 구성하는 요소들이 완전히 사라진다고 주장한다.', false, '에피쿠로스에 따르면, 죽음은 인간을 구성하는 원자들이 흩어져 다시 우주의 일부가 된다. 이 원자들은 사라지지 않고 다른 형태로 존재하게 된다. 즉 죽음은 원자들이 흩어지는 과정일 뿐, 인간을 구성하는 요소들이 완전히 사라지는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 9, '에피쿠로스', '에피쿠로스는 감각할 수 없는 자신의 죽음 때문에 불안을 느낄 필요가 없다고 주장한다.', true, '에피쿠로스는 죽음이 곧 감각의 상실이며, 산 사람 죽은 사람 모두가 죽음을 감각할 수 없으므로 인해 불안할 필요도 없다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 10, '에피쿠로스', '에피쿠로스는 죽은 후에 고통을 겪지 않도록 죽음을 두려워하지 말아야 한다고 주장한다.', false, '에피쿠로스는 죽은 후에 고통을 겪지 않으므로 죽음을 두려워하지 말라고 주장하지 않는다. 에피쿠로스는 오히려 죽음 후에 고통을 겪지 않기 때문에 죽음을 두려워할 필요가 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 11, '에피쿠로스', '에피쿠로스는 죽음은 육체의 고통을 낳지만 죽음에 대한 이해는 평온을 낳는다고 주장한다.', false, '에피쿠로스는 죽음을 원자들의 흩어짐으로 보고, 이로 인해 감각이 사라져 쾌락이나 고통을 느낄 수 없다는 것을 의미한다. 에피쿠로스에 따르면, 죽음에 대한 이해는 우리에게 마음의 평온을 가져다 준다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 12, '에피쿠로스', '에피쿠로스는 살아 있는 사람과 죽은 사람 모두 자신의 죽음을 경험할 수 없다고 주장한다.', true, '에피쿠로스는 죽은 사람은 감각의 주체인 영혼이 소멸해 죽음을 감각하거나 경험할 수 없으므로 죽음이 두려움의 대상이 아니라고 주장한다. 에피쿠로스는 산 사람이나 죽은 사람 모두 자신의 죽음을 경험할 수 없다라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 13, '에피쿠로스', '에피쿠로스는 죽음이라는 실체를 수용해야 불멸에 대한 열망을 실현할 수 있다고 주장한다.', false, '에피쿠로스는 죽음에 대한 두려움과 불멸에 대한 갈망이 인간을 고통스럽게 만든다고 보며, 죽음은 우리에게 아무것도 아니므로 죽음을 두려워할 필요도, 죽지 않음을 갈망할 필요도 없다라고 본다.'),
    (gen_random_uuid()::text, set_id, 14, '에피쿠로스', '에피쿠로스는 죽음은 영원한 삶으로 이행하는 과정이므로 두려워해서는 안 된다고 주장한다.', false, '에피쿠로스는 영혼의 불멸이나 내세와 같은 개념을 부정한다. 따라서 죽음 이후에 영원한 삶이 존재한다고 보지 않으며, 죽음은 그저 감각의 상실을 의미하는 상태를 의미한다.'),
    (gen_random_uuid()::text, set_id, 15, '에피쿠로스', '에피쿠로스는 죽은 후에 쾌락을 얻을 수도 있으므로 죽음을 두려워할 필요가 없다고 주장한다.', false, '에피쿠로스에 따르면 죽음은 인간의 모든 감각 능력을 상실하는 것이다. 따라서 에피쿠로스는 죽음 이후에는 쾌락을 얻을 수 없고 죽음을 두려워할 필요가 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 16, '갑(하이데거)/을(플라톤)', '하이데거는 현존재는 죽음을 의식하며 어떻게 살 것인지 고뇌하는 존재라고 주장한다.', true, '하이데거는 현존재가 동물들과는 달리 죽음을 의식할 수 있고, 죽음을 의식함으로써 삶을 더욱 의미있고 가치있게 살 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '갑(하이데거)/을(플라톤)', '하이데거는 인간은 죽음에 대한 자각을 할 수 있다는 점에서 동물과 다르다고 주장한다.', true, '하이데거는 인간이 동물과 달리 죽음을 자각할 수 있는 존재라고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '갑(하이데거)/을(플라톤)', '플라톤은 죽음의 순간에 육체의 소멸과 함께 영혼도 소멸한다고 주장한다.', false, '영혼은 불멸한다고 본 것은 플라톤이다. 플라톤은 죽음의 순간에 육체에서 영혼이 해방되어 이데아의 세계로 감으로써 이데아의 진리를 얻을 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 19, '갑(하이데거)/을(플라톤)', '플라톤은 죽음의 두려움은 감각적 쾌락을 통해 해소되어야 한다고 주장한다.', false, '플라톤은 감각적 쾌락을 통해 죽음의 두려움을 해소해야 한다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 20, '갑(하이데거)/을(플라톤)', '플라톤은 지혜로운 사람에게 죽음은 두려움의 대상이 아니라고 주장한다.', true, '플라톤에 따르면 지혜로운 사람은 죽음 이후에 영혼이 육체에서 벗어나, 이데아의 세계로 들어갈 수 있음을 안다고 본다. 따라서 플라톤의 관점에서 죽음은 두려움의 대상이 아니다.'),
    (gen_random_uuid()::text, set_id, 21, '갑(하이데거)/을(플라톤)', '플라톤은 불멸에 대한 열망을 통해 죽음의 불안에서 벗어나야 한다고 주장한다.', false, '플라톤은 현생에서 불멸에 대한 열망을 추구하지 않는다. 플라톤에 따르면 죽음은 영혼이 육체에서 벗어나 순수한 인식을 얻을 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 22, '갑(하이데거)/을(플라톤)', '플라톤은 지혜로운 사람은 죽음을 두려워하면서도 의연히 받아들인다고 주장한다.', false, '플라톤은 지혜를 사랑하는 자는 죽음을 싫어하지 않는다고 보며, 따라서 인간의 죽음을 두려움의 대상으로 보는 것은 부적절하다고 본다.'),
    (gen_random_uuid()::text, set_id, 23, '갑(하이데거)/을(플라톤)', '플라톤은 죽음은 불멸의 영혼이 육체의 구속에서 벗어나 자유를 누리는 과정이라고 주장한다.', true, '플라톤은 영혼을 불멸의 존재로 보았으며 육체는 순수한 인식을 방해하는 감옥이라고 본다.'),
    (gen_random_uuid()::text, set_id, 24, '갑(하이데거)/을(플라톤)', '플라톤은 사람들이 추구하는 가치가 달라도 죽음을 대하는 태도는 같다고 주장한다.', false, '플라톤에 따르면 철학자는 영혼을 몸으로부터 해방시키는 것에 관심을 두고 모든 사람들 중에서 죽음을 가장 덜 두려워한다. 이 말에서 사람들의 죽음을 대하는 태도가 모두 동일한 것은 아니라는 것을 알 수 있다.'),
    (gen_random_uuid()::text, set_id, 25, '갑(하이데거)/을(플라톤)', '하이데거와 플라톤은 죽음을 회피하는 태도보다 죽음에 대한 바른 인식이 필요하다고 주장한다.', true, '하이데거는 죽음 앞에 실존적 결단을 할 수 있으므로 죽음을 회피하지 말고, 죽음에 대해 바른 인식을 하라고 주장한다. 플라톤은 죽음은 영혼이 육체에서 벗어나, 이데아의 세계로 들어가는 것임을 인식해야 한다고 본다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '공자', '공자는 직업을 통해 최대한의 이익을 추구해야 한다고 주장한다.', false, '직업을 통해 최대한의 이익을 추구해야 한다는 관점이 공자의 입장이라고 보기는 어렵다.'),
    (gen_random_uuid()::text, set_id, 2, '공자', '공자는 각자가 자기의 직분에 충실할 때 공동체가 유지된다고 주장한다.', true, '공자는 정명 정신에 입각하여 임금과 신하가 자기의 직분에 충실해야 할 것을 강조하며, 각자가 직분에 충실할 때 공동체가 유지된다고 본다.'),
    (gen_random_uuid()::text, set_id, 3, '공자', '공자는 부의 축적의 궁극적인 정당화 근거를 금욕에서 찾는다고 주장한다.', false, '공자는 부의 축적의 궁극적 정당화 근거를 금욕에서 찾아야 한다고 주장하지 않았다. 금욕에서 부의 축적 정당화는 칼뱅의 입장이다.'),
    (gen_random_uuid()::text, set_id, 4, '공자', '공자는 자신의 사회적 역할에 부합하는 도리를 실천해야 한다고 주장한다.', true, '공자는 각자 맡은 바 직분을 올바르게 할 것을 주장한다. 이는 각자의 사회적 역할에 부합하는 도리를 실천해야 한다는 입장이다.'),
    (gen_random_uuid()::text, set_id, 5, '공자', '공자는 사회적 직분에는 그것에 합당한 도덕적 덕목이 요구된다고 주장한다.', true, '공자에 따르면 사회적 직분에는 그에 합당한 덕목이 요구된다.'),
    (gen_random_uuid()::text, set_id, 6, '공자', '공자는 각자는 역할 수행에 필요한 덕을 갖추도록 노력해야 한다고 주장한다.', true, '공자는 합당한 덕목을 각자가 갖추어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 7, '공자', '공자는 누구나 자신의 직업을 선택할 수 있는 자유를 가져야 한다고 주장한다.', false, '공자는 직업을 자율적으로 선택하는 것이 아니라 각자의 덕에 따라 직분이 정해져야 한다라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 8, '공자', '공자는 각자 자신이 맡은 직분 외에도 모든 분야에 능통해야 한다고 주장한다.', false, '공자는 군자와 소인이 각각 어떤 일은 잘 못하고 어떤 일은 잘 할 수 있다고 주장한다. 따라서 각자가 모든 분야에 능통해야 한다는 말은 공자의 입장에 부합하지 않는다.'),
    (gen_random_uuid()::text, set_id, 9, '공자', '공자는 자기 본분을 올바르게 행하여 공동체의 질서를 유지해야 한다고 주장한다.', true, '공자는 각자 맡은 바 직분을 올바르게 하면 나라가 잘 다스려진다고 주장한다. 이는 곧 자기 본분을 올바르게 행하여 공동체의 질서를 유지해야 한다는 입장이다.'),
    (gen_random_uuid()::text, set_id, 10, '공자', '공자는 구성원의 역할이 분담되면 자연스럽게 이상적 국가가 실현된다고 주장한다.', false, '공자가 추구하는 이상적 국가는 대동사회이며, 대동사회는 역할 분담을 통해 자연스럽게 실현되는 것이 아니라 통치자와 구성원들의 노력을 통해 사회적 약자가 보호되고 가족주의에 얽매이지 않음으로써 실현되는 것이다.'),
    (gen_random_uuid()::text, set_id, 11, '맹자', '맹자는 성인은 백성의 기본적 생계유지를 중시한다고 주장한다.', true, '맹자는 도덕적 통치자가 민본주의에 기반한 왕도 정치를 시행하기 위해서는 백성의 기본적 생계유지를 중시해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 12, '맹자', '맹자는 직업 선택은 능력보다 선호에 의해 이루어져야 한다고 주장한다.', false, '맹자는 직업 선택은 능력보다 선호에 의해야 한다고 하지 않는다. 맹자는 통치자가 사회 구성원들의 적성 및 능력을 고려해 직분을 부여해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 13, '맹자', '맹자는 직업을 선택할 때 생계유지의 문제는 중요하지 않다고 주장한다.', false, '맹자는 생계유지를 중요시한다.'),
    (gen_random_uuid()::text, set_id, 14, '맹자', '맹자는 다양한 직업들 사이에는 상호 보완적 관계가 성립한다고 주장한다.', true, '맹자는 사회적 분업을 바탕으로 직업들 사이에 상호 보완적 관계를 중시한다.'),
    (gen_random_uuid()::text, set_id, 15, '맹자', '맹자는 통치자와 피치자의 합의에 따라 역할 교환이 가능하다고 주장한다.', false, '맹자 또한 통치자와 피치자를 구분하는 사회적 분업에 찬성하지만 그러한 직분의 분업은 정명에 근거하여 덕, 능력에 따라 결정되는 것이지 합의에 의해서 교환될 수 있는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 16, '맹자', '맹자는 모든 사람은 각자가 맡은 직분과 역할에 충실해야 한다고 주장한다.', true, '맹자는 정명 사상에 근거하여 국가 구성원이 각자 맡은 역할에 충실해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '맹자', '맹자는 사회적 분업은 사회 질서를 유지하는 데 기여할 수 있다고 주장한다.', true, '맹자는 사회적 분업에 따른 자신의 직분에 충실할 때 사회 질서가 유지된다고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '맹자', '맹자는 직업 선택의 기준에서 경제적 보상을 가장 중시해야 한다고 주장한다.', false, '맹자는 물론 경제적 보상을 마냥 등한시하는 것은 아니다. 그러나 이를 가장 중시할 만한 것으로 보는 것도 아니다. 맹자에게는 경제적 이익보다도 도덕성이 더 우선되어야 하는 가치이다.'),
    (gen_random_uuid()::text, set_id, 19, '맹자', '맹자는 다스림의 근본은 의로움보다 이로움에 두어야 한다고 주장한다.', false, '맹자는 정치인이 추구해야 할 것은 이로움 보다는 인의라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 20, '맹자', '맹자는 직업을 선택할 때에는 인격에 미치는 영향을 고려해야 한다고 주장한다.', true, '맹자에 따르면, 직업 선택에 신중해야 하는 이유로 선한 마음을 지키는 것이 포함된다. 즉 맹자는 인격에 미치는 영향을 고려하여 선한 마음을 확충하는 직업이 보다 바람직하다고 본다.'),
    (gen_random_uuid()::text, set_id, 21, '맹자', '맹자는 분업을 통해 사회적 직분 간의 유기적 관계를 이루어야 한다고 주장한다.', true, '맹자는 사회 구성원들이 각자 생계유지나 재능을 교환하면서 사회에 기여한다고 본다. 즉 맹자는 분업을 통해 다양한 직분 사이의 유기적 관계를 이루어야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 22, '맹자', '맹자는 경제적 안정은 백성의 도덕적 인격 수양의 조건이 될 수 있다고 주장한다.', true, '생계가 안정된 것은 항산에 해당하고, 도덕성을 유지하는 것은 항심에 해당한다. 맹자의 입장에서 항산이 없어도 항심을 지닐 수 있는 자는 선비이다.'),
    (gen_random_uuid()::text, set_id, 23, '맹자', '맹자는 노력자는 생계가 안정되어야 도덕성을 유지할 수 있다고 주장한다.', true, '맹자의 항산항심론에 따르면 몸을 쓰는 사람인 노력자는 항산이 있어야 항심을 유지할 수 있다.'),
    (gen_random_uuid()::text, set_id, 24, '맹자', '맹자는 몸을 쓰는 사람은 항산에 앞서 항심을 지녀야 한다고 주장한다.', false, '맹자에 따르면 몸을 쓰는 사람은 항산이 있어야 항심을 유지할 수 있다. 즉 항산이 먼저이며, 선비만이 항산 없이도 항심을 지닐 수 있다.'),
    (gen_random_uuid()::text, set_id, 25, '맹자', '맹자는 직업 선택에서 사회적 기여보다 개인의 출세를 더 중시해야 한다고 주장한다.', false, '맹자는 사회적 기여의 가치를 개인적 출세의 가치보다 낮다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 26, '순자', '순자는 예에 맞게 사회적 분업이 이루어져야 한다고 주장한다.', true, '순자는 각자의 직분을 나누는 것이 예법의 핵심이다라고 주장한다. 즉 순자는 예에 맞게 직업의 분업이 이루어져야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 27, '순자', '순자는 직분의 구분은 공동체 이익 증진에 도움이 된다고 주장한다.', true, '순자는 예에 근거하여 그 사람의 덕, 능력, 적성에 따라 사회적 직분이 구별되어야 한다고 보며, 그래야 공동체에 이익을 줄 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 28, '순자', '순자는 백성들의 직업 활동은 욕망 충족과 무관해야 한다고 주장한다.', false, '순자에 따르면, 백성들의 직업 활동은 예와 관련 있는 것이므로 욕망 충족과 무관하다고 할 수 없다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 29, '순자', '순자는 노동을 통한 정당한 이익의 추구는 권장될 수 있다고 주장한다.', true, '순자는 직업 생활을 통해 백성의 욕망을 제한할 뿐만 아니라 정당한 이익을 취할 수 있도록 함으로써 욕망을 적절히 충족시키고 길러주어야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 30, '순자', '순자는 군자는 도를 익혀야만 자신의 일을 완수할 수 있다고 주장한다.', true, '순자는 도에 정통한 사람은 이 세 가지 일을 하도록 못해도, 이 세 가지 일을 다스릴 수 있다라고 주장한다. 순자에 따르면 군자는 도에 정통한 사람이기에, 계속 수양을 쌓으며 자신을 갖고 닦음으로써 백성을 잘 다스려야 한다.'),
    (gen_random_uuid()::text, set_id, 31, '순자', '순자는 사회적 분업을 토대로 한 사회 질서 유지를 중시한다고 주장한다.', true, '순자는 사회적 역할 분업을 강조하는데, 이는 사회적 분업이라고도 표현할 수 있는 것이다. 순자는 사회 구성원들의 분업을 바탕으로 한 사회 질서 유지를 강조한다.'),
    (gen_random_uuid()::text, set_id, 32, '순자', '순자는 백성의 직분은 예보다 능력을 기준으로 맡겨져야 한다고 주장한다.', false, '순자의 예는 능력과 적성에 따라 사회적 역할을 분담하고 사회적 재화를 분배하는 기준으로서의 역할을 수행하는 차등의 원리이다. 예라는 기준 안에 이미 능력이 포함된다는 내용이 포함된다.'),
    (gen_random_uuid()::text, set_id, 33, '순자', '순자는 자신의 사회적 역할에 부합하는 도리를 실천해야 한다고 주장한다.', true, '순자는 예에 근거하여 각자의 덕과 능력에 맞게 역할이 분배되고 각자가 그 역할에 부합하는 도리를 다 해야 한다는 점을 강조한다.'),
    (gen_random_uuid()::text, set_id, 34, '순자', '순자는 군주가 나라를 다스리려면 모든 직분에 통달해야 한다고 주장한다.', false, '순자는 군주, 즉 지도자가 모든 직분에 통달해야 한다고 주장하지 않는다. 오히려 순자에 따르면 도에 정통한 사람은 농부, 상인, 공인의 일을 하나도 하지 못해도 그 일을 다스리고 지도할 수 있다.'),
    (gen_random_uuid()::text, set_id, 35, '순자', '순자는 사회 구성원의 직분을 나누는 도덕적 기준이 존재한다고 주장한다.', true, '순자는 예가 도덕의 기준이며 사회 구성원의 직분을 나누는 기준이라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 36, '순자', '순자는 자신의 직분을 다하는 것은 동시에 예를 실천하는 일이라고 주장한다.', true, '순자는 예를 통해 각 개인의 직분을 명확히 하고, 각자가 자신이 직분에 충실히 임하는 것이 곧 예의 실천이라고 본다. 예를 통해 사회적 역할을 분담함으로써 각자가 자신의 역할을 충실히 수행할 때 사회의 안정과 조화가 유지될 수 있다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 37, '순자', '순자는 적성에 맞는 직업을 스스로 선택하여 부를 쌓아야 한다고 주장한다.', false, '순자는 성왕이 예를 제정하여 사람들에게 귀함과 천함의 등급을 분별하게 하였다라고 하면서, 각 개인이 자신의 적성에 맞는 직업을 선택하기보다는 사회적 예에 따라, 개인의 적성, 자질, 능력, 덕성 등을 고려하여 주어진 직분을 수행해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 38, '순자', '순자는 모든 사람은 각자가 맡은 직분과 역할에 충실해야 한다고 주장한다.', true, '순자는 사회적 분업에 따른 자신의 직분에 충실하여 사회 질서가 유지될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 39, '순자', '순자는 사회적 분업은 사회 질서를 유지하는 데 기여할 수 있다고 주장한다.', true, '순자는 직업 선택을 개인의 덕성과 능력에 따라 정해져야 한다고 그 기본 입장에서 비롯된다. 순자는 각 개인이 적합한 직분을 맡을 때 사회 전체의 조화와 효율이 극대화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 40, '순자', '순자는 직업의 배분에서 개인의 자질을 분별하는 것은 필수적이라고 주장한다.', true, '순자는 직업 선택은 개인의 덕성과 능력에 따라 정해져야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '순자', '순자는 올바른 직분 수행을 위해 예법에 따라 욕망을 절제해야 한다고 주장한다.', true, '순자는 인간을 이기적이고 욕망을 추구하는 존재라고 보며 예를 통해 이를 적절히 절제해야 한다고 주장한다. 즉 순자는 직분 수행에 있어 예법에 따라 욕망을 절제해야 한다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 42, '정약용', '정약용은 근검절약하면서도 인색하지 않도록 노력해야 한다고 주장한다.', true, '정약용은 자신이 여유롭다 하더라도 절약할 수 있는 검소함을 지녀야 한다라고 주장하며 절약을 강조한다. 또한, 인색함은 정약용이 추구하는 바가 아니다.'),
    (gen_random_uuid()::text, set_id, 43, '정약용', '정약용은 가족의 생계를 위해 목민관의 관직을 맡는 것은 바람직하다고 주장한다.', false, '정약용은 가족의 가난이 아닐지라도, 이러한 처지를 벗어나려는 목적으로 목민관이 되는 것은 올바르지 않다고 본다.'),
    (gen_random_uuid()::text, set_id, 44, '정약용', '정약용은 공과 사를 분명하게 구분하는 것은 목민관의 올바른 태도라고 주장한다.', true, '정약용은 청탁과 뇌물을 금기시했으며, 작은 선물이라도 경계해야 한다고 본다. 이는 공과 사를 명백히 구분하는 정약용의 청렴 정신을 보여준다.'),
    (gen_random_uuid()::text, set_id, 45, '정약용', '정약용은 공직자는 절약의 대상을 사적인 영역으로 국한해서는 안 된다고 주장한다.', true, '정약용은 공직자가 사적인 영역뿐만 아니라 공적인 영역에서도 절약해야 한다는 점을 강조한다. 또한 정약용에 따르면 공직자는 절약을 해야 청렴할 수 있으며, 공직자가 청렴해야 백성들에게 자애할 수 있다.'),
    (gen_random_uuid()::text, set_id, 46, '정약용', '정약용은 비싼 옷을 살 여유가 있더라도 목민관은 소비를 절제해야 한다고 주장한다.', true, '정약용은 공직자 자신의 체면을 지키는 과도한 소비를 자제하며 사치와 탐욕에서 벗어나야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 47, '정약용', '정약용은 공직자의 절용 실천은 애민 정신의 실현을 목적으로 한다고 주장한다.', true, '정약용은 공직자가 절용과 청렴을 통해 애민 정신을 실천해야 한다고 본다. 정약용은 공직자의 이러한 청렴과 절용은 풍요롭고 안정된 사회 조성의 기반이 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 48, '정약용', '정약용은 공직자는 청렴하기 위해 검소하고 절약하는 태도를 가져야 한다고 주장한다.', true, '정약용은 공직자가 청렴의 자세를 지녀야 한다고 주장하며, 청렴을 공직자의 본무이자 모든 선의 원천이며 덕의 근본으로 본다. 또한 정약용에 따르면 공직자의 이러한 청렴과 절용은 풍요롭고 안정된 사회 조성의 기반이 된다.'),
    (gen_random_uuid()::text, set_id, 49, '정약용', '정약용은 공직자는 자신의 체면을 지키려는 과도한 소비를 자제해야 한다고 주장한다.', true, '만약 목민관에 임명되어 부임지에 갈 때에는 부유하더라도 검소한 차림이어야 하며, 관청의 재물이나 자신이 여유롭다 하더라도 절약할 수 있는 검소함을 지녀야 한다.'),
    (gen_random_uuid()::text, set_id, 50, '정약용', '정약용은 목민관은 관할 지역의 학문 풍토를 조성하기 위해 노력해야 한다고 주장한다.', true, '정약용은 학문 풍토를 조성하는 것도 목민관의 역할이라고 본다. 고을의 선비들에게 학문을 권장하기 위해 수레의 책을 가져가는 것이 청렴한 관리의 자세이다.'),
    (gen_random_uuid()::text, set_id, 51, '정약용', '정약용은 공직자는 절용을 백성 통치의 유일한 실천 방안으로 삼아야 한다고 주장한다.', false, '정약용이 절용이 수령의 으뜸가는 임무라 주장하지만, 절용이 백성 통치의 유일한 실천 방안인 것은 아니다. 정약용은 공직자가 청렴, 절용, 애민을 통해 실천해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 52, '정약용', '정약용은 공직자의 청렴 실천은 인의예지를 구현하는 바탕이 된다고 주장한다.', true, '정약용은 유교의 실학자이므로 인의예지의 덕을 강조한다. 또한 정약용은 인의라는 도덕의 근본도 청렴에 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 53, '정약용', '정약용은 공직자는 곤궁한 친척을 도우려는 어진 마음조차 가져서는 안 된다고 주장한다.', false, '정약용은 공직자가 공공의 자금으로 친척을 돕는 것에는 반대하지만, 그렇다고 곤궁한 친척을 돕는 어진 마음을 지니지 말라고 주장한 것은 아니다. 정약용은 자신의 녹봉을 활용하여 곤궁한 친척에게 두루 베푸는 것도 긍정한다.'),
    (gen_random_uuid()::text, set_id, 54, '정약용', '정약용은 공직자의 청렴과 절용은 풍요롭고 안정된 사회 조성의 기반이 된다고 주장한다.', true, '정약용은 공직자의 이러한 청렴과 절용이 풍요롭고 안정된 사회 조성의 기반이 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 55, '정약용', '정약용은 공직자는 올바른 공무 수행을 위해 사치와 낭비, 탐욕을 없애야 한다고 주장한다.', true, '정약용은 공직자 자신의 체면을 지키는 과도한 소비를 자제하며 사치와 탐욕에서 벗어나야 한다고 본다. 즉 정약용에 따르면 공직자는 올바른 공무 수행을 위해 사치와 낭비, 탐욕을 없애야 한다.'),
    (gen_random_uuid()::text, set_id, 56, '정약용', '정약용은 공직자는 공적 재산이 국민의 노력으로 이루어진 것임을 유념해야 한다고 주장한다.', true, '정약용은 공직자가 백성을 위해서 있어야 한다고 주장하며, 공적 재산이 국민의 노력으로 이루어진 것을 유념하며 애민 정신과 백성에 대한 봉사를 강조한다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '플라톤', '플라톤은 구성원 각자가 직분을 충실히 이행해야 한다고 주장한다.', true, '플라톤은 타고난 성질에 의해 정해진 각 계층의 직분을 충실히 행할 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 2, '플라톤', '플라톤은 공직자에게는 엄격한 자기 절제가 필요하다고 주장한다.', true, '플라톤은 통치자가 절제의 덕을 바탕으로 현실에서 금을 탐하려는 것이 아니라고 본다. 즉 플라톤은 오직 자신과 나라를 정의롭게 하는 데 힘써야 하는 통치자로서의 자기 절제를 강조한 것으로 볼 수 있다.'),
    (gen_random_uuid()::text, set_id, 3, '플라톤', '플라톤은 직업 분담에 있어 각자의 탁월성을 중시해야 한다고 주장한다.', true, '플라톤은 직업에 있어서 분업을 강조한다. 즉 플라톤은 통치자, 방위자, 생산자 3계층이 각자에게 요구되는 탁월성을 발휘하는 것을 중시한다.'),
    (gen_random_uuid()::text, set_id, 4, '플라톤', '플라톤은 각자의 덕을 발휘하여 국가 공동체에 헌신해야 한다고 주장한다.', true, '플라톤은 국가의 구성원이 각자의 성향의 덕을 발휘하여 국가 공동체에 역할을 할 때 정의를 달성할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 5, '플라톤', '플라톤은 사회적 분업을 토대로 한 사회 질서 유지가 중요하다고 주장한다.', true, '플라톤은 사회적 역할 분업을 강조하는데, 이는 사회적 분업이라고도 표현할 수 있는 것이다. 플라톤은 직업의 분업을 바탕으로 사회 구성원들의 조화를 통해 사회 질서를 유지하고, 정의를 추구해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 6, '플라톤', '플라톤은 통치자와 피치자의 합의에 따라 역할 교환이 가능하다고 주장한다.', false, '플라톤은 통치자와 피치자의 역할을 구분하는 사회적 분업을 주장한다. 나아가 플라톤은 피치자가 통치에 관여할 경우, 나라가 파멸할 것이라고 강력하게 경고한다. 따라서 플라톤은 3계층 간 합의에 따른 역할 교환이 가능하다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 7, '플라톤', '플라톤은 시민의 사회적 지위 배정에 국가가 관여해서는 안 된다고 주장한다.', false, '플라톤은 어린 아이들이 시민으로 교육을 받은 뒤에, 타고난 성향에 따라, 적절한 사회적 지위에 배정받아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 8, '플라톤', '플라톤은 사회적 직분의 구분은 공동체 이익 증진에 도움이 된다고 주장한다.', true, '플라톤은 타고난 성향에 근거하여 통치자, 방위자, 생산자의 세 계층을 구분할 것을 주장한다. 플라톤은 이러한 직분의 구분을 바탕으로 각자의 직분을 탁월하게 발휘하여 조화를 이루어야 공동체에 이익이 되는 정의로운 사회가 달성된다고 본다.'),
    (gen_random_uuid()::text, set_id, 9, '플라톤', '플라톤은 사회적 직분에는 그것에 합당한 도덕적 덕목이 요구된다고 주장한다.', true, '플라톤은 통치자, 방위자, 생산자가 각자 직분에 맞는 타고난 성향의 덕인 지혜, 용기, 절제를 발휘해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 10, '플라톤', '플라톤은 각자는 역할 수행에 필요한 덕을 갖추도록 노력해야 한다고 주장한다.', true, '플라톤은 각자 직분에 합당한 덕목이 요구된다고 본다. 플라톤은 타고난 능력이 있더라도 제대로 교육받지 못해 능력을 발휘하지 못한다면 덕성이 있더라도 소용이 없다고 주장한다. 따라서 플라톤은 개인들은 타고난 덕을 갖추도록 노력해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 11, '플라톤', '플라톤은 누구나 자신의 직업을 선택할 수 있는 자유를 가져야 한다고 주장한다.', false, '플라톤은 누구나 직업을 자유롭게 택할 수 있는 것이 아니라 각자의 처지에 맞는 직업만이 가능할 뿐, 타고난 성향을 벗어나는 다른 직업은 선택할 수 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 12, '플라톤', '플라톤은 세 계층이 각자의 직분에 충실하면서 정의가 실현될 수 있다고 주장한다.', true, '플라톤에 따르면 각자가 제 할 일을 하고 참견하지 않는 것이 정의이다. 즉 플라톤은 타고난 성향에 근거하여 통치자, 방위자, 생산자의 세 계층의 구분을 바탕으로 각자의 직분을 탁월하게 발휘하여 조화를 이루어야 정의가 실현될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 13, '플라톤', '플라톤은 생산자와 수호자는 서로 간섭하지 않고 자급자족해야 한다고 주장한다.', false, '플라톤은 각 계층이 서로의 일에 간섭해서는 안 된다고 본다. 물론, 통치자와 방위자는 생산자에게 지시를 내리는 간섭도 아니다. 또한 플라톤은 분업을 주장했으므로, 생산자와 수호자가 각각 자급자족 해야 한다고 주장하지도 않았다.'),
    (gen_random_uuid()::text, set_id, 14, '플라톤', '플라톤은 올바른 통치를 위해 다스리는 자의 사유 재산을 금지해야 한다고 주장한다.', true, '플라톤은 통치자와 방위자가 사유 재산을 갖게 되면 국가를 위해 헌신하지 않고 자신의 것을 지키기 위해 노력할 것이기 때문에 사유 재산을 가져서는 안 된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 15, '플라톤', '플라톤은 구성원의 역할이 분담되면 자연스럽게 이상적 국가가 실현된다고 주장한다.', false, '플라톤의 관점에서 구성원의 역할이 분담되면, 자연스럽게 최소국가가 이루어진다는 것이지, 역할 분담만으로 자연스럽게 이상적 국가가 실현되는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 16, '플라톤', '플라톤은 통치자는 지혜의 덕을 발휘하여 정의로운 국가를 추구해야 한다고 주장한다.', true, '플라톤에 따르면 지혜로운 철학자가 타고난 지혜의 덕을 발휘하여 정의로운 국가를 추구해야 한다.'),
    (gen_random_uuid()::text, set_id, 17, '플라톤', '플라톤은 통치자는 시민들이 통치에 직접 참여할 수 있도록 허용해야 한다고 주장한다.', false, '플라톤은 시민이 통치에 직접 참여하는 것이 아니라 절제와 용기, 지혜의 덕을 갖춘 정의로운 인간, 즉 철인이 국가를 다스릴 때 조화롭고 정의로운 국가가 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '칼뱅', '칼뱅은 부의 축적이 직업의 궁극적 목적이라고 주장한다.', false, '칼뱅의 직업관은 부의 축적을 긍정하지만, 이러한 부의 축적이 직업의 궁극적 목적인 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 19, '칼뱅', '칼뱅은 인위적 규범에 따른 직분의 구별을 주장한다.', false, '칼뱅은 직분의 구별을 인위적인 규범이 아니라, 신으로부터 받은 명령인 소명에 따른 것으로 본다.'),
    (gen_random_uuid()::text, set_id, 20, '칼뱅', '칼뱅은 각자의 직분에 충실할 때 사회 질서가 유지된다고 주장한다.', true, '칼뱅은 직업 소명의 관점에서 바라보면, 신이 사람들에게 각자 맡아 해야 할 일을 정해 주었다고 주장한다. 칼뱅은 각자가 자신의 직분에 충실할 때 사회가 혼란에 빠지지 않고 질서가 유지된다고 본다.'),
    (gen_random_uuid()::text, set_id, 21, '칼뱅', '칼뱅은 노동이 가진 생계 수단 이상의 가치를 중시한다고 주장한다.', true, '칼뱅은 노동의 가치를 신의 부름인 소명에 따르는 것에서 찾는다. 즉 생계 수단 이상의 가치를 중시한다.'),
    (gen_random_uuid()::text, set_id, 22, '칼뱅', '칼뱅은 노동을 통하여 이웃 사랑을 실천할 것을 강조한다고 주장한다.', true, '칼뱅은 직업 소명의 관점에서 직업을 사랑의 터전으로 보며, 노동을 통한 이웃 사랑 실천을 강조한다.'),
    (gen_random_uuid()::text, set_id, 23, '칼뱅', '칼뱅은 노동을 통한 정당한 이익의 추구는 권장될 수 있다고 주장한다.', true, '칼뱅은 절제, 근면, 성실, 검약한 생활 태도로 직업에 종사해야 한다고 주장하며 이러한 태도를 통한 직업적 성공과 부의 추구를 긍정한다.'),
    (gen_random_uuid()::text, set_id, 24, '칼뱅', '칼뱅은 구원은 근면과 검소에 대해 주어지는 응분의 보상이라고 주장한다.', false, '칼뱅은 구원이 근면과 검소에 대해 주어지는 응분의 보상이 아니며, 직업 활동의 성공을 얻기 이전에 이미 구원 여부가 정해져 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 25, '칼뱅', '칼뱅은 적성에 맞는 직업을 스스로 선택하여 부를 쌓아야 한다고 주장한다.', false, '칼뱅은 직업을 신이 각자에게 부여한 소명으로 보았으며, 이는 개인의 선택이나 적성보다는 신이 각자에게 맡긴 의무를 수행하는 데 중점을 둔다.'),
    (gen_random_uuid()::text, set_id, 26, '칼뱅', '칼뱅은 신이 각자에게 부여한 소명에 따라 직업에 귀천이 생긴다고 주장한다.', false, '칼뱅은 직업을 신이 부여한 소명으로 보며, 신의 소명에 따르는 직업 간에는 귀천이 없다고 주장했다.'),
    (gen_random_uuid()::text, set_id, 27, '칼뱅', '칼뱅은 노동으로 얻은 부를 베푸는 선행은 신의 영광을 드러낸다고 주장한다.', true, '칼뱅은 직업 소명설을 통해 자신의 직업에 충실히 하는 것이 곧 신의 명령에 따르는 것이며, 직업을 성실하게 수행하여 봉사를 적극적으로 실천함으로써 신의 영광을 구현해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 28, '칼뱅', '칼뱅은 금욕적인 생활 태도를 바탕으로 한 직업 생활을 해야 한다고 주장한다.', true, '칼뱅은 직업의 소명을 실천하기 위해서 검소하고 금욕적인 태도를 지녀야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 29, '마르크스', '마르크스는 노동 착취가 자본 축적의 원천이라고 주장한다.', true, '마르크스의 자본 축적에 대한 견해로 적절하다. 마르크스는 자본주의가 존립하는 근본적인 토대가 노동자에 대한 착취에 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 30, '마르크스', '마르크스는 필요에 따른 분배가 노동 의욕을 저하시킨다고 주장한다.', false, '마르크스는 능력에 따라 일하고 필요에 따라 분배받는 것을 추구한다.'),
    (gen_random_uuid()::text, set_id, 31, '마르크스', '마르크스는 분업 노동이 자본주의 발전에 기여했다고 본다고 주장한다.', true, '마르크스는 분업 노동을 통해 자본가가 노동자를 착취하여 자본주의가 발전하였다고 본다.'),
    (gen_random_uuid()::text, set_id, 32, '마르크스', '마르크스는 자본주의의 노동 분업이 노동 소외의 원인이라고 주장한다.', true, '마르크스는 노동 분업을 노동 소외, 인간 소외의 원인으로 본다.'),
    (gen_random_uuid()::text, set_id, 33, '마르크스', '마르크스는 노동의 분업을 통해 인간 소외를 극복해야 한다고 주장한다.', false, '마르크스는 노동의 분업을 인간 소외의 원인으로 비판하기 때문에, 노동의 분업을 통해 인간 소외를 극복하는 것은 불가능하다고 본다.'),
    (gen_random_uuid()::text, set_id, 34, '마르크스', '마르크스는 자본주의에서는 노동자의 자아실현이 불가능하다고 주장한다.', true, '마르크스는 노동자의 자아실현은 진정한 노동을 통해 가능한데, 자본주의 사회에서는 노동이 소외되어 진정한 노동을 수행할 수 없으므로, 자본주의 사회에서는 노동자가 자아를 실현할 수 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 35, '마르크스', '마르크스는 자발적 노동을 통해 인간의 본질을 실현해야 한다고 주장한다.', true, '마르크스는 자본주의 사회에서의 강요된 노동이 아니라 공산주의 사회에서의 자발적 노동을 통해 인간 본질을 실현할 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 36, '마르크스', '마르크스는 자본주의에서 정신적 능력 회복으로 소외가 극복된다고 주장한다.', false, '마르크스는 자본주의 분업 시스템에서 노동자들이 노동에서 소외되는 현상을 극복하기 위해서는 자본주의 분업 시스템과 사적 소유를 철폐해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 37, '마르크스', '마르크스는 육체노동보다 정신노동에 더 높은 가치를 부여해야 한다고 주장한다.', false, '마르크스는 육체노동보다 정신노동에 더 높은 가치를 부여해야 한다고 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 38, '마르크스', '마르크스는 분업이 노동자의 정신적 능력 쇠퇴와 소외를 심화시킨다고 주장한다.', true, '마르크스는 자본주의의 분업 시스템은 노동자를 일개 부품의 역할로 전락시켜 정신적 능력을 쇠퇴하게 함으로써, 소외 현상을 심화시킨다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 39, '마르크스', '마르크스는 노동 생산성을 향상하여 사유 재산의 축적을 추구해야 한다고 주장한다.', false, '마르크스는 사유 재산의 축적을 추구하지 않고, 오히려 생산 수단을 공유하여 사적 소유를 철폐해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 40, '마르크스', '마르크스는 신이 부여한 노동의 신성한 의미를 현실 속에서 구현해야 한다고 주장한다.', false, '마르크스가 아니라 칼뱅의 주장에 해당한다. 오히려 마르크스는 유물론을 주장한 사상가로서 기독교적 관점의 신을 부정하고 신은 그저 인간의 상상력의 산물이라고 보았으며 종교를 인민의 아편이라고 비판했다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '아리스토텔레스', '아리스토텔레스는 분배적 정의만이 비례를 추구하는 특수적 정의라고 주장한다.', false, '아리스토텔레스에 따르면 분배적 정의뿐만 아니라 시정적 정의도 비례를 추구하는 특수적 정의에 해당한다. 아리스토텔레스에게 분배적 정의는 기하학적 비례, 시정적 정의는 산술적 비례에 따른 동등함을 의미한다.'),
    (gen_random_uuid()::text, set_id, 2, '아리스토텔레스', '아리스토텔레스는 재화의 분배는 개인의 자유로운 선택에 맡겨야 한다고 주장한다.', false, '아리스토텔레스는 재화에 대한 개인의 자유로운 선택이 아니라, 각자의 가치에 비례하여 분배되어야 한다고 본다. 아리스토텔레스는 정의를 실현하는 방법으로서 기하학적 비례를 강조하는데 예를 들어 100의 기여를 한 사람이 100만원을 받는다면, 200의 기여를 한 사람은 200만원을 받아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 3, '아리스토텔레스', '아리스토텔레스는 누구에게도 이익이 되지 않는 분배는 정의롭지 않다고 주장한다.', true, '교육과정상 누구에게도 이익이 되지 않는 분배를 찬성할 사람은 없다. 아리스토텔레스에 따르면, 많은 공적을 지닌 사람은 많은 이익을 얻어야 한다.'),
    (gen_random_uuid()::text, set_id, 4, '아리스토텔레스', '아리스토텔레스는 각자의 가치에 비례하여 각자의 몫이 분배되어야 한다고 주장한다.', true, '아리스토텔레스는 특수적 정의의 한 종류인 분배적 정의에서 각자의 가치에 비례하여 권력, 명예, 재화를 분배해야 한다는 기하학적 비례에 따른 동등함을 추구한다.'),
    (gen_random_uuid()::text, set_id, 5, '아리스토텔레스', '아리스토텔레스는 분배 정의는 기하학적 비례의 동등함을 추구하는 것이라고 주장한다.', true, '아리스토텔레스는 특수적 정의의 한 종류인 분배적 정의에서 각자의 가치에 비례하여 권력, 명예, 재화를 분배해야 한다는 기하학적 비례에 따른 동등함을 추구한다.'),
    (gen_random_uuid()::text, set_id, 6, '아리스토텔레스', '아리스토텔레스는 분배와 교환의 정의는 모두 비례의 동등함을 따라야 한다고 주장한다.', true, '아리스토텔레스는 분배적 정의와 교환적 정의 모두 비례의 동등함을 따라야 한다고 본다. 아리스토텔레스에 따르면 분배적 정의는 기하학적 비례를, 교환적 정의는 산술적 비례를 따라야 한다.'),
    (gen_random_uuid()::text, set_id, 7, '아리스토텔레스', '아리스토텔레스는 사회 경제적 불평등을 허용해도 분배 정의는 실현 가능하다고 주장한다.', true, '아리스토텔레스는 가치에 따라 명예, 재화 등을 분배해야 하므로 가치에 따른 사회 경제적 불평등이 발생할 수 있으며, 이는 기하학적 비례의 동등함을 만족시키는 불평등이다.'),
    (gen_random_uuid()::text, set_id, 8, '아리스토텔레스', '아리스토텔레스는 정의로운 사회는 각자에게 각자의 당연한 몫을 할당해야 한다고 주장한다.', true, '아리스토텔레스는 각자에게 마땅한 것이 공정하게 주어지는 것을 정의로 본다. 따라서 아리스토텔레스는 정의로운 사회가 각자에게 각자의 당연한 몫을 할당해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 9, '아리스토텔레스', '아리스토텔레스는 정의로운 분배는 비례적이고 부정의한 분배는 비례에 어긋난다고 주장한다.', true, '아리스토텔레스는 재화의 정의로운 분배는 각자의 가치를 고려한 기하학적 비례에 따라야 한다고 본다. 따라서 아리스토텔레스에 따르면, 기하학적 비례에 어긋나는 분배는 부정의하다.'),
    (gen_random_uuid()::text, set_id, 10, '롤스', '롤스는 차등의 원칙은 자연적 우연성의 영향을 완화한다고 주장한다.', true, '롤스는 차등의 원칙이 자연적 우연성의 영향을 완화한다고 본다. 롤스는 우연적인 요소로 이득을 얻는 것은 최소 수혜자에게 이익이 되어야 한다는 제한 조건하에 허용될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 11, '롤스', '롤스는 능력에 따른 분배는 정의 원칙에 어긋날 수 있다고 주장한다.', true, '롤스는 능력주의를 비판한다. 즉 개인이 선천적으로 타고나게 된 능력을 당연히 받아야 할 몫으로 바라보아서는 안 되며, 그러므로 이에 대해 자격이 있다고도 할 수 없는 것이다. 해당 선지는 노직도 동의할 수 있다. 노직은 능력에 따른 분배를 정형화된 분배 원칙으로 보며, 이는 개인의 소유 권리를 침해하게 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 12, '롤스', '롤스는 공정한 절차를 거친다면 그 분배는 모두 정의롭다고 주장한다.', true, '롤스에 따르면 분배 절차의 공정성에 의해 분배 결과의 정의가 보장된다. 롤스는 순수 절차적 정의에 따라 발생한 분배 결과가 그 내용에 상관없이 정의로운 것이라고 본다. 이러한 순수 절차적 정의에 입각한 사회는 정의로운 제도 체계의 설립과 운영, 정의로운 체제를 포함한 정의로운 기본 구조를 배경을 통해서만 성립된다.'),
    (gen_random_uuid()::text, set_id, 13, '롤스', '롤스는 개인은 사유 재산을 소유할 불가침적 권리를 지닌다고 주장한다.', true, '롤스는 사유 재산을 소유할 권리가 정의의 제1원칙에 의해 보장되어야 하는 권리라고 본다. 이 권리는 모든 개인이 평등하게 보장받아야 하는 권리이므로 함부로 침해될 수 없는 불가침적 권리이다.'),
    (gen_random_uuid()::text, set_id, 14, '롤스', '롤스는 무지의 베일 속 개인은 자유롭고 평등한 인격체라고 주장한다.', true, '롤스의 무지의 베일은 개인의 자유와 평등을 보장하는데, 이는 모든 개인이 동일한 조건에서 출발하여 정의의 원칙을 선택하게 함으로써, 그들이 자유롭고 평등한 인격체로서 행동할 수 있게 한다. 왜냐하면 무지의 베일 속에서의 개인들은 자신이 어떤 사회적 위치에 있는지 모르기 때문에, 그들은 자신에게 유리하거나 불리한 원칙을 선택할 수 없기 때문이다.'),
    (gen_random_uuid()::text, set_id, 15, '롤스', '롤스는 자기 노동의 결과에 대해서만 정당한 소유권을 갖는다고 주장한다.', false, '롤스는 자신의 노동이 투입되지 않은 결과물에 대해서도 소유할 권리를 지닐 수 있다고 본다. 예를 들어 상속의 경우에도, 정의의 원칙에 부합되게끔 이루어진다면 그에 대한 소유 권리를 지닐 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 16, '롤스', '롤스는 차등의 원칙은 천부적 능력의 차등이 있어도 성립한다고 주장한다.', true, '롤스는 차등의 원칙은 천부적 능력의 차등이 있어도 성립한다고 본다. 애초에 차등의 원칙은 천부적 능력의 차등으로 인한 영향을 적절히 조정하기 위한 원칙이다.'),
    (gen_random_uuid()::text, set_id, 17, '롤스', '롤스는 개인의 소유권을 침해하지 않는 과세 정책은 가능하다고 주장한다.', true, '롤스는 정당하게 확립된 세금 제도는 사유 재산권을 침해하지 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '롤스', '롤스는 정의의 원칙은 정당화될 수 있는 불평등을 규정해준다고 주장한다.', true, '롤스는 정의의 원칙 중 제2원칙이 요구하는 바를 충족시키면, 사회적 경제적 불평등이 정당화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 19, '롤스', '롤스는 정의의 원칙이 보장하는 기본적 권리는 제한될 수 없다고 주장한다.', false, '롤스의 정의론에서 기본적 권리는 절대적이지 않으며, 특정한 상황에서 제한될 수 있다. 이는 기본적 자유들이 서로 충돌할 수 있기 때문이다.'),
    (gen_random_uuid()::text, set_id, 20, '롤스', '롤스는 차등 원칙은 모든 성원을 고려한 상호 이익의 원칙이라고 주장한다.', true, '롤스의 정의의 원칙 중에서 특히 차등의 원칙은 사회의 모든 성원을 고려하는, 상호 이익의 원칙에 해당한다.'),
    (gen_random_uuid()::text, set_id, 21, '롤스', '롤스는 차등의 원칙은 더 큰 재능의 소유자에게 유익할 수 있다고 주장한다.', true, '롤스는 유리한 재능을 가진 사람들이 자신의 재능을 불리한 처지 하의 사람들에게 적절하게 활용할 시, 사회의 기본 구조는 그 유리한 재능의 소유자에게 보상을 함으로써 더 많은 이익을 획득하도록 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 22, '롤스', '롤스는 재산의 평등한 분배는 정의 원칙에 의해 허용될 수 있다고 주장한다.', true, '롤스는 차등의 원칙이 요구하는 최소 수혜자에게 최대의 이익, 모두에게 이익이라는 조건이 충족되지 않는 경우 재산이 평등하게 분배되어야 한다고 본다. 즉, 롤스는 모두에게 이익이 되는 불평등만을 허용하는 것이다.'),
    (gen_random_uuid()::text, set_id, 23, '롤스', '롤스는 기본적 자유는 절대적이기에 각 개인에게 평등해야 한다고 주장한다.', false, '롤스는 자유가 공공선을 위해서는 제한되거나 부정될 수 없지만, 하나 혹은 그 이상의 다른 기본적 자유들을 위해서만 어떤 기본적 자유가 제한되거나 부정될 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 24, '롤스', '롤스는 재산에 대한 사적 소유권은 차등적으로 분배되어야 한다고 주장한다.', false, '롤스는 재산에 대한 사적 소유권, 즉 사유 재산을 소유할 권리는 제1원칙(평등한 자유의 원칙)에서 언급되는 기본적 자유에 속한다고 본다. 이러한 기본적 자유는 평등하게 주어지는 것이므로, 사적 소유권이 차등적으로 분배되어야 한다는 주장은 롤스의 입장이 아니다.'),
    (gen_random_uuid()::text, set_id, 25, '롤스', '롤스는 천부적 자산에 대한 개인의 소유 권리는 제한할 수 없다고 주장한다.', false, '천부적 자산에 대한 개인의 소유 권리란, 타고난 재능과 능력에 대한 개인의 소유 권리로 이해할 수 있다. 그런데 제1원칙, 즉 평등한 기본적 자유의 원칙에 의해 포괄되는 권리도, 다른 기본적 자유들과 상충한다면 제한될 수 있다.'),
    (gen_random_uuid()::text, set_id, 26, '롤스', '롤스는 사유 재산을 소유할 권리는 제1원칙에 의해 평등해야 한다고 주장한다.', true, '롤스는 사유 재산을 소유할 권리가 정의의 제1원칙인 평등한 기본적 자유의 원칙에 의해 보장되는 기본적 자유, 즉 기본권이라고 본다.'),
    (gen_random_uuid()::text, set_id, 27, '롤스', '롤스는 개인은 자신의 유리한 천부적 자산을 소유할 권한을 갖는다고 주장한다.', true, '롤스는 개인은 자신의 천부적 자산에 대한 권한을 가지고 있다고 주장한다. 또한, 이는 기본적 자유인 제1원칙에 의해 포괄된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 28, '롤스', '롤스는 원초적 입장의 당사자들은 상호 신뢰할 수 있는 존재들이라고 주장한다.', true, '원초적 입장의 당사자들은, 그들의 합의로 인해 도출된 정의의 원칙에 모두가 따를 것이라는 신뢰를 하게 된다. 개인들은 이러한 합리성을 지닌 사람들이기 때문에, 오히려 서로의 이익에 무관심하면서도, 모두가 정의의 원칙을 준수할 것이라는 신뢰를 하게 된다.'),
    (gen_random_uuid()::text, set_id, 29, '롤스', '롤스는 정의로운 분배 결과로 생긴 불평등은 조정의 대상이 아니라고 주장한다.', true, '롤스의 입장에서, 정의로운 분배 결과는 정의의 원칙에 따른 분배 결과를 의미한다. 즉, 여기서 결과는 차등의 원칙 등을 만족하는 결과라는 의미이다. 즉, 최소 수혜자에게 최대의 이익이 되는 결과일 것이다. 그러한 결과는 순수 절차적 정의에 따른 결과이며, 공정한 절차를 통해 도출된 결과는 추가적인 조정이 필요하지 않다.'),
    (gen_random_uuid()::text, set_id, 30, '롤스', '롤스는 기본적 자유가 개인들에게 불평등하게 분배되어서는 안 된다고 주장한다.', true, '롤스는 기본적 자유가 제1원칙에 의해, 모든 사람들에게 평등하게 부여되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 31, '롤스', '롤스는 사회 구성원 모두의 협력을 가능하게 하는 분배만이 정당하다고 주장한다.', true, '롤스는 사회의 기본 구조가 정의의 원칙들을 기반으로 조직되어야 한다고 주장한다. 사회 협력을 통해 발생하는 이익은 모든 구성원에게 공정하게 분배되어야 하며, 특히 최소 수혜자의 이익이 보장되어야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 32, '롤스', '롤스는 정의 원칙 수립 시 당사자 간 합의는 가설적이고 비역사적이라고 주장한다.', true, '롤스는 원초적 상황을 설정할 때, 그 상황 자체가 순수한 가상적인 상황이며, 역사적으로 실존했던 상황이 아니라고 본다.'),
    (gen_random_uuid()::text, set_id, 33, '롤스', '롤스는 개인은 사회적 운의 결과물에 대해 정당한 자격을 갖지 않는다고 주장한다.', true, '롤스에게 자연적 운과 사회적 운은 도덕적으로 정당하다 또는 부정의하다고 평가할 수 없으므로, 각 개인은 그러한 운에 대한 응분의 자격 또는 정당한 자격을 갖지 않는다. 그러한 운은 그들이 정당한 자격, 응분의 자격을 지녀서 얻게 된 것이 아니라, 단지 우연히 갖게 된 것에 불과하기 때문이다.'),
    (gen_random_uuid()::text, set_id, 34, '롤스', '롤스는 원초적 입장에서 당사자들의 합의는 호혜적인 사회를 지향하게 된다고 주장한다.', true, '롤스에 따르면 원초적 입장의 당사자들은 자신이 사회에서 어떤 위치에 있게 될지 모르기 때문에, 모두에게 이익이 되는 원칙을 선택하게 된다. 즉, 호혜성을 중심으로 조직된다는 것을 함의한다.'),
    (gen_random_uuid()::text, set_id, 35, '롤스', '롤스는 천부적 능력이 분배 몫의 결정에 미치는 영향을 경감시킬 필요는 없다고 주장한다.', false, '롤스는 천부적 능력이 분배 몫의 결정에 미치는 영향을 경감시켜야 한다고 본다. 롤스는 사회 정의의 의미를 우연성이 지배하는 방식이 아니라, 이러한 우연성의 영향을 조정하는 방식에서 찾아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 36, '롤스', '롤스는 자연적 사회적 우연성의 이용에 따른 경제적 불평등은 허용될 수 있다고 주장한다.', true, '롤스는 최소 수혜자에게 이익이 된다는 조건하에서, 우연성에 의한 이익을 허용할 수 있다고 본다. 따라서 롤스는 절차상의 정당성이 확보된다면, 우연성으로 인한 불평등도 정당화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 37, '롤스', '롤스는 최소 수혜자에게 이익이 되지 않는 소득은 평등하게 분배되어야 한다고 주장한다.', true, '롤스에 따르면, 사회적 경제적 불평등은 공정한 기회 균등의 배경하에 모두에게 이익이 되는 조건하에서만 허용되며, 최소 수혜자들은 그들에게 이익이 되지 않는 불평등에 대한 거부권을 갖는다.'),
    (gen_random_uuid()::text, set_id, 38, '롤스', '롤스는 공정한 분배를 위해 올바른 결과에 대한 독립적 기준이 필수적으로 요구된다고 주장한다.', false, '롤스는 순수 절차적 정의의 관념에 따라 결과의 공정성이 절차의 공정성에 의존하기 때문에, 절차와 독립된 결과의 공정성이 별도로 존재하지 않는다고 본다. 즉 결과가 올바르기 위해서는, 절차가 공정해야 한다는 것이다.'),
    (gen_random_uuid()::text, set_id, 39, '롤스', '롤스는 차등의 원칙은 자연적 운의 도덕적 임의성을 처리하는 공정한 분배의 원칙이라고 주장한다.', true, '롤스는 사회의 어떤 특정한 지위에서 태어나는 것은 주로 공정한 기회 균등의 원칙을 통해서, 천부적으로 타고난 것은 주로 차등의 원칙을 통해서 그 영향력을 완화시킬 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 40, '롤스', '롤스는 기본적 자유들이 상충하더라도 그 기본적 자유들은 서로 균등하게 보장되어야 한다고 주장한다.', false, '롤스는 기본적 자유들이 상충할 수 있으므로 어떠한 기본적 자유도 절대적이지 않다고 본다. 따라서, 기본적 자유가 상충할 경우에는 균등하게 보장되는 것이 아니라, 제한되거나 부정될 수 있다라고 봐야 한다.'),
    (gen_random_uuid()::text, set_id, 41, '롤스', '롤스는 최소 수혜자에게 이득이 된다면 천부적 재능으로 인한 소득 격차도 허용될 수 있다고 주장한다.', true, '개인의 천부적 재능은 개인의 의지와 무관한 임의적인 요소, 즉 우연적인 요소이다. 롤스는 우연적인 요소로 이득을 얻는 것은 최소 수혜자에게 이익이 되어야 한다는 제한 조건하에 허용될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 42, '롤스', '롤스는 더 많은 재능을 타고난 자가 자신의 재능을 활용하여 더 많은 이익을 획득하도록 장려되는 경우가 있다고 주장한다.', true, '롤스는 사회 구조가 유리한 재능을 가진 사람들이 자신의 재능을 불리한 처지 하의 사람들에게 적절하게 활용할 시, 사회의 기본 구조는 그 유리한 개인에게 보상을 함으로써 더 많은 이익을 획득하도록 해야 한다고 본다. 따라서 최소 수혜자도 최초의 평등 상태보다 처지가 더욱 상승하고, 유리한 개인들도 이미 이익을 보고 있지만 재능의 적절한 사용을 통해 더 많은 이익을 얻도록 사회의 기본 구조가 장려한다는 것이다.'),
    (gen_random_uuid()::text, set_id, 43, '노직', '노직은 능력에 따른 분배는 정의 원칙에 어긋날 수 있다고 주장한다.', true, '노직은 능력에 따른 분배를 정형화된 분배 원칙으로 보며, 이는 개인의 소유 권리를 침해하게 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 44, '노직', '노직은 공정한 절차를 거친다면 그 분배는 모두 정의롭다고 주장한다.', true, '노직은 분배 결과의 공정성이 분배 과정, 즉 절차의 공정성에 근거한다고 보며, 공정한 분배 과정을 거쳐 획득한 재화는 마땅히 그 사람의 것이 되어야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 45, '노직', '노직은 최소 국가는 시민들의 권리를 차별적으로 보호한다고 주장한다.', false, '노직에 따르면 최소 국가는 시민들의 권리를 차별적으로 보호하지 않고 오히려 시민들의 권리를 차별 없이 보호하는 역할을 한다. 최소 국가는 모든 시민들에게 동일한 권리 보호를 제공해야 하며, 개인들의 소유권을 침해하지 않도록 해야 한다.'),
    (gen_random_uuid()::text, set_id, 46, '노직', '노직은 개인은 사유 재산을 소유할 불가침적 권리를 지닌다고 주장한다.', true, '노직은 사유 재산을 소유할 권리가 절대적으로 존중되어야 한다고 보며, 역사적으로 소유물의 최초 취득과 소유물의 이전이 모두 정의롭다면, 그 소유물에 대한 권리는 국가라고 할지라도 함부로 침해해서는 안 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 47, '노직', '노직은 역사적 원리에 따른 부의 불평등은 정당화될 수 있다고 주장한다.', true, '노직은 역사적 과정을 거쳐서 형성된 현재의 정당한 소유 권리에 따른 사회적 경제적 불평등은 정당화된다고 본다.'),
    (gen_random_uuid()::text, set_id, 48, '노직', '노직은 개인의 소유권을 침해하지 않는 과세 정책은 가능하다고 주장한다.', true, '노직에 따르면, 세금이 합법적일 수 있는 유일한 형태는, 방어, 치안, 정의의 집행을 위한 경우 뿐이다.'),
    (gen_random_uuid()::text, set_id, 49, '노직', '노직은 자기 노동의 결과에 대해서만 정당한 소유권을 갖는다고 주장한다.', false, '노직은 자기 노동의 결과가 아니더라도, 자발적 교환, 증여와 같은 자유로운 이전을 통해서도 소유권을 가질 수 있다고 본다. 노직은 그러한 소유권 양도를 정당화해주는 정의 원리를 이전의 원리라고 부른다.'),
    (gen_random_uuid()::text, set_id, 50, '노직', '노직은 분배의 결과보다 소유 과정의 정당성을 중시해야 한다고 주장한다.', true, '노직은 분배의 결과보다 소유 과정의 정당성을 중시해야 한다고 본다. 노직은 소유가 최초 취득·이전·교정의 원칙에 따라 이루어졌으면 그 결과가 불평등해도 해당 소유물들은 개인들이 소유할 권리와 자격이 주어진다고 본다.'),
    (gen_random_uuid()::text, set_id, 51, '노직', '노직은 지능 지수에 따른 분배 원리는 역사적이고 정형적이라고 주장한다.', false, '노직에 따르면 지능 지수에 따른 분배는 비역사적이고 정형적이다. 정형화된 비역사적 이론은 지능 지수, 공리의 총합과 같이 객관적인 분배 기준을 가지고 있고, 소유물 획득의 역사적 과정이 아니라 현 시점에서의 분배 구조 혹은 결과에 초점을 맞추는 정의론이다.'),
    (gen_random_uuid()::text, set_id, 52, '노직', '노직은 소유물 취득의 정당성은 타인의 처지 개선을 요구한다고 주장한다.', false, '노직은 소유물 취득에 있어서 타인의 처지 개선을 요구하지 않는다. 단지 노직이 주장하는 것은 소유물 최초 취득에 있어서 타인의 처지를 악화시키지 말라는 것이다.'),
    (gen_random_uuid()::text, set_id, 53, '노직', '노직은 정의의 원칙은 정당화될 수 있는 불평등을 규정해준다고 주장한다.', true, '노직은 소유물에서의 정의의 원칙(취득의 원칙, 이전의 원칙, 부정의 교정의 원칙)을 충족시키는 경제적 불평등이 정당화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 54, '노직', '노직은 국가는 자유롭게 체결된 계약의 이행을 강제할 수 있다고 주장한다.', true, '노직의 입장에서 계약 이행을 강제하는 것은 오히려 개인의 소유 권리를 보호하는 것으로 이해되어야 한다. 노직에 따르면 만약 개인 간에 체결된 계약이 정당함에도 불구하고 계약 당사자가 계약 내용을 이행하지 않는 경우에는 국가가 개입하여 해당 계약 이행을 강제하여야 한다.'),
    (gen_random_uuid()::text, set_id, 55, '노직', '노직은 정의의 원칙이 보장하는 기본적 권리는 제한될 수 없다고 주장한다.', false, '노직에 따르면, 개인의 권리는 도덕적 경계를 구성하며, 이 경계는 다른 사람의 권리를 침해하지 않는 범위 내에서만 허용된다. 따라서, 노직의 입장에서 개인의 권리는 다른 사람의 권리를 침해하지 않는 한에서만 보장될 수 있으며, 이러한 측면에서 권리는 제한될 수 있다.'),
    (gen_random_uuid()::text, set_id, 56, '노직', '노직은 각 개인에게 소유물을 분배하는 최소 국가만이 정의롭다고 주장한다.', false, '노직은 최소 국가가 분배를 주도해야 한다고 보지 않는다. 노직은 국가 주도의 중앙 분배가 개인의 권리를 침해하는 것이라고 보며, 소유물의 분배는 국가가 아니라, 주로 개인들이 소유물을 자유롭게 취득하고 이전함으로써 형성되는 것이다.'),
    (gen_random_uuid()::text, set_id, 57, '노직', '노직은 오직 최소국가에서만 개인의 소유 권리가 존재할 수 있다고 주장한다.', false, '자연 상태에서도 개인은 절대적이고 불가침적인 권리를 소유하고 있으며, 이는 자연법에 의해 결정된다. 최소국가는 이미 존재하는 개인의 권리를 보호하기 위해 조직된 단체이다.'),
    (gen_random_uuid()::text, set_id, 58, '노직', '노직은 도덕적 공과에 따른 소유 권리의 불평등은 정의롭다고 주장한다.', false, '노직이 정형적 분배 원리를 비판하였다는 점을 떠올리면 쉽게 풀 수 있다. 노직은 도덕적 공과와 같은 정형적인 기준에 의해 소유 권리가 불평등해지는 것은 부정의하다고 본다.'),
    (gen_random_uuid()::text, set_id, 59, '노직', '노직은 최소 국가는 정의 실현을 위해 분배 과정에 개입할 수 있다고 주장한다.', true, '노직의 국가관은 최소 국가로서, 국가가 개인들의 소유물의 취득 및 이전에 있어, 강압, 절도, 사기 등의 불의가 발생하면 개인들을 보호해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 60, '노직', '노직은 개인은 자신의 유리한 천부적 자산을 소유할 권한을 갖는다고 주장한다.', true, '노직은 개인의 타고난 재능, 역량 등의 천부적 자산은 오직 자신만이 소유할 수 있는 배타적인 것이라고 본다. 즉 노직은 천부적 자산을 소유할 권한을 기본권으로 인정한다. 이는 롤스와의 공통점이기도 하다.'),
    (gen_random_uuid()::text, set_id, 61, '노직', '노직은 분배 정의의 목표는 개인의 자유와 기본적 필요 보장에 있다고 주장한다.', false, '노직은 기본적 필요가 보장된 상태와 같은 정형적 상태를 만들기 위한 국가의 분배를 개인의 자유와 권리에 대한 침해로 본다. 물론 교정적 정의에 따른 재분배는 예외이다.'),
    (gen_random_uuid()::text, set_id, 62, '노직', '노직은 부정의한 분배의 교정 외에 국가의 역할을 허용해선 안 된다고 주장한다.', false, '노직이 주장하는 최소 국가의 역할은 부정의한 분배의 교정에만 국한되지 않는다. 노직은 강압, 절도, 사기로부터의 보호, 계약 집행 또한 최소 국가의 정당한 역할로 인정한다.'),
    (gen_random_uuid()::text, set_id, 63, '노직', '노직은 과거 상황은 사물에 대한 차별적 소유권을 창출하는 요인이라고 주장한다.', true, '노직은 과거 상황, 즉 역사적 상황이 개인의 차별적인 소유 권리를 창조한다고 본다. 이는 현재 이루어진 재화의 양도 상황만으로는 개인의 소유 권리를 정당화할 수 없고, 과거의 상황까지 모두 고려해야 개인의 소유권이 정당화된다는 노직의 입장을 나타낸다.'),
    (gen_random_uuid()::text, set_id, 64, '노직', '노직은 시정의 원칙에 따른 국가 개입은 개인의 소유 권리를 침해한다고 주장한다.', false, '노직은 시정의 원칙에 따라 국가가 개입하는 것은 개인의 소유 권리를 침해한다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 65, '노직', '노직은 취득 원칙과 이전 원칙을 충족했다면 그 소유는 정의롭다고 주장한다.', true, '노직의 입장에서 취득의 원칙과 이전의 원칙이 충족했다는 것은 해당 시점까지 교정이 필요하지 않다는 의미이다. 따라서 취득과 이전에서의 원칙을 충족한 소유는 모두 정의롭다고 할 수 있다.'),
    (gen_random_uuid()::text, set_id, 66, '노직', '노직은 개인은 사회적 운의 결과물에 대해 정당한 자격을 갖지 않는다고 주장한다.', false, '노직 입장에서 어떠한 재화가 사회적 운의 결과물로서 얻어진 것일지라도, 취득, 이전, 혹은 교정의 원칙에 부합한다면 이에 대한 정당한 자격을 가질 수 있다고 해석할 수 있다.'),
    (gen_random_uuid()::text, set_id, 67, '노직', '노직은 개인이 노동을 통해 취득한 소유물도 교정의 대상이 될 수 있다고 주장한다.', true, '노직은 노동을 통해 취득한 소유물일지라도, 그러한 취득이 타인의 재화 획득 행위를 막음으로써 타인의 입장을 악화시킨다면, 개인은 해당 재화에 대한 소유 권리를 획득할 수 없다고 본다. 따라서, 이는 교정의 대상이 될 수 있다.'),
    (gen_random_uuid()::text, set_id, 68, '노직', '노직은 정형적 원리에 따른 재분배는 이전에서의 정의에 어긋난다고 주장한다.', true, '소유물의 이전에 있어서 소유물을 받는 사람이 특정한 정형에 부합하지 않는 자격을 지닌다면, 다시 그러한 정형에 맞추기 위해 재분배를 실시할 것이기 때문에 이러한 점에서 정형적인 원리는 소유권자의 자유 의사에 반하여 재분배가 이루어지게 하므로 이전에서의 정의에 어긋난다.'),
    (gen_random_uuid()::text, set_id, 69, '노직', '노직은 자연적 사회적 우연성의 이용에 따른 경제적 불평등은 허용될 수 있다고 주장한다.', true, '노직은 소유물의 정의로운 취득 및 이전이라는 조건에서 우연성에 의한 이익을 허용할 수 있다고 본다. 그러한 절차가 지켜진다면, 소유물의 분배 결과가 불평등하더라도 부당한 것이 아니라는 입장이다.'),
    (gen_random_uuid()::text, set_id, 70, '노직', '노직은 공정한 분배를 위해 올바른 결과에 대한 독립적 기준이 필수적으로 요구된다고 주장한다.', false, '노직도 정형화된 정의론을 비판하고 객관적 분배 기준을 설정하지 않는 비정형화된 정의론을 주장한다. 따라서 노직의 입장에서도 올바른 결과에 대한 독립적 기준을 상정한다고 볼 수 없다.'),
    (gen_random_uuid()::text, set_id, 71, '노직', '노직은 자신의 노동을 투여하지 않고 취득한 소유물에 대한 정당한 소유 권리는 성립할 수 있다고 주장한다.', true, '노직은 증여 받은 소유물에 대해서도 정당한 소유 권리가 성립할 수 있다고 본다. 즉, 노동을 통하지 않더라도 소유권을 지닌 사람으로부터 정당하게 이전받은 재화에 대해서는 정당한 소유권이 성립한다고 본 것이다.'),
    (gen_random_uuid()::text, set_id, 72, '왈처', '왈처는 정의로운 사회에도 경제적 불평등이 존재할 수 있다고 주장한다.', true, '왈처는 불평등이 각자의 가치 영역이 존중되는 조건하에서 정당화될 수 있다고 보는 입장이다.'),
    (gen_random_uuid()::text, set_id, 73, '왈처', '왈처는 상이한 사회적 가치를 상이한 기준으로 분배해야 한다고 주장한다.', true, '왈처는 상이한 사회적 가치는 상이한 기준으로 분배되어야 하고, 각 영역의 가치가 분배되는 영역은 존중되어야 한다고 본다. 예를 들어, 정치 권력이 분배되는 방식과 소득이 분배되는 방식은 달라야 한다는 것이다.'),
    (gen_random_uuid()::text, set_id, 74, '왈처', '왈처는 정의의 원칙은 공정한 가상적 상황에서 선택되어야 한다고 주장한다.', false, '왈처는 정의의 원칙을 가상적 상황에서 도출하여 보편적으로 모든 사회에 적용시키는 것을 반대하며, 각 사회가 지니고 있는 고유한 역사적 의미에 따라 정의의 의미도 달라질 수 있음을 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 75, '왈처', '왈처는 영역 간 가치의 자유로운 전환은 분배의 평등을 촉진한다고 주장한다.', false, '왈처는 영역 간 가치의 자유로운 전환이 분배의 평등을 촉진한다고 보지 않는다. 왈처는 가치의 고유한 영역을 보호하며, 상이한 가치는 상이한 기준에 의해 분배되는 복합 평등을 추구한다.'),
    (gen_random_uuid()::text, set_id, 76, '왈처', '왈처는 분배적 정의와 관련되는 모든 가치들은 사회적 가치들이라고 주장한다.', true, '왈처는 분배적 정의와 관련되는 모든 가치들이 사회적 가치들이라고 본다. 즉, 왈처는 가치들의 맥락이 사회적 맥락과 무관하게 그 자체로 평가되지는 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 77, '왈처', '왈처는 정의의 세분화된 영역들을 하나의 영역으로 통합해야 한다고 주장한다.', false, '왈처는 정의의 세분화된 영역들을 하나의 영역으로 통합해야 한다고 보지 않는다. 왈처는 각자의 영역을 존중해야 하고, 어떠한 영역 내의 가치를 소유하고 있다는 이유만으로 다른 영역의 가치를 얻으려고 해서는 안 된다고 본다.'),
    (gen_random_uuid()::text, set_id, 78, '왈처', '왈처는 모든 사회적 가치는 필요의 원칙에 의해서 분배되어야 한다고 주장한다.', false, '왈처는 각 사회적 가치의 영역마다 상이한 분배 기준을 갖고 있다고 본다. 이것이 바로 복합 평등의 개념이다. 따라서 모든 사회적 가치는 ~의 기준에 따라 분배되어야 한다라는 문장 자체가 왈처에게는 해당되지 않는다.'),
    (gen_random_uuid()::text, set_id, 79, '왈처', '왈처는 가치의 분배 기준은 해당 가치의 사회적 의미에 따라 다르다고 주장한다.', true, '왈처는 해당 사회의 고유한 사회적 의미에 따라 가치의 분배 기준이 달라질 수 있다고 본다. 왈처는 분배 기준을 보편적·획일적으로 통일해야 한다고 보지 않고, 상이한 사회에서는 상이한 분배 기준이 있을 수 있음을 인정한다.'),
    (gen_random_uuid()::text, set_id, 80, '왈처', '왈처는 사회의 한 영역의 가치가 다른 영역의 가치를 지배해도 된다고 주장한다.', false, '왈처는 가치의 지배에 동의하지 않는 한편, 가치의 독점에는 동의한다. 독점이란 만약 A 영역에 속한 가치를 많이 보유한 유능한 자가 있다면, A의 영역을 독점해도 상관이 없다는 것이다. 하지만, 왈처는 어느 누구도 X를 소유하였다는 이유만으로 Y의 영역을 침범할 수는 없음을 분명히 한다. 이는 다른 가치의 영역을 침범하는 것이다.'),
    (gen_random_uuid()::text, set_id, 81, '왈처', '왈처는 정의론은 분배의 문제가 아니라 소유의 문제를 다루어야 한다고 주장한다.', false, '왈처는 분배적 정의를 논함에 있어 소유의 문제만을 다루어야 한다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 82, '왈처', '왈처는 가치를 분배할 때에는 사회의 특수성과 차이를 고려해야 한다고 주장한다.', true, '왈처는 상이한 사회적 가치들은 상이한 근거들에 따라 상이한 절차에 맞게 상이한 주체에 의해 분배되어야 한다고 본다. 그렇기 때문에 각 사회의 특수성은 왈처의 입장에서 고려되어야 할 대상인 것이다.'),
    (gen_random_uuid()::text, set_id, 83, '왈처', '왈처는 모든 사회적 가치는 자유 교환의 원칙에 의해 분배되어야 된다고 주장한다.', false, '왈처는 각 사회적 가치의 영역마다 상이한 분배 기준을 갖고 있다고 본다. 이것이 바로 복합 평등의 개념이다. 따라서 모든 사회적 가치는 ~의 기준에 따라 분배되어야 한다라는 문장 자체가 왈처에게는 해당되지 않는다.'),
    (gen_random_uuid()::text, set_id, 84, '왈처', '왈처는 가치의 사회적 의미와 무관한 기본적 재화를 공정하게 분배해야 한다고 주장한다.', false, '왈처는 분배적 정의와 관련되는 모든 가치들이 사회적 가치들이라고 본다. 즉, 왈처는 가치들의 맥락이 사회적 맥락과 무관하게 그 자체로 평가되지는 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 85, '왈처', '왈처는 복합 평등을 실현하기 위해 지배적 가치는 평등하게 공유되어야 한다고 주장한다.', false, '지배적 가치를 공유한다는 것은 가치의 다원성을 고려하지 않는 단순 평등 상태에 불과하다. 이는 각 가치 영역이 존중되지 않기 때문에, 왈처는 이러한 지배적 가치가 존재하는 단순 평등이 아니라 여러 가치의 다원성을 고려하는 복합 평등 체제를 지향해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 86, '왈처', '왈처는 사회적 가치는 그 고유한 의미에 의해 제한되지 않고 사용되어야 한다고 주장한다.', false, '만약 가치의 사용에 제한이 없다면, 각자의 영역에 머무르지 않고, 가치들 간의 전환을 통하여 고유한 영역을 침범하는 결과를 초래할 것이다. 왈처는 이러한 것은 가치의 다원성을 실현시키지 못한다고 보며, 각자의 가치가 고유한 영역에서 사용되어야 함을 주장한다.'),
    (gen_random_uuid()::text, set_id, 87, '왈처', '왈처는 어떠한 분배 영역의 가치도 다른 분배 영역의 가치로 전환되어선 안 된다고 주장한다.', true, '왈처는 어떠한 분배 영역의 가치도 다른 분배 영역의 가치로 전환되면 안 된다고 본다. 왈처가 보기에는 이러한 전환은 단순 평등이며, 단순 평등에서는 서로 다른 영역의 가치들 간의 교환이 일어나며, 이는 상이한 영역들 간의 침해로 이어진다. 따라서 왈처는 각자의 고유한 가치 영역이 존중되는 복합 평등 체제를 주장한다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '칸트', '칸트는 살인자도 인간으로 존중받을 자격이 있다고 주장한다.', true, '칸트는 살인자를 인간으로 존중하기 위해서 사형에 처해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 2, '칸트', '칸트는 형벌은 보편적 도덕 원리에 근거해야 한다고 주장한다.', true, '칸트는 보편적 도덕원리에 근거하여 형벌을 집행해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 3, '칸트', '칸트는 정의의 기초가 되는 원리에 따라 형벌을 가해야 한다고 주장한다.', true, '칸트에게 정의의 기초가 되는 원리란 법이론의 기초 원리를 의미한다. 칸트는 법이론의 기초 원리에 따라 형벌이 집행되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 4, '칸트', '칸트는 동해 보복 원리에 어긋나는 형벌은 정당화될 수 없다고 주장한다.', true, '칸트는 오직 보복법만이 형벌의 질과 양을 결정할 수 있다고 주장하면서 형벌의 동등성의 원리, 즉 동해 보복 원리를 따라야 한다고 본다. 즉, 칸트는 동해 보복 원리에 어긋나는 형벌은 도덕적으로도 법적으로도 정당화될 수 없다.'),
    (gen_random_uuid()::text, set_id, 5, '칸트', '칸트는 사형은 살인범의 자발적 행위에 대한 응보적 형벌이라고 주장한다.', true, '칸트는 형벌을 통해 살인자의 자발적인 행위인 살인 행위라는 범죄에 상응하는 응보를 가해야 한다고 주장한다. 즉, 칸트에 따르면 형벌은 범죄자의 행위에 대한 동등한 응보적 차원에서 부과되어야 하는 것이다.'),
    (gen_random_uuid()::text, set_id, 6, '칸트', '칸트는 범죄 억제력이 있는 형벌도 정당하지 않은 경우가 있다고 주장한다.', true, '칸트는 형벌이 범죄자 자신이나 사회를 위한 다른 선을 위한 수단으로 부과될 수 없다고 주장한다. 칸트의 입장에서 형벌이 이러한 응보법에 부합하지 않는다면 범죄 억제 효과가 있다 하더라도 그 형벌은 정당하지 않다.'),
    (gen_random_uuid()::text, set_id, 7, '칸트', '칸트는 사형은 국가 존립이 아니라 정의 실현을 위해 집행된다고 주장한다.', true, '칸트는 사형이 시민사회를 위해 어떤 다른 선(범죄 예방, 국가 존립 등)을 촉진하기 위한 수단으로써 집행될 수 없으며 공적 정의의 실현을 위해 집행되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 8, '칸트', '칸트는 사형 선고를 통해 살인범의 생득적 인격성이 박탈된다고 주장한다.', false, '칸트는 사형 선고를 통해 살인범의 시민적 인격성이 박탈되더라도 생득적 인격성은 박탈되지 않으며, 박탈되지 않고 보존되는 생득적 인격성이 그를 물권의 대상이 되는 것으로부터 보호해 준다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 9, '칸트', '칸트는 범죄자를 처벌하는 것은 그가 처벌을 의욕했기 때문이라고 주장한다.', false, '칸트에 따르면 범죄자에 대한 처벌, 형벌을 의욕하고 의지하는 것은 예지체 인격이 담당하는 것이기 때문에, 이 현상체 인격(=범죄자)은, 애초에 형벌에 대한 의지, 의욕을 할 수 없고, 그러할 자격이 없다.'),
    (gen_random_uuid()::text, set_id, 10, '칸트', '칸트는 형벌은 오직 범죄자의 인격 교화가 목적인 정언 명령이라고 주장한다.', false, '칸트에 따르면 형벌은 오직 범죄자가 범죄를 저질렀기 때문에 행해지는 것이며, 형벌의 법칙은 하나의 정언 명령이다. 칸트에게 형벌은 공적 정의를 실현하는 수단일 수는 있으나, 그 외의 범죄 예방과 같은 사회적 선, 사회적 이익, 범죄자의 교화 등을 위한 수단이 될 수는 없다.'),
    (gen_random_uuid()::text, set_id, 11, '칸트', '칸트는 형벌은 범죄자에게 고통을 유발하더라도 정당화 가능하다고 주장한다.', true, '칸트는 형벌을 받을 행위를 의욕한 범죄자에게 고통을 유발하는 형벌을 부과하는 것이 정당하다고 본다.'),
    (gen_random_uuid()::text, set_id, 12, '칸트', '칸트는 형벌의 경중은 오직 범죄의 동기에 비례하여 결정해야 한다고 주장한다.', false, '칸트는 형벌의 경중이 범죄와의 동등한 비례 관계에 따라 결정되어야 한다고 본다. 즉, 오직 범죄의 동기에 의해서가 아니라 범죄 행위의 경중에 비례해서 형벌의 경중이 결정되어야 한다고 본 것이다.'),
    (gen_random_uuid()::text, set_id, 13, '칸트', '칸트는 사형은 살인범을 목적 그 자체로 존중하는 정당한 형벌이라고 주장한다.', true, '칸트는 비록 사형을 집행하더라도 인간을 다른 목적을 위한 수단으로 취급하지 않고 인간 존엄성을 고려하여 목적 그 자체로 존중해야한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 14, '칸트', '칸트는 형벌은 사적인 보복이 아니라 공적인 정의를 실현해야 한다고 주장한다.', true, '칸트는 형벌이 사적 보복이 아니라 공적 정의를 실현하기 위한 수단이라고 본다.'),
    (gen_random_uuid()::text, set_id, 15, '칸트', '칸트는 인도적 동정심에서 사형의 부당성을 주장하는 것은 그릇된 것이라고 주장한다.', true, '칸트에게 있어 동정심이란 경향성이다. 따라서 칸트는 인도적 동정심에서 사형의 부당성을 주장하는 것은 그르다고 본다.'),
    (gen_random_uuid()::text, set_id, 16, '칸트', '칸트는 사형을 오직 본보기로 집행하는 것은 부당하다고 주장한다.', true, '칸트는 형벌이 범죄자가 범죄를 저질렀다는 이유 때문이 아닌 다른 목적을 위해 부과되어서는 안 된다고 본다. 따라서 이 선지에 동의할 것이다.'),
    (gen_random_uuid()::text, set_id, 17, '칸트', '칸트는 살인자에게 사형 이외의 형벌이 부과될 수 있다고 주장한다.', true, '칸트는 살인자에게 사형 이외의 형벌이 부과되는 경우가 존재한다고 본다. 칸트는 모든 살인자가 반드시 사형에 처해져야 한다고 보지만, 이러한 엄격한 원칙으로서의 당위와 별개로, 국가를 실질적으로 통치하는 과정에서 주권자가 사면권을 포함한 재량권을 행사할 수 있는 잠재적 필요성을 예외적으로 인정한 것이다.'),
    (gen_random_uuid()::text, set_id, 18, '칸트', '칸트는 살인범은 더 이상 도덕적 인격으로 간주될 수 없다고 주장한다.', false, '칸트는 인격성을 생득적(도덕적) 인격성과 시민적 인격성으로 구분한다. 생득적 인격성은 인간이 본래 갖고 있는, 목적으로서 대우받아야 할 인격성으로서 칸트는 살인범이 시민적 인격성을 상실할지라도 생득적 인격성은 상실되지 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 19, '칸트', '칸트는 살인자에 대한 사형은 사회 계약에 포함될 수 있다고 주장한다.', true, '칸트는 사회 계약에 근거하여 자신의 형벌론을 전개하며, 사회 계약에 사형이 포함될 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 20, '칸트', '칸트는 형벌의 목적은 범죄자에게 고통을 주는 데 있지 않다고 주장한다.', true, '칸트는 형벌의 목적이 범죄 행위를 저지른 범죄자에 대한 응보적 정의를 달성하는 것에 있다고 본다. 즉 칸트는 형벌의 목적이 범죄자에게 고통을 주는 데 있지 않다고 본다.'),
    (gen_random_uuid()::text, set_id, 21, '칸트', '칸트는 범죄 사실 자체를 근거로 형벌을 부과해서는 안 된다고 주장한다.', false, '칸트는 응보주의의 입장에서 범죄 사실 자체를 근거로 형벌을 부과해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 22, '칸트', '칸트는 살인자에 대한 사형은 그의 인격성을 존중하는 것이라고 주장한다.', true, '칸트는 살인자에 대한 사형이 그의 생득적 인격성을 존중하는 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 23, '칸트', '칸트는 형벌은 사회적 선을 촉진하기 위한 수단으로 가해질 수 없다고 주장한다.', true, '칸트는 형벌은 결코 범죄자 자신이나 시민 사회를 위해서, 어떤 다른 선을 촉진하기 위한 한낱 수단으로 가해질 수는 없다라고 주장한다. 칸트는 형벌은 오직 공적 정의에 따라 응보적 정의를 실현하기 위한 수단이라고 본다.'),
    (gen_random_uuid()::text, set_id, 24, '칸트', '칸트는 살인범은 살인을 의욕한 자로서 어떠한 인격성도 지닐 수 없다고 주장한다.', false, '칸트는 시민적 인격성이 살인으로 인해 상실될 수는 있지만, 생득적 인격성은 살인범에게 박탈되지 않는다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 25, '베카리아', '베카리아는 처벌의 목적은 교화가 아니라 응보에 있다고 주장한다.', false, '베카리아는 처벌의 목적을 범죄 예방과 교화에서 찾는다. 응보적 관점에서 형벌의 정당성을 주장하는 사상가는 칸트와 루소이다.'),
    (gen_random_uuid()::text, set_id, 26, '베카리아', '베카리아는 형벌은 최대 다수의 최대 행복을 지향해야 한다고 주장한다.', true, '베카리아의 형벌론은 공리주의적 성격을 지니고 있다. 즉, 형벌은 최대 다수의 최대 행복을 지향해야 하는 것이다.'),
    (gen_random_uuid()::text, set_id, 27, '베카리아', '베카리아는 사형은 시민의 범죄 의욕을 전혀 억제할 수 없다고 주장한다.', false, '베카리아는 사형의 범죄 억제력이 아예 없다는 것이 아니라, 사형은 범죄 억제력의 효과 면에서 일시적인 것이고, 종신 노역형의 범죄 억제력 효과가 가장 강력하다고 본다.'),
    (gen_random_uuid()::text, set_id, 28, '베카리아', '베카리아는 형벌이 주는 공포는 강도보다 지속성에서 나온다고 주장한다.', true, '베카리아는 일반적으로 종신 노역형이 사형보다 시민들이 범죄를 저지르지 못하도록 막는 효과가 더 높다고 본다.'),
    (gen_random_uuid()::text, set_id, 29, '베카리아', '베카리아는 형벌은 반드시 법률을 통해서만 집행되어야 한다고 주장한다.', true, '베카리아는 근대 형법에 죄형 법정주의를 도입한 근대 형법 사상가이다. 죄형 법정주의란, 형법이 법률로 엄밀히 규정되어야 하며, 형벌은 반드시 법률을 통해서만 집행되어야 한다는 근대 형법 사상이다.'),
    (gen_random_uuid()::text, set_id, 30, '베카리아', '베카리아는 범죄자 처벌보다 범죄의 예방이 형벌의 목적이라고 주장한다.', true, '베카리아는 범죄자 처벌보다 범죄 예방이 형벌의 목적이라고 본다.'),
    (gen_random_uuid()::text, set_id, 31, '베카리아', '베카리아는 동해 보복 원리에 어긋나는 형벌도 정당화될 수 있다고 주장한다.', true, '베카리아에 따르면, 형벌의 목적은 동해 보복이 아니라 다른 사람이 같은 범죄를 저지르지 못하도록 하는 범죄 예방에 있으며, 형벌은 범죄가 공익에 반하는 정도에 비례해야 한다. 즉, 베카리아는 범죄 예방의 목적을 달성할 수 있다면 형벌이 반드시 동해 보복 원리를 따라야 한다고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 32, '베카리아', '베카리아는 종신 노역형은 범죄자를 목적으로 대우하는 형벌이라고 주장한다.', false, '베카리아는 종신 노역형이 범죄자를 목적으로 대우하는 형벌이라고 보지 않는다. 오히려 종신 노역형을 수행하는 범죄자는 본보기로써 시민들의 범죄를 억제하는 수단으로 취급된다.'),
    (gen_random_uuid()::text, set_id, 33, '베카리아', '베카리아는 과도한 형벌은 효용 원리와 사회 계약 모두에 위배된다고 주장한다.', true, '베카리아에게 있어서 필요 이상의 잔혹한 형벌은 정의에도 반하고, 사회 계약의 본질과도 상반된다. 따라서 베카리아는 형벌은 타인들의 범죄를 억제시키기에 충분한 정도의 강도만을 가져야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 34, '베카리아', '베카리아는 사회 계약에 근거해 모든 종류의 형벌이 집행될 수 있다고 주장한다.', false, '베카리아는 형벌에 대한 권한이 사회 계약으로부터 나오는 것이지만 그렇다고 해서 형벌권이 모든 종류의 형벌을 집행할 수 있는 권력이라고 본 것은 아니다. 베카리아에 따르면, 사형은 부당한 형벌이며 사회 계약에 의해 정당화될 수 없다.'),
    (gen_random_uuid()::text, set_id, 35, '베카리아', '베카리아는 사형의 선고와 집행은 살인자의 동의를 전제하지 않는다고 주장한다.', true, '베카리아는 사회 계약의 당사자들이 자신의 자유 중 최소한의 몫을 모아 법을 만들며, 이 과정에서 자신의 생명에 대한 권리를 양도하지 않는다고 본다. 또한 베카리아에 따르면, 범죄자의 동의는 형벌권의 기초가 되며, 그들은 자신이 사형을 당할 수 있다는 것에 동의하지 않는다.'),
    (gen_random_uuid()::text, set_id, 36, '베카리아', '베카리아는 범죄에 상응하는 형벌의 부과는 사회 계약에 근거해야 한다고 주장한다.', true, '베카리아는 범죄와 형벌 간 비례성의 원칙을 주장하면서, 범죄에 상응하는 형벌이 사회 계약에 의해 정당화된다고 본다. 이는 형벌을 잔혹하게 시행하거나, 과도하게 집행하면 안 된다는 주장과도 연관된다.'),
    (gen_random_uuid()::text, set_id, 37, '베카리아', '베카리아는 형벌의 경중은 오직 범죄의 동기에 비례하여 결정해야 한다고 주장한다.', false, '베카리아는 범죄의 유일 타당한 척도로 사회에 끼친 해악을 제시하며 결과론적 접근을 보여준다. 베카리아는 개인의 의사를 범죄의 진정한 척도라고 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 38, '베카리아', '베카리아는 형벌이 방지할 해악이 형벌의 해악보다 크다면 형벌은 정당하다고 주장한다.', true, '베카리아와 벤담과 같은 공리주의자들은 형벌은 고통을 가하는 것이므로 공리를 하락시키지만, 만약 형벌을 통해서 더 큰 공리의 하락을 막을 수 있다면 그러한 형벌은 적절하다고 본다.'),
    (gen_random_uuid()::text, set_id, 39, '베카리아', '베카리아는 종신 노역형은 비공개로 집행하는 것이 범죄 예방에 효과적이라고 주장한다.', false, '베카리아는 범죄자가 형벌 받는 모습을 공개적으로 보게 하는 것이 일반인들의 범죄 억제에 효과적이라고 보았다. 이는 범죄자의 행위뿐만이 아니라 시민의 행위까지 통제하는 효과라고 할 수 있다.'),
    (gen_random_uuid()::text, set_id, 40, '베카리아', '베카리아는 사형은 사회 계약에 의해 정당화될 수 있다고 주장한다.', false, '베카리아는 인간이 사회 계약을 맺을 때 모든 가치 중 최대한의 것인 생명과 관련된 권리를 양도하지 않을 것이라고 보기 때문에, 베카리아의 사회 계약에는 살인자에 대한 사형이 포함되지 않는다.'),
    (gen_random_uuid()::text, set_id, 41, '베카리아', '베카리아는 사형을 오직 본보기로 집행하는 것은 부당하다고 주장한다.', true, '베카리아는 본보기를 위한 형벌 집행에 찬성하지만, 종신 노역형보다 범죄 예방효과가 떨어지면서 과도하게 잔혹한 형벌인 사형에는 반대하기 때문에 이 선지에 동의할 것이다.'),
    (gen_random_uuid()::text, set_id, 42, '베카리아', '베카리아는 사회 계약의 목적에 반하는 형벌은 정당성이 없다고 주장한다.', true, '베카리아는 형벌이 사회 계약에 근거하여 부과되어야 한다고 주장하며, 사회 계약의 목적에 반하는 형벌은 정당성이 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 43, '베카리아', '베카리아는 사형은 강렬한 인상을 줄 수 없는 비효과적 형벌이라고 주장한다.', false, '베카리아에 따르면 살인자에게 부과하는 사형은 강렬한 인상을 줄 수 있지만 종신 노역형에 비해 범죄 예방의 목적을 달성하는 데 효과가 떨어지는 형벌이다.'),
    (gen_random_uuid()::text, set_id, 44, '베카리아', '베카리아는 형벌은 모든 고통을 한순간에 집중시켜야만 효과적이라고 주장한다.', false, '베카리아는 모든 고통을 한순간에 집중시키는 사형과 같은 형벌은 시민들에게 한순간의 강렬한 인상을 주는 것에 불과할 뿐 범죄 억제에 큰 효과가 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 45, '베카리아', '베카리아는 종신 노역형은 범죄자보다 시민들에게 더 큰 공포를 준다고 주장한다.', true, '베카리아에 따르면, 종신 노역형을 부과받은 범죄자의 경우에는 눈앞의 비참한 순간에 사로잡혀 미래를 생각할 여력이 없는 한편, 시민들의 경우 범죄자가 형벌을 받는 불행한 순간 순간의 고통의 합산을 고려하기 때문에 범죄자보다 더 큰 공포를 느낀다.'),
    (gen_random_uuid()::text, set_id, 46, '베카리아', '베카리아는 법은 살인을 금지하므로 법에 의해 살인하는 형벌은 부당하다고 주장한다.', true, '베카리아는 살인을 금지하는 법이 존재함에도 불구하고 살인을 행한 범죄자에 대해 국가가 공공적이라는 명목으로 사형이라는 살인 행위를 자처하는 것이 모순적이라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 47, '베카리아', '베카리아는 사형을 통해 지속적으로 공포 인상을 주어 범죄를 예방해야 한다고 주장한다.', false, '베카리아는 형벌을 통해서 지속적으로 공포의 인상을 줌으로써 범죄를 예방해야 한다고 본다. 그런데 문제는 선지의 주어가 사형이라는 것이기 때문에 이는 베카리아의 입장으로 적절하지 않다.'),
    (gen_random_uuid()::text, set_id, 48, '베카리아', '베카리아는 생명권 양도 여부가 사형제의 정당성을 판단하는 근거가 될 수 있다고 주장한다.', true, '베카리아는 계약의 바탕이 되는 개인의 최소한의 몫에 생명권은 포함될 수 없다는 생명권의 양도 불가능성을 바탕으로 사형제에 대해 반대한다.'),
    (gen_random_uuid()::text, set_id, 49, '베카리아', '베카리아는 형벌을 통해 행위를 통제하고자 하는 대상은 범죄자에 국한되어야 한다고 주장한다.', false, '베카리아는 형벌을 통해 범죄자뿐만 아니라, 일반 시민들이 미래에 범죄를 저지를 수 없도록 행위를 통제하고자 한다.'),
    (gen_random_uuid()::text, set_id, 50, '벤담', '벤담은 범죄 피해자의 보복 의지가 형벌의 근거라고 주장한다.', false, '범죄 피해자의 보복 의지라는 의미는, 공적인 것이 아니라 사적인 범주에 포함된다. 사형제에 주로 등장하는 사상가(벤담, 베카리아, 루소, 칸트)들은 형벌이 모두 공적 정의를 위한 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 51, '벤담', '벤담은 형벌은 범죄 의지를 억제시키는 수단이어야 한다고 주장한다.', true, '벤담은 공리주의의 입장에서, 형벌이 사회의 이익 증진 수단으로 행해져야 한다고 본다. 이러한 사회적 이익에는 일반인의 범죄 의지를 억제시키는 것도 포함된다.'),
    (gen_random_uuid()::text, set_id, 52, '벤담', '벤담은 형벌은 범죄의 사회적 해악에 비례해 부과해야 한다고 주장한다.', true, '벤담은 범죄 행위가 사회의 행복을 저해하는 경향에 비례하여 형벌이 가해져야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 53, '벤담', '벤담은 사형 제도는 범죄의 경중에 비례하는 보복의 수단이라고 주장한다.', false, '벤담이 사형을 옹호하는 경우는 오직 최대 다수의 최대 행복이라는 공리의 원리에 부합할 때이다. 벤담은 살인자에게 응당한 보복을 하기 위해서 사형을 집행해야 한다고 주장하지는 않는다.'),
    (gen_random_uuid()::text, set_id, 54, '벤담', '벤담은 살인죄에 대하여 사형을 대체할 다른 처벌이 존재한다고 주장한다.', true, '벤담은 어떤 살인자가 나라 전체를 중대한 위험에 처하게 하지 않는 경우에는 사형보다는 공리를 증진시킬 수 있는 다른 형벌을 집행해야 한다고 본다. 벤담이 사형제의 완전 폐지를 주장하지는 않으나 기본적으로는 사형에 대해 부정적인 입장을 취한다.'),
    (gen_random_uuid()::text, set_id, 55, '벤담', '벤담은 공동체의 해악을 방지한다면 형벌 그 자체는 악이 아니라고 주장한다.', false, '벤담에게 있어 고통은 악이며, 그러한 고통을 유발하는 처벌도 악이다. 즉, 그 자체가 악인 형벌은 목적 달성에 필요한 정도 이상으로 가해져서는 안 되며, 형벌이 방지할 해악이 형벌 자체의 해악보다 더 커야 그 형벌이 악임에도 정당하다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 56, '벤담', '벤담은 형벌이 방지할 해악이 형벌의 해악보다 크다면 형벌은 정당하다고 주장한다.', true, '벤담과 베카리아와 같은 공리주의적 관점에서만 동의할 주장이다. 공리주의자들은 형벌은 고통을 가하는 것이므로 공리를 하락시키지만, 만약 형벌을 통해서 더 큰 공리의 하락을 막을 수 있다면 그러한 형벌은 적절하다고 본다.'),
    (gen_random_uuid()::text, set_id, 57, '벤담', '벤담은 형벌의 종류와 크기는 사회적 파급 효과를 고려하여 정해야 한다고 주장한다.', true, '벤담은 공리주의적 입장에서 형벌의 목적이 최대 다수의 최대 행복을 증진시키는 것이라고 보며, 이는 형벌이 시행되었을 때 사회적인 파급 효과가 어떠할지 고려하여 형벌의 종류와 크기를 설정해야 한다고 보는 관점에 해당한다.'),
    (gen_random_uuid()::text, set_id, 58, '벤담', '벤담은 형벌로부터 초래되는 해악은 형벌을 부과할 때 고려해야 할 사항이 아니라고 주장한다.', false, '벤담은 형벌을 부과할 때 형벌로부터 초래되는 해악을 고려해야 한다고 본다. 형벌이 제거하는 해악이 형벌이 초래하는 해악보다  커야한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 59, '벤담', '벤담은 범죄자에게 가능한 한 적은 고통을 주는 동시에 범죄 억지력을 갖는 형벌은 허용될 수 있다고 주장한다.', true, '벤담은 처벌이 공리주의적 관점에 따라 범죄를 예방하기 위한 충분한 정도의 강도로 부과되어야 한다고 주장한다. 고통을 적게 주는 것은 그만큼 사회 공리의 감소가 더 적다는 것을 함의한다.'),
    (gen_random_uuid()::text, set_id, 60, '루소', '루소는 형벌은 공적 정의를 실현하기 위한 수단이라고 주장한다.', true, '루소는 형벌이 공적 정의를 실현하기 위한 수단이라고 보며, 형벌을 공적 정의를 실현하기 위한 수단이라고 보는 점은 형벌론에서 등장하는 사상가들 모두의 공통점이다.'),
    (gen_random_uuid()::text, set_id, 61, '루소', '루소는 사형은 사회 계약의 목적 달성을 위한 수단이라고 주장한다.', true, '사형을 사회 계약 목적(국민의 생명과 재산 보호) 달성을 위한 수단으로 보는 것은 루소의 입장에 해당한다.'),
    (gen_random_uuid()::text, set_id, 62, '루소', '루소는 사회 계약의 목적에 반하는 형벌은 정당성이 없다고 주장한다.', true, '루소는 사회 계약론에 의해 자신의 형벌관을 전개하고 정당화하는 사상가이다. 따라서 형벌이 사회 계약에 근거하여 부과되어야 한다고 주장하며, 사회 계약의 목적에 반하는 형벌은 정당성이 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 63, '루소', '루소는 모든 형벌은 공공의 이익을 위해서 집행되어야 한다고 주장한다.', true, '루소는 모든 입법체계의 목적이 전체 인민의 최대 행복이 되어야 한다고 주장한다. 루소는 오직 공공의 이익을 지향하는 일반 의지의 지도 아래에서 시민들은 법에 복종하고 시민적 질서를 지켜 나가야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 64, '루소', '루소는 살인자에게 부과될 수 있는 형벌은 오직 사형뿐이라고 주장한다.', false, '루소는 사람을 죽인 살인자는 국가의 시민이 아니라 국가의 적으로서 사형이나 추방형에 처해져야 한다고 본다. 왜냐하면, 살인자는 자기 보존을 목적으로 한 사회 계약을 스스로 파기한 자이므로 국가의 적으로 간주되기 때문이다.'),
    (gen_random_uuid()::text, set_id, 65, '루소', '루소는 계약자의 생명은 국가로부터 조건부로 보장된다고 주장한다.', true, '루소에 따르면 계약자의 생명은 자연이 베푼 은혜일 뿐만 아니라 국가가 조건부로 준 선물이기도 하다.'),
    (gen_random_uuid()::text, set_id, 66, '루소', '루소는 사형은 살인범의 자발적 행위에 대한 응보적 형벌이라고 주장한다.', true, '루소에 따르면 타인을 희생시켜 자신의 생명을 보존하려는 자는 마찬가지로 필요할 경우 타인을 위해 자신의 생명을 내놓아야 한다.'),
    (gen_random_uuid()::text, set_id, 67, '루소', '루소는 사형은 국가 존립이 아니라 정의 실현을 위해 집행된다고 주장한다.', false, '루소는 사형을 비롯한 형벌이 국가 존립을 위해 집행될 수 있다고 본다. 애당초 루소는 사회 방위론에 근거하여 사형을 지지한 사상가이다.'),
    (gen_random_uuid()::text, set_id, 68, '루소', '루소는 사형은 시민들의 생명을 지키기 위해 실행되는 형벌이라고 주장한다.', true, '루소는 사형이 시민들의 생명을 지키기 위해 시행된다는 사회 방위론적 입장을 취한다. 그는 사회 계약론자로서, 사회 계약의 목적이 구성원의 생명을 보존하는 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 69, '루소', '루소는 형벌은 정의의 기초가 되는 원리에 따라 부과되어야 한다고 주장한다.', true, '루소는 형벌이 정의의 기초가 되는 원리에 따라 부과되어야 한다고 본다. 이러한 입장은 형벌론 파트에서 등장하는 칸트, 루소, 벤담, 베카리아에 모두 해당한다.'),
    (gen_random_uuid()::text, set_id, 70, '루소', '루소는 모든 형벌은 범죄자를 시민의 일원으로서 처벌하는 것이라고 주장한다.', false, '루소는 사회적 권리를 침해한 중범죄자의 경우 그를 시민의 일원이 아니라 국가의 적으로 간주하여 사형에 처하거나 국외로 추방해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 71, '루소', '루소는 범죄에 상응하는 형벌의 부과는 사회 계약에 근거해야 한다고 주장한다.', true, '루소는 사회 계약을 근거로 형벌을 부과해야 한다고 본다. 루소는 살인 범죄에 상응하는 형벌이 사형이나 추방형이라고 볼 것이다.'),
    (gen_random_uuid()::text, set_id, 72, '루소', '루소는 살인범은 자신이 사회 구성원이 아님을 스스로 입증하는 자라고 주장한다.', true, '루소는 누군가가 살인을 저질렀다면 그가 가지고 있던 사회 구성원, 즉 시민이라는 자격을 박탈당하게 된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 73, '루소', '루소는 사회 계약의 목적을 위해 모든 시민이 사형제에 동의해야 한다고 주장한다.', true, '루소는 살인자가 되면 죽을 것이라고 사람들이 스스로 약속하는 것은 곧 다른 살인자에게 희생되지 않기 위해서, 자신의 생명을 보존하기 위해서라고 본다. 즉, 루소는 살인자에게 사형을 부과하는 것을 개인들이 동의한다고 보며, 그러한 계약을 할 때는 오직 자신의 생명을 보장받는 일만을 생각할 따름이라고 본다.'),
    (gen_random_uuid()::text, set_id, 74, '루소', '루소는 법을 위반한 살인범은 자기 보존을 목적으로 한 사회 계약을 파기한 자라고 주장한다.', true, '루소는 사회 계약론자로서, 사람을 죽인 자는 사형에 처하거나 추방형에 처함으로써, 더 이상 해당 국가의 시민이 되지 못하도록 해야 한다고 본다. 왜냐하면, 살인범은 자기 보존을 목적으로 한 사회 계약을 스스로 파기한 자로, 국가의 적으로 간주되기 때문이다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '아리스토텔레스', '아리스토텔레스는 인간은 국가 안에서만 행복한 삶을 살 수 있다고 주장한다.', true, '아리스토텔레스에 따르면 인간은 국가 안에서만 행복한 삶을 살 수 있다. 아리스토텔레스는 개인의 행복과 폴리스 공동체의 행복이 다른 것일 수 없다고 보며, 개인의 행복은 전체 공동체의 행복 위에서 이루어져야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 2, '아리스토텔레스', '아리스토텔레스는 공공의 이익에 입각하여 국가가 운영되어야 한다고 주장한다.', true, '아리스토텔레스는 개인의 유익함이 아니라 공동의 유익함을 위한 정치체제가 유익하다고 주장한다. 즉, 아리스토텔레스는 정치체의 정당성을 공공의 이익 차원에서 논하는데, 정치적 좋음이란 정의이며, 이러한 정의는 곧 공동의 이익이다.'),
    (gen_random_uuid()::text, set_id, 3, '아리스토텔레스', '아리스토텔레스는 국가 권위에 복종할 의무는 자연 발생적이지 않다고 주장한다.', false, '아리스토텔레스는 인간이 정치적 본성을 지닌 존재이므로 자연스럽게 국가가 형성되고 국가에 복종할 정치적 의무 또한 본성에 부합하는 자연스러운 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 4, '아리스토텔레스', '아리스토텔레스는 정치 공동체인 국가에서 인간은 선을 실현할 수 있다고 주장한다.', true, '아리스토텔레스에게 있어서 선=좋음=어떤 존재의 기능이나 역할에서 탁월함=덕이다. 아리스토텔레스에 따르면 국가라는 공동체 안에서 인간은 좋은 삶, 선, 덕을 실현하며 살아갈 수 있다.'),
    (gen_random_uuid()::text, set_id, 5, '아리스토텔레스', '아리스토텔레스는 시민은 자신이 속한 국가에 대해 정치적 의무를 지닌다고 주장한다.', true, '아리스토텔레스에 따르면 시민은 국가 권위를 존중하고 정치적 의무를 져야 한다. 아리스토텔레스의 이상 국가에서는 모든 시민이 번갈아가며 치자와 피치자가 되므로 다 같은 교육을 받아야 하며, 훗날 국정에 참여하기 위해서는 먼저 정부에 복종하는 법부터 배워야 한다.'),
    (gen_random_uuid()::text, set_id, 6, '아리스토텔레스', '아리스토텔레스는 인간은 국가 속에서 훌륭하고 행복한 삶을 영위할 수 있다고 주장한다.', true, '아리스토텔레스는 최상위 공동체인 국가에서 더 좋고 고귀한 선을 성취할 수 있으며, 훌륭하고 행복한 삶을 영위할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 7, '아리스토텔레스', '아리스토텔레스는 국가는 정치적 동물인 인간들의 상호 동의를 통해 발생한다고 주장한다.', false, '아리스토텔레스에 따르면 인간은 본성적으로 국가 공동체를 구성하는 동물이다. 따라서, 이러한 본성에 의해 국가 또한 자연스럽게 형성된다. 즉, 국가는 인위적인 상호 동의를 통해 발생하는 것이 아니라 자연의 산물이다.'),
    (gen_random_uuid()::text, set_id, 8, '아리스토텔레스', '아리스토텔레스는 국가는 인간의 정치적 본성으로 형성되는 자연적 공동체라고 주장한다.', true, '국가를 인간의 정치적 본성으로 형성되는 자연적 공동체로 보는 것은 아리스토텔레스의 주요 입장이다.'),
    (gen_random_uuid()::text, set_id, 9, '아리스토텔레스', '아리스토텔레스는 국가는 자연 상태에서 벗어나려는 인간들의 계약으로 수립된다고 주장한다.', false, '이 선지는 사회 계약론의 입장에 해당하므로 아리스토텔레스의 입장이 아니다. 아리스토텔레스는 국가는 자연의 산물이며 인간 본성에 의해 국가 공동체가 구성된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 10, '홉스', '홉스는 자연 상태의 인간은 이기적 존재가 아니라고 주장한다.', false, '홉스는 인간을 자기 보존의 욕구를 추구하는 이기적 존재로 본다.'),
    (gen_random_uuid()::text, set_id, 11, '홉스', '홉스는 시민은 양도할 수 없는 주권을 보유해야 한다고 주장한다.', false, '홉스는 시민이 아니라 주권자인 군주가 양도할 수 없는 주권을 보유해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 12, '홉스', '홉스는 국가는 신의 계약으로 탄생한 자연적 인격이라고 주장한다.', false, '홉스는 국가가 인위적으로 수립되었다고 보며, 국가는 신의 계약으로 탄생한 인위적 인격이라고 주장한다. 홉스에 따르면 국가와 국가 권력은 그 구성요소인 개인들의 인위적 합의에 의해 정당성을 부여받는다.'),
    (gen_random_uuid()::text, set_id, 13, '홉스', '홉스는 사회 계약의 목적은 개인의 생명권 보장에 있다고 주장한다.', true, '홉스에 따르면 사회 계약의 목적은 개인의 생명권을 보장하는 것에 있다.'),
    (gen_random_uuid()::text, set_id, 14, '홉스', '홉스는 시민은 주권자로서 동등한 자유와 권리를 지닌다고 주장한다.', false, '홉스에 따르면 주권자는 시민이 아니라 통치자이다.'),
    (gen_random_uuid()::text, set_id, 15, '홉스', '홉스는 국가가 부재한 곳에서는 각자의 소유권도 부재한다고 주장한다.', true, '홉스는 국가가 부재한 곳에서는 각자의 소유권도 부재한다고 본다. 홉스에 따르면 자연 상태는 만인의 만인에 대한 투쟁 상태로서, 재산이나 소유의 개념도 존재하지 않는다.'),
    (gen_random_uuid()::text, set_id, 16, '홉스', '홉스는 사회 계약의 주체가 국가의 주권을 갖는 것은 아니라고 주장한다.', true, '홉스는 사회 계약의 주체가 국가의 주권을 갖는 것이 아니라, 사회 계약을 통해 수립되는 주권자(통치자)가 국가의 주권을 갖는다고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '홉스', '홉스는 국민의 자유와 주권자의 절대 권력은 양립할 수 있다고 주장한다.', true, '홉스에 따르면 국민의 자유와 주권자의 절대 권력은 양립할 수 있다. 홉스는 주권자의 절대 권력 아래에서 국민이 생명과 안전을 보장받음으로써 자유를 누릴 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '홉스', '홉스는 국가의 통치자가 사회 계약을 위반하는 것은 가능하다고 주장한다.', false, '홉스는 국가의 통치자가 사회 계약을 위반하는 것이 불가능하다고 본다. 왜냐하면 홉스에 따르면 통치자는 사회 계약의 당사자가 아니기 때문에 계약을 위반할 수 없는 존재이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 19, '홉스', '홉스는 개인은 자연 상태에서의 불의를 피하려고 계약을 맺는다고 주장한다.', false, '홉스에 따르면 자연 상태에서는 정의와 부정의가 존재하지 않는다. 따라서 자연 상태에서 발생하는 분쟁을 불의라고 볼 수 없다. 홉스는 자연 상태의 인간은 자기 보존의 욕구 때문에 계약을 맺는다고 본다.'),
    (gen_random_uuid()::text, set_id, 20, '홉스', '홉스는 입법부가 지닌 권력은 제한될 수 있어도 철회될 수는 없다고 주장한다.', false, '홉스는 입법부라는 용어를 사용하지 않으며, 이는 로크의 입장이다.'),
    (gen_random_uuid()::text, set_id, 21, '홉스', '홉스는 사회 계약 이후에는 개인이 아닌 국가만이 처벌권을 지닌다고 주장한다.', true, '홉스에 따르면 사회 계약 이후에는 개인이 아닌 국가만이 처벌권을 지닌다.'),
    (gen_random_uuid()::text, set_id, 22, '홉스', '홉스는 개인의 권리를 보장하기 위해 국가 권력은 분할되어야 한다고 주장한다.', false, '국가 권력의 분할(권력 분립)은 홉스의 입장이 아니다. 홉스는 절대적이고 분할될 수 없는 주권을 주장한다.'),
    (gen_random_uuid()::text, set_id, 23, '홉스', '홉스는 자연 상태에는 생명과 자유를 빼앗을 수 있는 불의가 존재한다고 주장한다.', false, '홉스에 따르면 자연 상태에서는 정의와 부정의가 존재하지 않으므로, 생명과 자유를 빼앗는 행위가 불의라고 할 수 없다.'),
    (gen_random_uuid()::text, set_id, 24, '홉스', '홉스는 주권자는 평화와 공동 방위를 위해 국민의 힘과 수단을 임의로 사용할 수 있다고 주장한다.', true, '홉스에 따르면 주권자는 평화와 공동 방위를 위해 국민의 힘과 수단을 임의로 사용할 수 있다.'),
    (gen_random_uuid()::text, set_id, 25, '홉스', '홉스는 주권은 양도될 수 없고 분할할 수도 없다고 주장한다.', true, '홉스에 따르면 사회 계약을 통해 확립된 주권자의 주권은 권리의 전면 양도를 통해 확립된 절대적이고 무조건적인 것이기 때문에, 주권자가 주권을 직접 포기하지 않는 한, 그의 주권과 그것에서 비롯되는 권리는 분할되거나 양도될 수 없다.'),
    (gen_random_uuid()::text, set_id, 26, '홉스', '홉스는 자연 상태는 부정의가 난무하는 전쟁 상태라고 주장한다.', false, '홉스에 따르면 자연 상태에서는 정의와 부정의가 존재하지 않는다. 따라서, 전쟁 상태에서 일어나는 개인들 간의 분쟁 또한 부정의한 것이 아니다.'),
    (gen_random_uuid()::text, set_id, 27, '홉스', '홉스는 자연 상태의 모든 인간은 동일한 자연권을 가진다고 주장한다.', true, '홉스는 자연 상태의 모든 인간이 동일한 자연권을 가진다고 본다. 즉, 자연 상태의 인간이 가지는 동일한 자연권은 모두가 동일하게 가지고 있기 때문에 필연적으로 자연 상태의 전쟁을 야기하는 원인이 된다.'),
    (gen_random_uuid()::text, set_id, 28, '홉스', '홉스는 절대 권력은 시민의 소유를 보호해야 할 의무가 있다고 주장한다.', true, '절대 권력, 즉 주권자는 시민의 소유를 보호해야 할 의무가 있다. 홉스에 따르면, 주권자는 개인들이 자연권을 포기한 대가로 상호 계약에 의해 소유권을 확보할 수 있도록 보장해야 하며, 개인들은 주권자에 의해 안정적인 소유권을 보장받을 수 있다.'),
    (gen_random_uuid()::text, set_id, 29, '홉스', '홉스는 자연 상태의 인간은 자유에 대한 평등한 권리가 있다고 주장한다.', true, '홉스는 자연 상태의 인간이 자연권을 가지고 있다고 보는데, 자연권은 모든 사람이 그 자신의 본성, 즉 자신의 생명을 보존하기 위해 자기 뜻대로 힘을 사용할 수 있는 자유이다. 아울러, 이러한 자유는 자연 상태의 인간들 모두가 평등하게 가지고 있는 것이다.'),
    (gen_random_uuid()::text, set_id, 30, '홉스', '홉스는 국가의 권위에 복종해야 할 의무는 계약에 토대를 둔다고 주장한다.', true, '홉스는 국가의 권위에 복종해야 할 의무의 근거를 사회 계약에 둔다.'),
    (gen_random_uuid()::text, set_id, 31, '홉스', '홉스는 사회 계약 이후에 군주와 시민은 자연법을 준수해야 한다고 주장한다.', true, '홉스에 따르면 사회 계약 이후에 군주와 시민은 자연법을 준수해야 한다. 절대적 통치자 또한 자연법을 어길 순 없으며, 통치권자의 의무는 자연법에 의해 부과된다. 또한, 자연법은 모든 백성에게 예외 없이 의무를 부과한다.'),
    (gen_random_uuid()::text, set_id, 32, '홉스', '홉스는 인간 본성으로 인해 자연 상태는 전쟁 상태일 수밖에 없다고 주장한다.', true, '홉스에 따르면 인간 본성에 의해 자연 상태는 전쟁 상태일 수밖에 없다. 인간의 이기적 본성은 자연 상태의 갈등을 심화시키고, 재화의 희소성으로 인해 더욱 투쟁 상태가 이어지기 떄문이다.'),
    (gen_random_uuid()::text, set_id, 33, '홉스', '홉스는 인간은 자연 상태에서 이성의 능력을 발휘하여 계약을 한다고 주장한다.', true, '홉스는 자연 상태의 인간들이 이성을 발휘하는 합리적 존재라고 본다. 홉스에 따르면 이러한 인간의 이성이 찾아낸 계율인 자연법에 따라 개인들은 자신의 생명과 안전을 보장받을 수 있는 사회 계약으로 나아가게 된다.'),
    (gen_random_uuid()::text, set_id, 34, '홉스', '홉스는 절대 군주는 모든 인간의 사회 계약 체결과 이행을 강제한다고 주장한다.', false, '홉스에 따르면 절대 군주는 모든 인간의 사회 계약의 체결과 이행을 강제하는 것은 아니다. 절대 군주는 체결 이후 생겨나는 것이기 때문이다. 그러나 이행은 다르다. 홉스는 사회 계약 이후 생겨나는 공통 권력이 채무의 이행을 강제하도록 한다고 본다. 즉, 절대 군주는 신의 계약의 이행을 강제하는 것이지, 체결을 강제하는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 35, '로크', '로크는 국가의 통치자가 신탁을 위반하는 것은 가능하다고 주장한다.', true, '로크에 따르면 국가의 통치자가 신탁을 위반하는 것은 가능하다. 이에 따라 시민들은 통치자의 신탁 위반을 근거로 저항권을 행사할 수 있다.'),
    (gen_random_uuid()::text, set_id, 36, '로크', '로크는 자연 상태의 모든 인간은 동일한 자연권을 가진다고 주장한다.', true, '로크는 모든 인간이 동일한 자연권을 가진다고 본다. 자연 상태의 인간은 자신의 생명과 자유에 대한 자연권뿐만 아니라, 정당한 노동을 통해 획득한 재산에 대해 침해받지 않는 자연권을 가지고 있는데, 이는 자연 상태의 모든 인간이 누리는 자연권이다.'),
    (gen_random_uuid()::text, set_id, 37, '로크', '로크는 국가의 통치자에게는 단지 신탁된 권력만 주어진다고 주장한다.', true, '로크에게 있어 국가의 통치자에게는 단지 신탁된 권력만 주어진다. 이때 정치 권력은 시민들의 복지와 재산의 보전을 위해 사용되어야 한다는 명시적이거나 묵시적인 신탁과 더불어 사회가 그 자신 위에 세운 통치자들에게 넘겨준 권력이다.'),
    (gen_random_uuid()::text, set_id, 38, '로크', '로크는 자연 상태의 인간은 자유에 대한 평등한 권리가 있다고 주장한다.', true, '로크가 정의하는 자연 상태는 개인들이 자연적 평등을 누리는 상태로서, 권력과 권리에 있어서 동등함을 누린다. 이들은 권력과 권리에 있어서 동등하므로 그들 간에는 어떠한 복종 관계도 상정될 수 없다.'),
    (gen_random_uuid()::text, set_id, 39, '로크', '로크는 국가에 양도하지 않은 시민의 권리는 보장될 수 없다고 주장한다.', false, '로크는 교육과정상 개인들이 자연권을 일부 양도하여 국가를 수립한다고 보며, 계약에 의해서 양도하지 않았던 일부 자연권도 보장받을 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 40, '로크', '로크는 시민은 자신이 속한 국가에 대해 정치적 의무를 지닌다고 주장한다.', true, '로크는 명시적 또는 묵시적 동의에 따라서 국가에 복종해야 할 정치적 의무가 발생한다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '로크', '로크는 국가는 자국민을 침해한 외부인들을 처벌할 권력을 지닌다고 주장한다.', true, '로크에 따르면 국가는 국가 외부인이 자국민을 침해한다면 그에 대해 처벌할 수 있는 권력을 가진다.'),
    (gen_random_uuid()::text, set_id, 42, '로크', '로크는 자연 상태의 인간은 자연법을 이해할 수 있는 능력이 없다고 주장한다.', false, '로크는 자연 상태의 인간에게 자연법을 이해할 수 있는 능력이 있다고 본다. 자연법은 이성적 피조물 누구에게나 명료하고도 인식 가능한 것이다.'),
    (gen_random_uuid()::text, set_id, 43, '로크', '로크는 국가는 가족 공동체 의식이 전제된 정치적 공동체여야 한다고 주장한다.', false, '로크는 국가를 가족 공동체 의식이 전제된 공동체라고 보지 않으며, 오히려 자신의 재산을 보호하고 다른 사람들과의 상호 간에 안전한 삶을 영위하기 위해서, 동의 또는 합의를 통해서 결성된 공동체라고 주장한다.'),
    (gen_random_uuid()::text, set_id, 44, '로크', '로크는 국가는 시민 모두에게 동등한 자유와 권리를 보장해야 한다고 주장한다.', true, '국가는 시민 모두에게 동등한 자유와 권리를 보장해야 한다.'),
    (gen_random_uuid()::text, set_id, 45, '로크', '로크는 국가는 인간의 정치적 본성으로 형성되는 자연적 공동체라고 주장한다.', false, '로크가 아니라 아리스토텔레스의 입장이다.'),
    (gen_random_uuid()::text, set_id, 46, '로크', '로크는 국가는 개인의 기본권 보장을 목적으로 계약에 의해 수립된다고 주장한다.', true, '로크는 정치질서와 국가권력의 정당성은 개인들의 자유로운 동의에 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 47, '로크', '로크는 시민은 주권자로서 동등한 자유와 권리를 지닌다고 주장한다.', true, '로크가 입장으로 적절하다.'),
    (gen_random_uuid()::text, set_id, 48, '로크', '로크는 정부에 신탁한 권력은 시민에 의해서 철회될 수 있다고 주장한다.', true, '로크는 정부가 신탁에 반해서 행동한다면, 그러한 정부를 폐지하거나 변경할 수 있는 권력이 시민에게 있다고 본다. 그러므로 로크는 국가가 시민들의 재산권을 침해한다면 시민들은 신탁을 철회하고 저항권에 따라서 정부를 해체하거나 변경할 수 있다.'),
    (gen_random_uuid()::text, set_id, 49, '로크', '로크는 입법부를 폐지할 수 있는 최고의 권력은 시민에게 있다고 주장한다.', true, '로크는 입법부를 폐지할 수 있는 최고의 권력에 대해 논하며, 공동체가 항상 이에 대해 최고의 권력을 가지고 있다고 말한다. 또한, 이러한 최고 권력은 정부가 해체되어야 비로소 발생하는 권력이다.'),
    (gen_random_uuid()::text, set_id, 50, '로크', '로크는 국가의 권위에 복종해야 할 의무는 계약에 토대를 둔다고 주장한다.', true, '로크에게 국가의 권위에 복종해야 할 의무는 자유롭고 평등한 개인들이 그들의 재산을 안정적이고 확실하게 보존하기 위해 맺는 계약에 근거한다.'),
    (gen_random_uuid()::text, set_id, 51, '로크', '로크는 공권력이 형성된 이후에 자연권 보호는 개인만의 책임이라고 주장한다.', false, '개인들은 정부에 의한 자연권 보호를 위해 계약을 맺어 정치사회를 형성하였으므로 개인들만의 책임이라고 할 수 없다. 오히려 국가가 개인들이 자연권을 안정적으로 향유할 수 있도록 보호해 주어야 한다.'),
    (gen_random_uuid()::text, set_id, 52, '로크', '로크는 인간은 자연 상태에서 이성의 능력을 발휘하여 계약을 한다고 주장한다.', true, '로크는 인간을 자유의 주체이자 이성의 주체로 보며, 인간은 이성을 통해 자연법을 준수하고, 사회 계약을 바탕으로 국가가 규정하는 법률의 구속 아래에 들어가는 것에 동의한다.'),
    (gen_random_uuid()::text, set_id, 53, '로크', '로크는 정부에 의한 시민의 재산권 침해는 정부 해체의 근거가 된다고 주장한다.', true, '로크는 정부가 신탁에 반해서 행동한다면, 그러한 정부를 폐지하거나 변경할 수 있는 권력이 시민에게 있다고 본다. 그러므로 로크는 국가가 시민들의 재산권을 침해한다면 시민들은 신탁을 철회하고 저항권에 따라서 정부를 해체하거나 변경할 수 있다.'),
    (gen_random_uuid()::text, set_id, 54, '로크', '로크는 자연 상태는 어떠한 불평등도 없는 대체로 평화로운 상태라고 주장한다.', false, '자연 상태의 평등은 자연 상태에 어떠한 불평등이 없다고 말하는 것이 아니라, 자연 상태의 인간에게 있는 모든 권력과 사법권이 상호적이며 평등하게 이러한 권력을 가지고 있다는 의미에서 평등이다. 이처럼, 로크가 말하는 평등은 인간의 삶의 모든 측면에서의 평등을 의미하는 것이 아니라, 사법권과 지배권 상의 평등, 이를테면 법적 혹은 정치적 평등에 한정된다.'),
    (gen_random_uuid()::text, set_id, 55, '로크', '로크는 자연 상태에서 분쟁은 공통된 자연법의 부재로 인해 발생한다고 주장한다.', false, '자연 상태의 분쟁은 공통된 자연법의 부재로 인한 것이 아니라, 공통된 법률의 부재에 의한 것이다. 공통된 자연법은 자연 상태에 존재한다.'),
    (gen_random_uuid()::text, set_id, 56, '로크', '로크는 국가는 공통된 법률에 따라 시민들 간의 분쟁을 조정해야 한다고 주장한다.', true, '로크에 따르면 국가 상태에서 옳고 그름을 판별하는 것은 각자가 지닌 이성이 아니라, 옳고 그름을 판별하는 기준이자 사람들 사이의 분쟁을 해결하는 공통의 척도로서, 공통의 동의를 통해 인정된 법률이다.'),
    (gen_random_uuid()::text, set_id, 57, '루소(사회계약)', '루소는 주권은 양도될 수 없고 분할할 수도 없다고 주장한다.', true, '루소에게 주권은 일반 의지의 행사일 뿐이므로 절대로 양도할 수 없으며 분할될 수 없는 것이다. 또한, 집합적 존재에 불과한 주권자는 오직 자기 자신에 의해서만 대표될 수 있으므로, 다른 대표자를 상정해 주권을 행사할 수는 없다.'),
    (gen_random_uuid()::text, set_id, 58, '루소(사회계약)', '루소는 자연 상태에서 자유와 권리를 지닐 수 없다고 주장한다.', false, '루소는 자연 상태에서도 개인들이 자유와 권리를 지닐 수 있다고 본다. 이렇게 자연 상태에서 개인은 자연적 자유를 갖고 있으며 이와 더불어 생명권, 물건에 대한 선취권을 갖고 있다.'),
    (gen_random_uuid()::text, set_id, 59, '루소(사회계약)', '루소는 계약 당사자에게 법을 제정하는 입법권이 있다고 주장한다.', true, '루소는 계약 당사자에게 법을 제정하는 입법권이 있다고 주장한다. 루소는 국가가 형성되는 기반인 사회 계약의 주체는 모든 성원들이라고 보며, 계약 당사자인 국민들 모두가 주권의 담당자인 주권자라고 주장한다. 루소에 따르면 이러한 주권자만이 입법권을 가진다.'),
    (gen_random_uuid()::text, set_id, 60, '루소(사회계약)', '루소는 공공의 이익에 입각하여 국가가 운영되어야 한다고 주장한다.', true, '루소에 따르면 일정한 영토 내에 거주하고 있는 모든 성원들이 공동의 이익을 추구하는 일반 의지에 따르기로 하는 사회 계약으로 형성되는 정치체가 곧 국가이다. 이러한 국가는 일반 의지에 근거하여, 즉 공공의 이익에 입각하여 운영되어야 한다.'),
    (gen_random_uuid()::text, set_id, 61, '루소(사회계약)', '루소는 법에 대한 복종이 곧 자기 자신에 대한 복종이라고 주장한다.', true, '루소에 따르면 일반 의지에 복종하는 것은 결국 자기 자신의 의지를 따르는 것이며, 일반 의지에 복종하는 것은 예속이 아니라 자유를 실현하는 것이다. 이에 따라 개인들은 참된 사회적 자유를 누릴 수 있다.'),
    (gen_random_uuid()::text, set_id, 62, '루소(사회계약)', '루소는 자연 상태에서 인간은 평화로운 삶을 누릴 수 있다고 주장한다.', true, '루소에 따르면 최초의 자연 상태는 자유롭고 평화로운 상태이다. 그러나, 사유 재산 등의 발생으로 인해 사회적 경제적 불평등과 같은 문제가 생겨난다. 즉, 사적 소유의 출현을 통해 평등했던 자연 상태가 사회 상태로 이행하게 되며, 불평등과 예속의 불행한 상태에 처하게 된다.'),
    (gen_random_uuid()::text, set_id, 63, '루소(사회계약)', '루소는 국가는 계약 주체의 의지가 반영되어 성립된 것이라고 주장한다.', true, '루소에게 사회 계약은 구성원들의 힘과 의지를 하나로 결합하여 전체의 공통된 힘으로 만듦으로써, 이렇게 결합된 사회체에 정당한 권력과 권위를 부여하는 것이다.'),
    (gen_random_uuid()::text, set_id, 64, '루소(사회계약)', '루소는 개인의 자기 보존 욕구가 계약 체결에 영향을 미친다고 주장한다.', true, '루소는 개인의 자기 보존 욕구가 사회 계약 체결에 영향을 미친다고 본다. 루소에 따르면 사회 계약의 목적은 개인의 안전과 재산을 보존하는 것이다.'),
    (gen_random_uuid()::text, set_id, 65, '루소(사회계약)', '루소는 사유 재산제가 성립되면서 경제적 불평등이 해소된다고 주장한다.', false, '루소에 따르면 최초의 자연 상태는 자유롭고 평화로운 상태이다. 그러나 사유 재산 등의 발생으로 인해 사회적 경제적 불평등과 같은 문제가 생겨난다. 즉, 사적 소유의 출현을 통해 평등했던 자연 상태가 사회 상태로 이행하게 되며, 불평등과 예속의 불행한 상태에 처하게 된다.'),
    (gen_random_uuid()::text, set_id, 66, '루소(사회계약)', '루소는 국가의 주권은 사회 계약에 참여한 주체에 귀속된다고 주장한다.', true, '루소는 계약 당사자에게 법을 제정하는 입법권이 있다고 주장한다. 루소는 국가가 형성되는 기반인 사회 계약의 주체는 모든 성원들이라고 보며, 계약 당사자인 국민들 모두가 주권의 담당자인 주권자라고 주장한다. 루소에 따르면 이러한 주권자만이 입법권을 가진다.'),
    (gen_random_uuid()::text, set_id, 67, '루소(사회계약)', '루소는 자연 상태는 평화롭다는 점에서 사회 상태와 구분된다고 주장한다.', true, '루소에 따르면 최초의 자연 상태는 자유롭고 평화로운 상태이다. 그러나 사유 재산 등의 발생으로 인해 사회 상태로 이행하게 되며, 불평등과 예속의 불행한 상태에 처하게 된다. 따라서 자연 상태는 평화롭다는 점에서 사회 상태와 구분된다.'),
    (gen_random_uuid()::text, set_id, 68, '루소(사회계약)', '루소는 국민의 자신이 선택한 대표자를 통해 주권을 행사해야 한다고 주장한다.', false, '루소에게 주권은 일반 의지의 행사일 뿐이므로 절대로 양도할 수 없으며 분할될 수 없는 것이다. 또한, 집합적 존재에 불과한 주권자는 오직 자기 자신에 의해서만 대표될 수 있으므로, 다른 대표자를 상정해 주권을 행사할 수는 없다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '소로', '소로는 양심에 어긋나는 모든 법에 불복종해야 한다고 주장한다.', true, '소로는 인간으로서 양심을 우선하는 것이 국민으로서 법을 존경하는 것보다 중요하다고 보았으며, 양심에 따라 부정의한 모든 법에 대해 적극적으로 불복종할 것을 주장하였다.'),
    (gen_random_uuid()::text, set_id, 2, '소로', '소로는 시민 불복종은 위법 행위이지만 하나의 권리라고 주장한다.', true, '소로는 시민 불복종이 위법 행위이지만 하나의 권리임을 주장한다. 여담으로 이 진술은 롤스와 싱어에게도 해당되는 진술이다.'),
    (gen_random_uuid()::text, set_id, 3, '소로', '소로는 공동체의 정의감이 불복종 정당화의 최종 근거라고 주장한다.', false, '소로가 아니라 롤스의 입장에 적합한 선지이며, 오히려 소로는 공동체의 정의감보다 개인의 양심을 불복종 정당화의 최종 근거로 본다.'),
    (gen_random_uuid()::text, set_id, 4, '소로', '소로는 시민 불복종은 정의의 실현을 위한 합법적 행위라고 주장한다.', false, '소로는 시민 불복종을 정의의 실현을 위한 정치적 행위로 보지만, 법을 위반하는 행위이므로 위법 행위로 본다.'),
    (gen_random_uuid()::text, set_id, 5, '소로', '소로는 시민 불복종은 공권력에 의한 처벌을 거부하는 수단이라고 주장한다.', false, '소로는 시민 불복종이 부정의한 법에 저항하는 수단이라고 보았지, 처벌을 거부하는 수단이라고 보지는 않았다.'),
    (gen_random_uuid()::text, set_id, 6, '소로', '소로는 법보다 정의에 대한 존경심을 함양하는 것이 바람직하다고 주장한다.', true, '소로는 법보다 정의에 대한 존경심을 함양할 것을 강조하며, 개인의 양심을 시민 불복종의 근거로 제시했다.'),
    (gen_random_uuid()::text, set_id, 7, '소로', '소로는 개인은 법에 우선하여 양심과 정의에 따라 행동해야 한다고 주장한다.', true, '소로는 모든 법이 항상 정의로운 것은 아니라고 보았으며, 부정의한 법에 대해서는 법을 존경하는 것보다 개인의 양심, 정의를 근거로 부정의한 법에 즉각적으로 저항해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 8, '소로', '소로는 시민 불복종은 신중하고 양심적인 신념의 표현이어야 한다고 주장한다.', true, '소로에 따르면, 시민 불복종은 신중해야 하며, 양심적인 행위여야 한다.'),
    (gen_random_uuid()::text, set_id, 9, '소로', '소로는 시민 불복종은 개인적 양심과 사회적 승인에 근거해야 한다고 주장한다.', false, '소로는 시민 불복종 시행에 있어 개인의 양심이 사회적 승인보다 우선한다고 주장한다. 소로는 사회적 승인이 때로는 부도덕한 행위를 정당화할 수 있으므로 도덕적 판단의 기준이 될 수 없다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 10, '소로', '소로는 시민 불복종은 다수 국민이 공유하는 정의관에 근거해야 한다고 주장한다.', false, '소로에 따르면 시민 불복종은 다수 국민이 공유한 정의관에 근거할 필요가 없다. 시민 불복종이 반드시 다수의 정의감에 근거해야 한다고 본 사상가는 롤스이다. 소로는 개인의 양심에 어긋나는 법에 대한 즉각적인 시민 불복종을 옹호한다.'),
    (gen_random_uuid()::text, set_id, 11, '소로', '소로는 법률과 양심을 시민 불복종의 정당성 판별 근거로 삼아야 한다고 주장한다.', false, '소로는 양심을 시민 불복종의 정당성 판별 근거로 삼아야 한다고 보았지만, 법률을 시민 불복종의 정당성 판별 근거로 삼아야 한다고 보지는 않았다.'),
    (gen_random_uuid()::text, set_id, 12, '소로', '소로는 정의로운 정부에서는 소수의 권력자가 다수의 시민을 지배한다고 주장한다.', false, '소로는 소수의 권력자가 다수의 시민을 지배하는 정부를 부정의하다고 본다. 소로는 정부가 시민의 의견을 반영하지 못하고 부정의한 법과 정책을 제정 및 집행할 때, 이러한 부정의에 맞서 시민 불복종을 전개해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 13, '소로', '소로는 다수 의사를 반영한 법은 시민 불복종 대상에서 제외되어야 한다고 주장한다.', false, '소로는 다수의 의견이 항상 정의로운 것이 아니며, 다수의 의견을 반영한 법이라도 정의롭지 않다면 시민 불복종의 대상이 될 수 있다고 보았다.'),
    (gen_random_uuid()::text, set_id, 14, '소로', '소로는 양심에서 비롯된 시민불복종도 실패 가능성이 크면 정당성을 상실할 수 있다고 주장한다.', false, '소로는 개인의 양심에서 비롯된 시민 불복종의 정당성이 그 행위의 성공 여부에 달려 있지 않다고 본다. 소로는 이러한 저항이 사회의 변화를 일으킬 가능성이 낮더라도, 도덕적으로 올바른 행동이라면 정당성이 유지된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 15, '롤스', '롤스는 시민 불복종은 양심적 개인들의 종교적 신념에 근거할 수 있다고 주장한다.', false, '롤스는 개인의 도덕, 특정 집단의 이익, 종교적 가르침 등은 시민 불복종의 정당한 근거가 될 수 없다고 본다. 왜냐하면 이는 공동체 내에서 보편화될 수 있는 것들이 아니기 때문이다.'),
    (gen_random_uuid()::text, set_id, 16, '롤스', '롤스는 시민 불복종은 헌법의 근거가 되는 원칙에 의해 지도되어야 한다고 주장한다.', true, '롤스에 따르면, 사회의 기본 구조를 규제하는 정의의 원칙은 헌법의 근간이 된다.'),
    (gen_random_uuid()::text, set_id, 17, '롤스', '롤스는 정의로운 시민에게 부정한 법을 준수할 의무는 성립할 수 없다고 주장한다.', false, '롤스에 따르면 정의의 자연적 의무, 공정성의 책무는 정의의 원칙에 따라서, 거의 정의로운 사회의 정치 체계의 불완전한 결과들을 존중하라고 우리를 제약하고 있다. 즉, 거의 정의로운 사회에서는 보통의 정의로운 법뿐만 아니라 어느 정도 부정의한 법에도 따라야 할 의무가 있다.'),
    (gen_random_uuid()::text, set_id, 18, '롤스', '롤스는 시민 불복종은 합법적인 정치적 반대와 동시에 이루어져야만 한다고 주장한다.', false, '롤스는 시민 불복종은 위법 행위이고, 그러한 위법 행위를 하기 전에, 합법적인 정치적 반대를 통하여, 부정의한 법의 개정을 충분히 시도해 보아야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 19, '롤스', '롤스는 헌법에 규정된 방식으로 제정된 법은 시민 불복종의 대상이 아니라고 주장한다.', false, '롤스에 따르면, 헌법에 따라 제정된 법이 정의로운 것이 아닐 수 있다. 따라서 롤스는 헌법에 따라 제정된 법이 부정의하고, 그러한 부정의가 한도를 넘어섰을 경우, 그러한 부정의한 법에 대해서 불복종이 정당화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 20, '롤스', '롤스는 차등의 원칙을 위반한 정책은 시민 불복종의 대상이 된다고 주장한다.', false, '롤스는 차등의 원칙을 위반하는 법은 시민 불복종의 대상이 될 수 없다고 본다. 제1원칙과 공정한 기회 균등의 원칙 위반은 명확하게 판단될 수 있는 데 반해, 차등의 원칙은 위반 여부를 명백히 판단하기가 어렵기 때문이다.'),
    (gen_random_uuid()::text, set_id, 21, '롤스', '롤스는 매우 부정의한 입헌 체제에서 시민 불복종은 성립할 수 없다고 주장한다.', true, '롤스는 매우 부정의한 체제에서는 시민 불복종이 성립되지 않는다고 본다. 롤스는 시민 불복종이 거의 정의로운 입헌 체제에서 시행되는 것이라고 본다.'),
    (gen_random_uuid()::text, set_id, 22, '롤스', '롤스는 시민불복종으로 발생할 불행한 결과를 고려해야 한다고 주장한다.', true, '롤스에 따르면, 시민 불복종을 할 수 있는 자격을 갖춘 집단의 수가 많고 그들 모두가 시민 불복종을 시행한다면 사회 질서 및 체제가 파멸할 가능성이 있다. 따라서 롤스는 이러한 불행한 결과가 발생하지 않도록, 시민 불복종에 가담할 수 있는 범위에 한계를 두어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 23, '롤스', '롤스는 시민 불복종은 개인의 이익이 아닌 집단의 이익에 근거해야 한다고 주장한다.', false, '롤스에게 시민 불복종의 근거는 개인의 이익, 집단의 이익이 아니라 다수의 정의감이다.'),
    (gen_random_uuid()::text, set_id, 24, '롤스', '롤스는 시민 불복종은 헌법의 정당성에 이의를 제기하는 정치적 행위이라고 주장한다.', false, '롤스의 시민 불복종은 사회 구성원 다수가 공유한 정의관과 이를 바탕으로 하는 헌법의 정의로움을 전제로 한다.'),
    (gen_random_uuid()::text, set_id, 25, '롤스', '롤스는 시민 불복종의 근거인 다수의 정의감은 개인의 양심과 양립할 수 없다고 주장한다.', false, '개인의 양심이 롤스의 시민 불복종을 정당화해주는 근거는 아니지만, 롤스의 시민 불복종은 양심적인 행위이다. 따라서 시민 불복종의 근거인 다수의 정의감은 개인의 양심과 양립할 수 있다.'),
    (gen_random_uuid()::text, set_id, 26, '롤스', '롤스는 시민 불복종은 정의감에 의해 상당히 규제되는 사회에서만 성립한다고 주장한다.', true, '롤스는 시민 불복종이 정의감에 의해 상당한 정도로 규제되는 사회에서만 합당하다고 본다.'),
    (gen_random_uuid()::text, set_id, 27, '롤스', '롤스는 정의 원칙도 시민 불복종의 대상에서 제외되지 않는다고 주장한다.', false, '롤스는 정의의 원칙을 시민 불복종의 근거 혹은 기준으로 본다. 따라서 롤스는 정의의 원칙이 시민 불복종의 대상이 될 수 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 28, '롤스', '롤스는 시민 불복종은 위법 행위이지만 사회 정의를 추구한다고 주장한다.', true, '롤스는 시민 불복종을 위법이지만 정의를 추구하는 도덕적인 행위로 보았다.'),
    (gen_random_uuid()::text, set_id, 29, '롤스', '롤스는 공직을 맡을 권리를 침해하는 정책은 시민 불복종의 대상이 된다고 주장한다.', true, '롤스는 공직을 맡을 자유가 제1원칙이 보장하는 정치적 자유에 포함된다고 본다. 따라서 공직을 맡을 권리를 침해하는 정책은 정의의 원칙을 어긴 것이나 다름없으며 시민 불복종의 대상이 될 수 있는 것이다.'),
    (gen_random_uuid()::text, set_id, 30, '롤스', '롤스는 시민 불복종이 가져올 효과를 신중히 고려해야 한다고 주장한다.', true, '롤스는 시민 불복종이 합당하게 계획되어 소기의 목적을 달성할 수 있는지, 아니면 시민 불복종에 가담하는 자가 많아 체제의 파멸을 야기하는 불행한 결과가 초래되지는 않을지 등을 고려해야 한다고 본다. 추가적으로 이는 싱어의 입장에도 해당된다.'),
    (gen_random_uuid()::text, set_id, 31, '롤스', '롤스는 합법적인 민주적 권위에 대한 시민 불복종은 가능하다고 주장한다.', true, '롤스의 시민 불복종은 합법적인 민주적 권위에 저항하는 행위이다. 롤스에 따르면 정당한 시민 불복종은 그러한 민주적 권위에 반대하는 형식으로 나아가 민주적인 권위를 더욱 발전시키고 입헌 체제를 더욱 공고히 하는 결과로 이어진다.'),
    (gen_random_uuid()::text, set_id, 32, '롤스', '롤스는 국가의 처벌이 시민 불복종의 대상이 되는 경우는 없다고 주장한다.', false, '롤스에 따르면, 국가의 처벌이 지나치게 과도할 경우, 그 처벌을 중지할 것을 시민 불복종을 통해 요구할 수 있다. 원전에 직접적으로 명시된 부분은 아니지만, 롤스 이론을 해석한 바에 따르면, 위의 설명이 적절하다고 할 수 있다.'),
    (gen_random_uuid()::text, set_id, 33, '롤스', '롤스는 시민 불복종은 정당한 법에 대한 위반을 수반할 수 있다고 주장한다.', true, '롤스는 항의의 대상이 되는 바로 그 법을 위반하는 직접적 시민 불복종뿐만 아니라 교통 법규 등과 같은 정당한 법을 어기는 방법을 통해 특정한 법의 폐지를 요구하는 간접적 시민 불복종 또한 주장한다. 롤스의 간접적 시민 불복종은 항의의 대상이 되는 법의 위반으로 인한 처벌이 너무 강력할 때, 또는 국제 문제에 관한 부정의일 때 정당화될 수 있다.'),
    (gen_random_uuid()::text, set_id, 34, '롤스', '롤스는 종교의 자유를 부정하는 법은 시민 불복종의 대상이 된다고 주장한다.', true, '종교의 자유는 정의의 제1원칙인 평등한 기본적 자유의 원칙에 의해 보장되는 기본적 자유이다. 롤스는 정의론에서 소수자의 종교적 자유를 억압하는 법률이나 정책이 시민 불복종의 대상이 될 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 35, '롤스', '롤스는 시민 불복종은 법의 부당함을 다수에게 강요하는 행위라고 주장한다.', false, '시민 불복종은 법이 부당하다고 다수의 시민들에게 알리는 행위이나, 즉 시민 불복종은 당연히 법의 부당함을 강요하는 행위가 아니다. 이 선지는 상식적으로 보아도 누구나 옳지 않다고 판단할 수 있는 선지이다.'),
    (gen_random_uuid()::text, set_id, 36, '롤스', '롤스는 소수자가 지닌 정의관은 시민 불복종의 근거가 될 수 없다고 주장한다.', false, '롤스에 따르면, 소수자의 정의관이 공공적 정의관과 일치하고, 정의의 원칙에 기반할 경우, 이는 시민 불복종의 정당한 근거가 될 수 있다. 즉 해당 선지에서는 소수자만이 갖는 정의관이라고 명시한 것이 아니라, 단순히 소수자가 갖는 정의관이라고 명시했을 뿐이다.'),
    (gen_random_uuid()::text, set_id, 37, '롤스', '롤스는 다수의 정의감이 상실될 때 시민 불복종은 반드시 요청된다고 주장한다.', false, '롤스에 따르면, 시민 불복종은 본디 다수의 정의감에 호소하는 것인데, 다수의 정의감이 상실된다면 시민 불복종의 역할이 제대로 시행되지 않게 된다. 따라서 롤스는 시민 불복종이 다수의 정의감을 전제하는 사회에서만 발생할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 38, '롤스', '롤스는 준법의 의무는 기본적 자유를 방어할 권리와 상충할 수 없다고 주장한다.', false, '롤스는 일반적으로 부정의한 법을 준수해야 할 자연적인 의무가 있다고 본다. 그러므로 부정의한 법에 대해서도, 그 정도가 심각하지 않다면 그 법을 준수해야 한다. 그러나 부정의한 법이 기본적 자유를 심각하게 침해할 경우, 이러한 준법 의무는 기본적 자유를 방어할 권리와 상충하여 무효화될 수 있다.'),
    (gen_random_uuid()::text, set_id, 39, '롤스', '롤스는 시민 불복종은 정치 체제의 효율성을 이유로 제한될 수 있다고 주장한다.', true, '롤스는 불복종 행위의 시기가 부적절하다거나, 정의감에 대한 호소가 효율적으로 이루어지게끔 계획이 잘 짜여져 있지 않을 경우에는 시민 불복종이 갖는 목적을 달성하기 어렵다고 본다. 롤스는 시민 불복종에 가담할 수 있는 범위에 한계를 두어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 40, '롤스', '롤스는 시민 불복종의 대상은 기본적 자유의 심각한 위반에 국한된다고 주장한다.', false, '롤스는 시민 불복종의 대상을 기본적 자유의 심각한 위반만이 아니라 공정한 기회 균등의 심각한 위반도 포함한다.'),
    (gen_random_uuid()::text, set_id, 41, '롤스', '롤스는 의회가 합법적으로 제정한 법은 시민 불복종의 대상이 아니라고 주장한다.', false, '롤스는 의회가 합법적으로 제정한 법도 부정의한 경우 시민 불복종의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 42, '롤스', '롤스는 시민 불복종은 법의 경계선 내에서 행해지는 정치적 행위라고 주장한다.', false, '시민 불복종은 법의 경계선 내에서 행해지는 정치적 행위가 아니라 위법 행위이다.'),
    (gen_random_uuid()::text, set_id, 43, '롤스', '롤스는 부정의한 법의 변혁은 시민 불복종의 목적이 아니라 결과라고 주장한다.', false, '롤스에게 시민 불복종의 목적은 부정의한 법이나 정책의 변혁이다.'),
    (gen_random_uuid()::text, set_id, 44, '롤스', '롤스는 공적 심의를 거친 정책이 시민 불복종의 대상이 될 수는 없다고 주장한다.', false, '롤스는 공적 심의를 거친 정책도 부정의할 수 있으며, 부정의한 경우 시민 불복종의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 45, '롤스', '롤스는 차등의 원칙에 근거한 법은 시민 불복종의 대상이 될 수 있다고 주장한다.', true, '롤스는 차등의 원칙에 근거한 법도 부정의할 경우 시민 불복종의 대상이 될 수 있다고 본다. 다만 롤스는 차등의 원칙의 위반이 명확하고 실질적인 침해에만 국한되어야 한다는 조건을 제시한다.'),
    (gen_random_uuid()::text, set_id, 46, '롤스', '롤스는 시민 불복종 참여자는 위법 행위에 대한 처벌을 감수해야 한다고 주장한다.', true, '롤스에 따르면 시민 불복종은 법정이 정당한 시민 불복종에 대해 법적인 제재를 축소하거나 보류할 수 있다고 본 것이지, 처벌 자체가 이루어지지 않는 것은 아니라고 본다. 애초에 시민 불복종은 안정적인 체제 내에서 이루어지는 것이고, 시민 불복종 행위자는 자신의 불복종 행위에 대한 처벌을 감수해야 한다.'),
    (gen_random_uuid()::text, set_id, 47, '롤스', '롤스는 시민 불복종은 다수자의 정의감을 나타내는 양심적인 행위라고 주장한다.', true, '롤스는 시민 불복종이 다수자의 정의감을 나타내는 행위이자, 양심적인 행위라고 본다. 시민 불복종은 법에 대한 충실성의 한계 내에서 부정의에 대해 항거하는 위법한 행위이다.'),
    (gen_random_uuid()::text, set_id, 48, '롤스', '롤스는 안정적인 체제에서는 시민 불복종 행위에 대해 처벌하지 않는다고 주장한다.', false, '롤스는 법정이 정당한 시민 불복종에 대해 법적인 제재를 축소하거나 보류할 수 있다고 본 것이지, 처벌 자체가 이루어지지 않는 것은 아니라고 본다. 애초에 시민 불복종은 안정적인 체제 내에서 이루어지는 것이고, 시민 불복종 행위자는 자신의 불복종 행위에 대한 처벌을 감수해야 한다.'),
    (gen_random_uuid()::text, set_id, 49, '롤스', '롤스는 기본적 자유를 침해한 법에 대한 항거도 정당하지 않을 수 있다고 주장한다.', true, '롤스는 불법적인 수단 중에서 시민 불복종은 도덕적으로 정당화될 수 있는 조건이 충족된다면 정당화될 수 있다고 보는 반면, 그 외의 불법적인 수단인 양심적 거부, 폭력적 저항, 군사적 행동, 혁명 등은 정당화되기 어렵다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 50, '롤스', '롤스는 시민 불복종이 성립되지 않는 사회가 정의로운 사회일 수는 없다고 주장한다.', false, '롤스는 시민 불복종이 완전히 질서 정연한 사회, 체제 자체가 부정의한 사회가 아니라 거의, 대체로 질서 정연한 거의 정의로운 사회라는 특수한 경우에 시행되는 것이라고 주장한다. 따라서 시민 불복종이 성립되지 않는 사회에는 완전히 정의로운 사회가 포함될 수 있기 때문에, 해당 선지는 롤스의 입장에 부합하지 않는다.'),
    (gen_random_uuid()::text, set_id, 51, '롤스', '롤스는 다수 의사를 반영한 법은 시민 불복종 대상에서 제외되어야 한다고 주장한다.', false, '롤스는 다수결의 결과로 제정된 법 등이 평등한 자유의 원칙이나 공정한 기회 균등의 원칙을 심각하게 위반하는 경우, 해당 법은 시민 불복종의 대상이 될 수 있다고 설명한다.'),
    (gen_random_uuid()::text, set_id, 52, '롤스', '롤스는 다수가 믿는 종교적 가르침은 시민 불복종을 정당화하는 근거라고 주장한다.', false, '롤스는 시민 불복종의 근거가 사회적 다수에 의해 공유된 정의관, 즉 공공적 정의관이어야 한다고 본다. 이러한 의미에서 롤스는 시민 불복종이 개인적인 도덕 원칙이나 종교적 교설에 의거해서는 안 된다고 강조한다. 이는 이러한 개인적 또는 종교적 신념이 정치 체제에서 보편적 기준이 될 수 없기 때문이다.'),
    (gen_random_uuid()::text, set_id, 53, '롤스', '롤스는 시민 불복종은 비민주적 체제의 변혁을 목적으로 이루어져야 한다고 주장한다.', false, '롤스의 시민 불복종은 민주적 체제를 갖춘 거의 정의로운 사회에서만 행해질 수 있다. 따라서 비민주적 체제의 변혁은 시민 불복종의 목적이 아니다. 애초에 비민주적인 체제에서는 시민 불복종이 성립하지 않는다.'),
    (gen_random_uuid()::text, set_id, 54, '롤스', '롤스는 시민 불복종은 다수결의 원칙에 대한 반대를 표하는 정치 행위라고 주장한다.', false, '롤스의 시민 불복종은 다수결의 원칙 자체에 대해 반대를 표하는 정치 행위가 아니라 다수결의 원칙에 의해 만들어진 법, 제도, 정책이라도 그것이 심각하게 부정의하다면 시행될 수 있는 정치적 행위이다. 롤스에 따르면 민주주의의 헌법이 다수결 원칙을 채택하는 것은 필연적이라고 본다.'),
    (gen_random_uuid()::text, set_id, 55, '롤스', '롤스는 시민 불복종은 사회의 기본 구조가 아주 부정의하면 성립할 수 없다고 주장한다.', true, '롤스의 시민 불복종은 사회의 기본 구조가 대체로 정의로운 거의 정의로운 사회에서 행해지는 불복종 행위이다. 즉, 롤스는 기본 구조가 아주 부정의한 사회에서 시민 불복종이 시행될 수 없다고 본다.'),
    (gen_random_uuid()::text, set_id, 56, '롤스', '롤스는 시민 불복종은 공유된 정의관에 따른 숙고를 권력자들에게 촉구한다고 주장한다.', true, '롤스는 일반적으로 소수의 시민 불복종 행위자가 권력자들로 하여금 공유된 정의관에 대해 숙고해볼 것을 요구한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 57, '롤스', '롤스는 심각한 부정의가 존재하는 민주 체제에서는 시민 불복종이 가능하다고 주장한다.', true, '롤스는 심각한 부정의가 존재하는 민주 체제에서도 시민 불복종이 가능하다고 본다. 롤스는 거의 정의로운 사회에서 시민 불복종이 가능하다고 보았으며, 거의 정의로운 사회는 입헌 체제가 존재하며 공인된 정의관이 존재하는 사회이지만 심각한 부정의인 결함이 발생할 수 있는 사회이다.'),
    (gen_random_uuid()::text, set_id, 58, '롤스', '롤스는 양심적 거부에 대한 국가의 규제는 시민 불복종의 대상이 될 수 없다고 주장한다.', false, '롤스에 따르면, 각자의 양심적 거부에 대해서 국가가 심하게 탄압한다면, 이는 시민 불복종의 대상이 될 수 있는 것이다. 참고로, 양심적 거부는 개인이 자신의 양심에 따라 특정 법령이나 명령에 따르지 않는 것을 의미한다.'),
    (gen_random_uuid()::text, set_id, 59, '롤스', '롤스는 이익 집단의 시민 불복종은 공공의 정의관에 근거해야 허용될 수 있다고 주장한다.', true, '롤스는 이익 집단이 그들의 이익에 근거해서가 아닌, 다수의 정의관에 근거하여 시민 불복종을 시행한다면 정당화될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 60, '롤스', '롤스는 시민 불복종은 다수의 정의감을 전제하므로 소수자가 주체일 수는 없다고 주장한다.', false, '시민 불복종은 대체로 소수자들 또는 각기 다른 여러 소수자 집단이 행한다. 다수자들은 시민 불복종을 하지 않아도 된다. 다수자들은 합법적인 투표를 통해서, 다수결의 원리에 따라서, 본인들이 생각할 때 부정의한 법을 고칠 수 있기 때문이다. 물론, 다수자도 시민 불복종에 참여할 수는 있을 것이다.'),
    (gen_random_uuid()::text, set_id, 61, '롤스', '롤스는 시민 불복종은 정의로운 법을 제정할 절차가 불완전하여 발생할 수 있다고 주장한다.', true, '롤스는 헌법이 불완전한 절차적 정의라고 본다. 그렇기에 심각하게 부정의한 법이 제정될 수 있기 때문에, 시민 불복종이 발생할 수 있다는 것이 롤스의 입장이다.'),
    (gen_random_uuid()::text, set_id, 62, '롤스', '롤스는 다수결 원칙에 따라 민주적으로 제정된 법은 시민 불복종의 대상이 아니라고 주장한다.', false, '롤스는 다수결 원칙에 따라 제정된 법도 부정의할 수 있다고 본다. 만약 그 법 중에서 한계를 넘는 부정의한 법, 즉 심각하게 부정의한 법이 있다면, 이에 대해 시민 불복종을 고려할 수 있다는 것이 롤스의 입장이다. 참고로, 이는 싱어와의 공통점이기도 하다.'),
    (gen_random_uuid()::text, set_id, 63, '롤스', '롤스는 부정의한 법을 변혁하고자 불가피하게 다른 법을 위반하는 시민 불복종은 정당화될 수 있다고 주장한다.', true, '롤스는 항의의 대상이 되는 바로 그 법을 위반하는 직접적 시민 불복종뿐만 아니라 교통 법규 등과 같은 정당한 법을 어기는 방법을 통해 특정한 법의 폐지를 요구하는 간접적 시민 불복종 또한 주장한다. 롤스의 간접적 시민 불복종은 항의의 대상이 되는 법의 위반으로 인한 처벌이 너무 강력할 때, 또는 국제 문제에 관한 부정의일 때 정당화될 수 있다.'),
    (gen_random_uuid()::text, set_id, 64, '싱어', '싱어는 시민 불복종이 가져올 효과를 신중히 고려해야 한다고 주장한다.', true, '싱어의 입장으로 적절하다. 싱어는 공리주의적 관점에서 시민 불복종이 가져올 수 있는 긍정적인 효과와 부정적인 효과를 미리 신중하게 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 65, '싱어', '싱어는 시민 불복종은 법에 대한 존중심을 감소시킬 수 있다고 주장한다.', true, '싱어는 시민 불복종이 법에 대한 존중심을 감소시킬 수 있는 행위이기에 공리주의 원칙에 입각하여 시민 불복종 행위를 통해 발생할 이익과 손해를 고려하여 합당하게 불복종 행위를 시행해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 66, '싱어', '싱어는 시민 불복종으로 발생할 불행한 결과를 고려해야 한다고 주장한다.', true, '싱어는 공리주의자로서 효용성을 강조하는 사상을 시민 불복종에도 적용시켜, 시민 불복종으로 발생할 수 있는 불행한 결과를 사전에 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 67, '싱어', '싱어는 시민 불복종은 민주주의적 결정을 복원하려는 시도라고 주장한다.', true, '싱어는 시민 불복종이 민주주의적 의사결정을 좌절시키기보다는 복원하려는 시도라고 본다.'),
    (gen_random_uuid()::text, set_id, 68, '싱어', '싱어는 시민 불복종의 목적은 결코 그 수단을 정당화할 수 없다고 주장한다.', false, '싱어는 목적이 결코 그 수단을 정당화할 수 없다라는 형식으로 말하지 않는다. 어떤 수단이 어떤 목적에 의해서 정당화될 수 있는가가 더 중요한 것이다. 따라서 시민 불복종은 합당한 목적에 의하여 정당화될 수 있다는 것이 싱어가 말하고 있는 원칙이다.'),
    (gen_random_uuid()::text, set_id, 69, '싱어', '싱어는 시민 불복종을 하는 시민은 보편적 법치 원리를 존중한다고 주장한다.', true, '싱어는 시민 불복종을 하는 시민은 보편적 법치 원리를 존중한다고 본다.'),
    (gen_random_uuid()::text, set_id, 70, '싱어', '싱어는 시민 불복종은 법의 부당함을 다수에게 강요하는 행위라고 주장한다.', false, '싱어의 입장으로 적절하지 않다. 시민 불복종은 법이 부당하다고 다수의 시민들에게 알리는 행위이다. 법의 부당함을 강요하는 행위가 아니다.'),
    (gen_random_uuid()::text, set_id, 71, '싱어', '싱어는 시민 불복종은 성패에 따르는 비용과 편익을 고려해야 한다고 주장한다.', true, '싱어는 공리주의자로서 시민 불복종은 비용과 편익, 즉 효용성을 고려하여 시행되어야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 72, '싱어', '싱어는 시민 불복종이 산출할 사회적 이익과 해악이 고려되어야 한다고 주장한다.', true, '싱어는 공리주의자로서 시민 불복종은 비용과 편익, 즉 효용성을 고려하여 시행되어야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 73, '싱어', '싱어는 시민 불복종 참여자는 위법 행위에 대한 처벌을 감수해야 한다고 주장한다.', true, '싱어는 시민 불복종 행위자가 항의의 진지성과 법의 통치 및 민주주의 기본 원칙들에 대한 존중을 명백히 하기 위해 처벌을 감수해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 74, '싱어', '싱어는 부정의를 해결할 수 있는 합법적 방법이 우선적으로 고려되어야 한다고 주장한다.', true, '싱어는 시민 불복종을 시행하기 이전에 다른 합법적인 방법을 먼저 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 75, '싱어', '싱어는 다수의 견해를 진정으로 반영한 법에 대한 시민 불복종은 불가능하다고 주장한다.', false, '싱어는 다수의 진정한 의사가 반영된 법이라고 하더라도 도덕적으로 옳지 못하다면 시민 불복종의 대상이 될 수 있다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 76, '싱어', '싱어는 다수결 원칙에 따라 민주적으로 제정된 법은 시민 불복종의 대상이 아니라고 주장한다.', false, '싱어는 다수결 원칙이 현실적으로 완전하지 않음을 인정한다. 그러므로 싱어는 다수결 원칙에 따라 제정된 법도 부정의할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 77, '싱어', '싱어는 양심에서 비롯된 시민 불복종도 실패 가능성이 크면 정당성을 상실할 수 있다고 주장한다.', true, '싱어에 따르면 시민 불복종이 실패 가능성이 크다고 판단된다면 시민 불복종 행위는 정당성을 상실할 수 있다. 왜냐하면 싱어는 공리주의자로서 시민 불복종 행위의 결과를 고려해야 한다고 주장하는 사상가이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 78, '싱어', '싱어는 법에 대한 존중이 강한 민주 사회일수록 시민 불복종이 옹호될 가능성이 높다고 주장한다.', true, '싱어에 따르면, 법과 민주주의에 대한 존중이 깊이 뿌리내린 민주주의 사회에서는 시민 불복종이 오히려 더 쉽게 정당화될 수 있다. 이는 민주주의 사회가 비판적 의견과 사회적 변화에 대한 개방성을 지니고 있기 때문이다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '갑(도가)/을(유교)/병(불교)', '도가는 인간과 자연의 합일을 추구한다.', true, '동양의 자연관은 모두 인간과 자연의 엄격한 분리가 아니라, 합일을 긍정한다.'),
    (gen_random_uuid()::text, set_id, 2, '갑(도가)/을(유교)/병(불교)', '도가는 자연이 목적론적 체계로 구성된다고 주장한다.', false, '도가에서는 자연을 아무런 목적이 없는 무위의 체계로 바라본다. 도가는 자연이 무위의 원리로 운행하듯 인간 또한 자연에 조작과 통제를 가해서는 안 된다고 보았다.'),
    (gen_random_uuid()::text, set_id, 3, '갑(도가)/을(유교)/병(불교)', '도가는 자연을 목적이 없는 무위의 체계로 파악한다.', true, '도가에서는 자연을 아무런 목적이 없는 무위의 체계로 바라본다.'),
    (gen_random_uuid()::text, set_id, 4, '갑(도가)/을(유교)/병(불교)', '도가는 인위를 버리고 상선약수의 도를 따르려 한다.', true, '노자는 무위자연의 삶을 물에 비유하여 최고의 선은 물과 같다라고 설명하였다.'),
    (gen_random_uuid()::text, set_id, 5, '갑(도가)/을(유교)/병(불교)', '도가는 자연 만물을 상의와 화해의 관계에 놓인 것으로 본다.', true, '동양 자연관의 공통점이다. 상의란 개개의 사물이 서로 의존해서 존재한다는 것을 뜻하며 화해란 개개의 존재가 서로 간의 균형과 협동을 통해 조화를 이루는 것을 말한다.'),
    (gen_random_uuid()::text, set_id, 6, '갑(도가)/을(유교)/병(불교)', '유교는 자연의 순리에 따라야 한다고 강조한다.', true, '동양의 자연관은 모두 자연의 순리에 따르는 것을 긍정한다.'),
    (gen_random_uuid()::text, set_id, 7, '갑(도가)/을(유교)/병(불교)', '유교는 하늘을 인과 같은 덕의 근원이라고 본다.', true, '유교는 도덕천의 관점으로, 하늘이 인과 같은 도덕의 근원이라고 보는 관점을 취한다.'),
    (gen_random_uuid()::text, set_id, 8, '갑(도가)/을(유교)/병(불교)', '유교는 자연을 필연적 질서가 지배하는 기계적인 존재로 본다.', false, '서양의 기계론적 자연관에 해당하는 표현이다. 동양의 자연관은 자연을 기계가 아니라, 유기체로 본다.'),
    (gen_random_uuid()::text, set_id, 9, '갑(도가)/을(유교)/병(불교)', '유교는 자연을 원인과 조건에 의해 생멸하는 관계의 그물로 본다.', false, '유교가 아니라 불교의 입장이다. 불교는 인연생기설에 따라, 자연을 상호 의존적인 그물망인 인드라망으로 파악한다.'),
    (gen_random_uuid()::text, set_id, 10, '갑(도가)/을(유교)/병(불교)', '유교는 인간과 하늘을 상호 독립된 존재로 이해해야 한다고 주장한다.', false, '동양의 자연관은 인간과 자연, 하늘이 상호 조화를 이뤄야 한다고 본다. 따라서 인간과 하늘을 상호 독립된 존재로 보지 않는다.'),
    (gen_random_uuid()::text, set_id, 11, '갑(도가)/을(유교)/병(불교)', '불교는 인간과 자연의 엄격한 분리를 추구한다.', false, '불교를 포함한 동양의 자연관은 인간과 자연의 엄격한 분리가 아니라, 합일을 긍정한다.'),
    (gen_random_uuid()::text, set_id, 12, '갑(도가)/을(유교)/병(불교)', '불교는 자연 만물에 고정된 실체가 없다고 주장한다.', true, '불교는 자연 만물에 고정된 실체가 없다고 본다. 이는 불교의 삼법인 중 제행무상으로 이해할 수 있다.'),
    (gen_random_uuid()::text, set_id, 13, '갑(도가)/을(유교)/병(불교)', '불교는 살아 있는 모든 생명에 대한 존중을 강조한다고 주장한다.', true, '불교는 연기에 대한 깨달음을 통해서 모든 생명에 자비를 베풀 것을 강조한다.'),
    (gen_random_uuid()::text, set_id, 14, '갑(도가)/을(유교)/병(불교)', '불교는 만물이 원인과 조건에 의해 생멸한다고 주장한다.', true, '불교는 인연생기설에 따라, 자연을 상호 의존적인 그물망인 인드라망으로 파악한다. 만물이 원인과 조건에 의해 생멸한다는 것은 연기적 관점에 해당한다.'),
    (gen_random_uuid()::text, set_id, 15, '갑(도가)/을(유교)/병(불교)', '불교는 연기적 관점에서 자연을 이해해야 한다고 주장한다.', true, '불교는 연기설에 근거하여 인간과 자연의 상호 의존성을 자각하고 모든 생명에 자비를 베풀 것을 강조한다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '칸트', '칸트는 인간은 토지를 단지 자원으로만 이용해서는 안 된다고 주장한다.', false, '칸트는 인간이 창조의 궁극 목적이기 때문에, 자연의 세계는 인간의 사용을 위해 존재하는 것이라고 본다. 즉, 칸트에 따르면 토지를 인간을 위한 자원으로만 이용해도 되는 것이다.'),
    (gen_random_uuid()::text, set_id, 2, '칸트', '칸트는 도덕적 행위 주체들의 도덕적 지위가 서로 평등하다고 주장한다.', true, '칸트의 입장에서 도덕적 행위 주체는 도덕적으로 행위할 수 있는 이성적 인간을 말한다. 그리고, 칸트는 도덕적 행위 능력을 지닌 인간만이 목적 그 자체로서의 가치, 내재적 가치를 지닌 존재로서 평등한 도덕적 지위를 지닌다고 본다.'),
    (gen_random_uuid()::text, set_id, 3, '칸트', '칸트는 도덕적 행위 능력이 없는 존재도 모두 내재적 가치를 지닌다고 주장한다.', false, '칸트는 도덕적 행위 능력을 지닌 인간만이 목적 그 자체로서의 가치, 내재적 가치를 지닌 존재로서 평등한 도덕적 지위를 지닌다고 본다.'),
    (gen_random_uuid()::text, set_id, 4, '칸트', '칸트는 자연에 속하면서 권리를 가질 수 있는 개별 존재가 있다고 주장한다.', true, '칸트의 입장에서 자연에 속하면서 권리를 가지는 존재는 인간이다.'),
    (gen_random_uuid()::text, set_id, 5, '칸트', '칸트는 어떤 존재를 목적 그 자체로 보는 근거는 이성이 아니라고 주장한다.', false, '칸트는 이성과 자율성을 지닌 존재만이 스스로의 행위 원리를 세우는 도덕 법칙의 입법자이기 때문에 그 자체로 목적인 존재가 될 수 있다고 보았다. 이런 점에서 칸트는 인간이 다른 모든 존재보다 우월하다고 본다.'),
    (gen_random_uuid()::text, set_id, 6, '칸트', '칸트는 인간은 다른 모든 생명체보다 본질적으로 우월하지 않다고 주장한다.', false, '칸트의 입장에서 인간의 가치 평가에서 독립적인 가치는 목적적 가치로서, 인간만이 지니는 가치이다. 이런 점에서 칸트는 인간이 다른 모든 존재보다 우월하다고 본다.'),
    (gen_random_uuid()::text, set_id, 7, '칸트', '칸트는 동물은 인간의 가치 평가에서 독립적인 가치를 지닐 수 없다고 주장한다.', true, '동물과 같은 존재는 이성과 자율성을 지니지 못하기 때문에 목적 그 자체로서의 가치를 갖지 못하고, 오직 상대적 가치만을 지닌다고 할 수 있다.'),
    (gen_random_uuid()::text, set_id, 8, '칸트', '칸트는 생명체들의 가치보다 생명 공동체의 가치가 더 중요하다고 주장한다.', false, '칸트의 입장이 아니다. 이 선지는 전체론적 자연관을 가진 사상가의 입장이다. 평가원에 출제되는 사상가 중에서는 레오폴드만의 입장이다.'),
    (gen_random_uuid()::text, set_id, 9, '칸트', '칸트는 인간 이외의 존재에게는 어떠한 가치도 부여되지 않는다고 주장한다.', false, '칸트에 따르면 자연의 생물이나 무생물은 수단으로서 상대적 가치를 가지거나, 미적 가치 등을 가질 수 있다. 하지만 목적 그 자체로서의 가치, 내재적 가치는 인간만이 가진다.'),
    (gen_random_uuid()::text, set_id, 10, '칸트', '칸트는 생명 없는 존재의 파괴가 도덕적으로 정당한 경우는 없다고 주장한다.', false, '칸트는 무생물 등 자연물 파괴가 정당화되지 않는다고 보지 않는다. 예를 들어, 집 건축 등 인간의 필요를 위해 자연물을 파괴하는 경우도 있을 수 있다.'),
    (gen_random_uuid()::text, set_id, 11, '칸트', '칸트는 자연물을 파괴하는 인간의 행위가 도덕적으로 허용될 수 있다고 주장한다.', true, '칸트는 무생물 등 자연물 파괴가 정당화되지 않는다고 보지 않는다. 예를 들어, 집 건축 등 인간의 필요를 위해 자연물을 파괴하는 경우도 있을 수 있다.'),
    (gen_random_uuid()::text, set_id, 12, '칸트', '칸트는 인간에 대한 인간의 의무로 환원되지 않는 의무가 있다고 주장한다.', false, '칸트는 인간이 인간에 대한 의무만을 지닌다고 본다. 인간이 아닌 존재와 관련된 의무는 모두 인간에 대한 의무로 환원된다.'),
    (gen_random_uuid()::text, set_id, 13, '칸트', '칸트는 인간 존엄성을 훼손할 가능성이 동물 학대 금지의 근거라고 주장한다.', true, '칸트의 입장에서 동물을 학대하지 않을 의무에서 금지되는 행위는 동물 학대이지만, 동물 학대 금지의 근거는 인간의 도덕성을 훼손하지 않을 의무라는 점에서 동물 학대 금지는 인간에 대한 의무인 것이다.'),
    (gen_random_uuid()::text, set_id, 14, '칸트', '칸트는 쾌고 감수 능력은 도덕적 행위자임을 판별하는 결정적 기준이라고 주장한다.', false, '칸트의 입장에서 도덕적 행위자란 이성과 자율성을 바탕으로 자발적으로 도덕 법칙에 따라 행위할 수 있는 존재를 의미한다. 따라서 쾌고 감수 능력이 아니라, 이성적 능력이 도덕적 행위자임을 판별하는 기준이 된다.'),
    (gen_random_uuid()::text, set_id, 15, '칸트', '칸트는 어떤 생명체의 존속은 그 생명체의 본래적 가치에 의해 정당화된다고 주장한다.', true, '칸트는 선지에서 말하는 어떤 생명체를 인간이라고 보고, 인간이 생명을 유지해야 함은 인간의 본래적 가치에 의해 정당화된다고 볼 것이다.'),
    (gen_random_uuid()::text, set_id, 16, '칸트', '칸트는 인간은 살아 있는 모든 존재를 도덕적으로 존중해야 한다고 주장한다.', false, '칸트의 입장에서, 인간이 도덕적으로 존중해야 하는 존재는 인간뿐이다.'),
    (gen_random_uuid()::text, set_id, 17, '칸트', '칸트는 자신 이외의 존재에 대한 도덕적 의무는 성립 불가능하다고 주장한다.', false, '칸트는 자신 이외에도 타인에 대한 도덕적 의무가 성립한다고 본다.'),
    (gen_random_uuid()::text, set_id, 18, '칸트', '칸트는 이성적 삶의 주체만이 생명체에 대한 도덕적 의무를 지닌다고 주장한다.', false, '칸트는 인간이 인간에 대한 의무만을 지닌다고 보고, 인간 이외의 존재에 대한 의무를 인정하지 않는다. 한편, 생명을 함부로 대하지 않을 의무와 같은 인간 이외의 존재와 관련된 의무가 발생할 수 있는데, 그런 의무의 근거와 목적은 인간성 보존이다.'),
    (gen_random_uuid()::text, set_id, 19, '칸트', '칸트는 동물의 고통에 대한 동정심은 도덕적 의무에 어긋나지 않는다고 주장한다.', true, '칸트는 동물의 고통에 대한 동정심은 동물에 대한 의무는 아니지만, 인간성 실현을 위해 요구되는 의무로 성립할 수 있다고 보았다.'),
    (gen_random_uuid()::text, set_id, 20, '칸트', '칸트는 동물을 학대하지 않는 것은 인간의 자신에 대한 의무에 부합한다고 주장한다.', true, '동물을 학대하면 인간이 가진, 고통에 대한 공감이 무뎌지고, 인간의 도덕성에 유익한 천성적 소질이 고갈될 수 있다. 따라서, 동물을 학대하는 것은 인간에 대한 의무에 어긋나는 것이다.'),
    (gen_random_uuid()::text, set_id, 21, '칸트', '칸트는 생태계뿐만 아니라 개별 생명체도 도덕적 고려의 대상일 수 있다고 주장한다.', false, '칸트는 인간만을 도덕적 고려 대상으로 본다. 생태계나 인간이 아닌 생명체는 이성이 없기 때문에 도덕적 고려 대상이 될 수 없다.'),
    (gen_random_uuid()::text, set_id, 22, '칸트', '칸트는 종이 다른 개체를 서로 다르게 대우하는 것이 정당화될 수 있다고 주장한다.', true, '칸트는 인간을 목적적 존재로 대우하고, 인간이 아닌 다른 개체는 단지 수단적 가치를 가지는 대상일 뿐이라고 보는 관점에서 인간과 인간이 아닌 다른 개체를 서로 다르게 대우해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 23, '칸트', '칸트는 인간에 대한 의무의 근거가 동물에 대한 의무를 정당화할 수 있다고 주장한다.', false, '인간에 대한 의무의 근거는 인간이 가진 목적적 가치이다. 칸트에 따르면, 이성적 존재가 목적적 가치를 가지는 것이고, 동물은 목적적 가치를 갖지 못한다. 따라서 인간은 동물에 대한 의무를 갖지 않는다.'),
    (gen_random_uuid()::text, set_id, 24, '칸트', '칸트는 도덕적 행위 주체성은 도덕적 지위 결정의 유일한 요인이라고 주장한다.', true, '칸트에 따르면, 이성적이고 자율적인 존재만이 자신이 세운 보편적인 도덕 법칙을 따를 의무를 지닐 수 있으므로, 이들은 도덕적 행위의 주체가 된다. 따라서 도덕적 행위 주체성은 도덕적 지위를 결정하는 유일한 요인이 된다.'),
    (gen_random_uuid()::text, set_id, 25, '칸트', '칸트는 도덕적 능력이 있어야만 도덕적 존중의 대상이 되는 것은 아니라고 주장한다.', false, '칸트에 따르면 도덕적 능력이 있어야만 도덕적 존중의 대상이 된다. 이것이 바로 도덕적 행위 주체성이며 도덕적 지위를 결정하는 유일한 요인이다.'),
    (gen_random_uuid()::text, set_id, 26, '칸트', '칸트는 인간에 대해서뿐만 아니라 자연과 관련해서도 도덕적 의무가 발생한다고 주장한다.', true, '칸트에 따르면, 인간은 인간에 대한 의무만을 지닌다. 인간에 대한 의무로부터 자연과 같은 인간이 아닌 존재와 관련된 의무가 발생한다. 칸트는 자연을 대할 때의 태도가 자기 자신의 인간성과 타인을 대할 때의 태도에 영향을 미치기 때문에 자연을 함부로 하지 않을 의무가 발생한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 27, '칸트', '칸트는 어떤 존재가 생명을 지닌 개체가 아니어도 도덕적 지위를 가질 수 있다고 주장한다.', false, '칸트는 생명을 지닌 개체 중 인간만이 도덕적 지위를 가질 수 있다고 본다. 생명을 지닌 개체가 아니라면, 즉 무생물이라면 도덕적 지위를 가질 수 없다.'),
    (gen_random_uuid()::text, set_id, 28, '칸트', '칸트는 생태계의 구성원만이 도덕적 지위를 지닌 존재가 될 수 있는 것은 아니라고 주장한다.', false, '칸트는 인간만이 도덕적 지위를 지닌다고 본다. 그리고 모든 인간은 생태계의 구성원이다. 따라서 칸트의 입장에서는 생태계의 구성원만이 도덕적 지위를 지닌 존재가 될 수 있는 것이다.'),
    (gen_random_uuid()::text, set_id, 29, '칸트', '칸트는 수단으로만 이용되어선 안 되는 존재는 도덕적 의무의 대상이 될 수 있다고 주장한다.', true, '칸트의 입장에서 수단으로만 이용되어서는 안 되는 존재란 이성과 자율성을 갖춘 존재, 곧 인간을 의미한다. 인간은 자신의 행위를 스스로 결정하고 책임질 수 있는 자율적 존재이므로, 그 자체로 목적적 존재가 된다.'),
    (gen_random_uuid()::text, set_id, 30, '칸트', '칸트는 쾌고 감수 능력은 어떤 개체가 도덕적 지위를 갖는지 판단할 때 고려해야 할 조건이 아니라고 주장한다.', true, '칸트에 따르면, 도덕적 지위를 가질 수 있는 존재는 이성을 지닌 존재, 곧 자율적으로 도덕 법칙을 세우고 따를 수 있는 존재다. 따라서 쾌고 감수 능력은 도덕적 지위를 판단하는 기준이 되지 않는다.'),
    (gen_random_uuid()::text, set_id, 31, '레건', '레건은 삶의 주체에 대한 도덕적 존중은 내재적 가치에 근거한다고 주장한다.', true, '레건은 삶의 주체가 내재적 가치를 지니기 때문에 도덕적 존중을 받아야 한다고 본다. 즉, 삶의 주체에 대한 도덕적 존중의 근거는 삶의 주체가 지니는 내재적 가치이다.'),
    (gen_random_uuid()::text, set_id, 32, '레건', '레건은 어떤 존재를 목적 그 자체로 보는 근거는 이성이 아니라고 주장한다.', true, '어떤 존재를 목적 그 자체로 본다는 것은 그 존재의 내재적 가치를 인정한다는 것과 같은 의미이다. 레건의 입장에서는 이성을 지니지 않은 존재도 내재적 가치를 가질 수 있기 때문에, 이성이 내재적 가치의 근거가 아님을 추론할 수 있다.'),
    (gen_random_uuid()::text, set_id, 33, '레건', '레건은 도덕적 행위 주체들의 도덕적 지위가 서로 평등하다고 주장한다.', true, '레건은 도덕적 행위 주체들은 물론, 모든 삶의 주체의 도덕적 지위가 평등하다고 보았다.'),
    (gen_random_uuid()::text, set_id, 34, '레건', '레건은 인간은 생태계에 간섭해서는 안 되는 의무를 지닌다고 주장한다.', false, '레건은 삶의 주체인 존재를 도덕적으로 고려할 의무를 주장한다. 생태계에 간섭해서는 안 되는 의무를 지닌다고 주장하지는 않았다. 한편, 개별 생명체를 위해 생태계에 간섭하지 않을 의무를 주장하는 것은 테일러이다.'),
    (gen_random_uuid()::text, set_id, 35, '레건', '레건은 한 살 이상의 정상적인 포유동물은 내재적 가치를 지닌다고 주장한다.', true, '레건에 따르면, 한 살 이상의 정상적인 포유동물은 쾌고 감수 능력 등 자기 삶을 영위하기 위해 필요한 능력을 지니기 때문에 삶의 주체이다. 삶의 주체인 존재는 모두 동등한 내재적 가치를 지닌다.'),
    (gen_random_uuid()::text, set_id, 36, '레건', '레건은 생태계의 선이 개체의 선보다 우선하는 것은 아니라고 주장한다.', true, '레건은 개체론자로서 개체의 선을 생태계의 선보다 중시하고 우선시한다.'),
    (gen_random_uuid()::text, set_id, 37, '레건', '레건은 인간 상호 간의 의무는 도덕적으로 정당화될 수 있다고 주장한다.', true, '인간 상호 간의 의무는 인간 사이의 지켜야 할 것들을 말한다. 이런 의무는 모든 환경 윤리 사상가가 동의할 의무이다.'),
    (gen_random_uuid()::text, set_id, 38, '레건', '레건은 이익 관심을 지닌 모든 개체는 동일한 대우를 받아야 한다고 주장한다.', false, '이익 관심을 지닌 모든 개체가 삶의 주체인 것은 아니다. 이익 관심을 가졌지만 자기 삶을 영위하는데 필요한 다른 능력을 갖지 못한 동물은 삶의 주체가 아니다.'),
    (gen_random_uuid()::text, set_id, 39, '레건', '레건은 목적 그 자체로서 가치를 지닌 존재는 도덕적 존중의 대상이라고 주장한다.', true, '목적 그 자체로서 가치는 내재적 가치이다. 레건의 입장에서 모든 삶의 주체가 내재적 가치를 지니며, 도덕적 존중의 대상이다.'),
    (gen_random_uuid()::text, set_id, 40, '레건', '레건은 동물 학대가 그릇된 근본 이유는 인간성 실현을 저해함에 있다고 주장한다.', false, '레건의 입장에서 동물 학대가 그릇된 이유는 동물 학대는 삶의 주체인 동물의 내재적 가치와 도덕적 권리를 무시하는 행위이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 41, '레건', '레건은 자율적 행위 능력과 무관하게 도덕적 지위는 부여되어야 한다고 주장한다.', true, '레건의 입장에서 자율적 행위 능력이나 사유 능력의 여부는 도덕적 지위와 무관하다. 레건은 자율적 행위 능력이나 사유 능력 여부와 상관없이 삶의 주체인 모든 존재가 동등한 도덕적 지위를 지닌다고 본다.'),
    (gen_random_uuid()::text, set_id, 42, '레건', '레건은 사유 능력 여부로 어떤 존재의 도덕적 지위가 결정되지 않는다고 주장한다.', true, '레건의 입장에서 자율적 행위 능력이나 사유 능력의 여부는 도덕적 지위와 무관하다.'),
    (gen_random_uuid()::text, set_id, 43, '레건', '레건은 살아 있는 모든 개체는 도덕적 고려 대상인 공동체의 일원이라고 주장한다.', false, '레건에게 공동체는 도덕적 고려 대상이 아니다. 모든 생명체가 도덕적 고려 대상인 것도 아니다. 레건이 인정하는 도덕적 고려 대상은 삶의 주체인 개체이다.'),
    (gen_random_uuid()::text, set_id, 44, '레건', '레건은 생명에 대한 권리는 인간에게 한정된 특수한 권리가 아니라고 주장한다.', true, '레건은 삶의 주체인 존재는 모두 생명에 대한 권리를 갖는다고 본다.'),
    (gen_random_uuid()::text, set_id, 45, '레건', '레건은 도덕적 행위 능력이 있어야만 도덕적 존중의 대상이 되는 것은 아니라고 주장한다.', true, '레건의 입장에서 자율적 행위 능력이나 사유 능력의 여부는 도덕적 지위와 무관하다. 도덕적 지위 문제에 있어서 자율적 행위 능력을 고려하는 것은 인간 중심주의뿐이다.'),
    (gen_random_uuid()::text, set_id, 46, '레건', '레건은 인간 이외의 존재에게는 어떠한 가치도 부여되지 않는다고 주장한다.', false, '인간 이외에도 삶의 주체인 동물이 있다. 그런 존재는 내재적 가치를 지닌다. 또한, 삶의 주체가 아닌 생물도 문화적 가치, 사용 가치 등 나름의 가치를 지닐 수 있다.'),
    (gen_random_uuid()::text, set_id, 47, '레건', '레건은 인간은 동물 종에 대한 직접적 의무를 실천해야 한다고 주장한다.', false, '레건은 개체론의 관점에서 개체 하나하나에 대한 의무를 인정한다. 동물 종에 대한 의무는 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 48, '레건', '레건은 인간은 살아 있는 모든 존재를 도덕적으로 존중해야 한다고 주장한다.', false, '살아 있는 모든 존재를 도덕적으로 존중해야 한다고 보는 것은 생명 중심주의와 생태 중심주의이다. 레건이 도덕적 고려 대상으로 여기는 존재는 자신의 삶을 영위할 능력을 가진 삶의 주체이다.'),
    (gen_random_uuid()::text, set_id, 49, '레건', '레건은 인간만이 아니라 동물도 권리를 지닌 존재일 수 있다고 주장한다.', true, '레건은 삶의 주체인 존재가 도덕적으로 대우받을 권리를 갖는다고 보는데, 삶의 주체인 존재에는 인간과 일부 동물이 포함된다.'),
    (gen_random_uuid()::text, set_id, 50, '레건', '레건은 어떤 개체가 생명을 지녀야만 도덕적 지위를 지닐 수 있다고 주장한다.', true, '레건이 인정하는 도덕적 지위를 지닌 존재는 삶의 주체인 존재이다. 삶의 주체인 존재이려면 생명을 지녀야 한다.'),
    (gen_random_uuid()::text, set_id, 51, '레건', '레건은 동물은 인간의 가치 평가에서 독립적인 가치를 지닐 수 없다고 주장한다.', false, '동물 중에 삶의 주체인 동물은 인간의 가치 평가에서 독립적인 가치, 예를 들어, 내재적 가치를 지닌다.'),
    (gen_random_uuid()::text, set_id, 52, '레건', '레건은 인간에 대한 인간의 의무로 환원되지 않는 의무가 있다고 주장한다.', true, '레건의 경우, 삶의 주체인 동물에 대한 의무는 인간에 대한 인간의 의무로 환원되지 않는 의무이다.'),
    (gen_random_uuid()::text, set_id, 53, '레건', '레건은 쾌고 감수 능력은 어떤 개체가 도덕적 지위를 갖는지 판단할 때 고려해야 할 조건이 아니라고 주장한다.', false, '레건은 어떤 개체가 도덕적 지위를 갖는지 판단하기 위해 삶의 주체 기준을 제시한다. 삶의 주체 기준에는 쾌고 감수 능력이 포함된다.'),
    (gen_random_uuid()::text, set_id, 54, '레건', '레건은 어떤 생명체와 비교하든 인간이 본질적으로 우월하지는 않다고 주장한다.', false, '레건은 내재적 가치를 갖지 않는 생명체와 비교하면 내재적 가치를 갖는 인간이 본질적으로 우월하다고 볼 것이다.'),
    (gen_random_uuid()::text, set_id, 55, '레건', '레건은 개체의 선에 우선하는 생명 공동체의 선은 존재할 수 없다고 주장한다.', true, '레건은 개체론자로서, 개체의 선을 중요시한다. 생명 공동체의 선은 아예 도덕적 고려의 대상이 아니다.'),
    (gen_random_uuid()::text, set_id, 56, '레건', '레건은 인간이 생명 공동체에 개입하는 것이 정당화되는 경우가 있다고 주장한다.', true, '레건은 우리가 생명 공동체의 구성원들이 자유로울 권리를 보호한다면, 생명 공동체에 개입하지 않아도 자연히 공동체는 보존될 것이라는 자유방임적 태도에 찬성한다. 레건의 입장에서 생명 공동체나 생태계에 대한 불간섭의 의무는 없다.'),
    (gen_random_uuid()::text, set_id, 57, '레건', '레건은 비도구적 가치를 지닌 비이성적 존재를 수단으로 사용하는 것은 어떠한 경우에도 정당화될 수 없다고 주장한다.', false, '레건은 삶의 주체인 존재가 인간의 가치 평가에 독립적이면서도 비도구적인 가치인 내재적 가치를 가진다고 본다. 레건은 목적적 존재를 목적으로 대우한다는 조건 아래, 수단으로 사용하는 것은 정당화된다.'),
    (gen_random_uuid()::text, set_id, 58, '레건', '레건은 인간 존엄성을 훼손할 가능성이 동물 학대 금지의 근거라고 주장한다.', false, '레건은 동물이 내재적 가치를 가진 존재로서 존중의 대우를 받을 권리가 있다고 보았다. 레건의 입장에서 동물 학대는 동물의 내재적 가치를 존중하지 않는 행위이고, 동물의 가치와 권리를 부정하는 행위이기 때문에 금지되어야 한다.'),
    (gen_random_uuid()::text, set_id, 59, '레건', '레건은 생태계의 구성원만이 도덕적 지위를 지닌 존재가 될 수 있는 것은 아니라고 주장한다.', false, '전 지구를 면적으로 하는 생태계에서는 인간을 포함한 모든 생명체와 무생물이 생태계의 구성원이다. 즉, 레건의 입장에서 도덕적 지위를 지닌, 인간 및 동물은 모두 생태계의 구성원인 것이다.'),
    (gen_random_uuid()::text, set_id, 60, '레건', '레건은 수단으로만 이용되어선 안 되는 존재는 도덕적 의무의 대상이 될 수 있다고 주장한다.', true, '레건의 입장에서 수단으로만 이용되어선 안 되는 존재는 삶의 주체이다. 그리고 삶의 주체는 도덕적 의무의 대상이다.'),
    (gen_random_uuid()::text, set_id, 61, '싱어', '싱어는 인간에게는 생명 공동체에 대한 불간섭의 의무가 있다고 주장한다.', false, '개체론자로 분류되는 싱어는 쾌고 감수 능력을 지닌 개체에 대한 의무를 인정하지만, 생명 공동체에 대한 의무를 주장하지는 않는다.'),
    (gen_random_uuid()::text, set_id, 62, '싱어', '싱어는 개체는 쾌고 감수 능력을 지녀야만 도덕적 지위를 갖는다고 주장한다.', true, '싱어는 공리주의자로서 도덕적 지위를 갖기 위해 쾌고 감수 능력이 필요하다고 보기 때문에 해당 선지는 싱어의 입장에서 옳다. 싱어의 입장에서 쾌고 감수 능력은 도덕적 지위를 갖기 위한 필요충분조건이다.'),
    (gen_random_uuid()::text, set_id, 63, '싱어', '싱어는 삶의 주체인 동물의 권리를 의무론의 관점에서 존중해야 한다고 주장한다.', false, '레건의 주장으로 적절한 선지이다. 레건은 삶의 주체의 권리를 모두 의무론의 관점에서 존중해야 한다고 본다. 그런데 싱어는 의무론이 아니라 공리주의의 관점에서 쾌고 감수 능력을 지닌 존재를 존중해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 64, '싱어', '싱어는 자연물을 파괴하는 인간의 행위가 도덕적으로 허용될 수 있다고 주장한다.', true, '자연물을 파괴하는 행위 자체는 해당 자연물이 고통을 느낄 수 있는 존재가 아닌 한 도덕적으로 비난받을 일이 아니다. 싱어에 따르면 도덕적 고려의 대상이 되는 것은 쾌고감수능력을 가진 존재이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 65, '싱어', '싱어는 도덕적 행위 주체성은 도덕적 지위 결정의 유일한 요인이라고 주장한다.', false, '싱어는 자율적 도덕적 행위 능력과는 무관하게, 쾌고 감수 능력의 여부에 따라 도덕적 지위가 부여되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 66, '싱어', '싱어는 자율적 행위 능력과 무관하게 도덕적 지위는 부여되어야 한다고 주장한다.', true, '싱어는 자율적 도덕적 행위 능력과는 무관하게, 쾌고 감수 능력의 여부에 따라 도덕적 지위가 부여되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 67, '싱어', '싱어는 동물의 고통에 대한 동정심은 도덕적 의무에 어긋나지 않는다고 주장한다.', true, '싱어는 동정심 그 자체를 부정하지 않으며, 동물의 고통에 공감하는 태도가 도덕적 의무와 상충한다고 보지 않는다. 다만 주의할 것은, 동정심이 동물에 대한 의무의 근거는 아니라는 것이다.'),
    (gen_random_uuid()::text, set_id, 68, '싱어', '싱어는 동물 학대가 그릇된 근본 이유는 인간성 실현을 저해함에 있다고 주장한다.', false, '싱어 관점에서 동물 학대가 잘못된 근본 이유는 인간성 실현 저해가 아니라, 동물 학대는 고통을 느끼는 존재에게 정당한 이유 없이 고통을 초래함으로써 그 존재의 이익을 부당하게 침해한다는 점에 있다.'),
    (gen_random_uuid()::text, set_id, 69, '싱어', '싱어는 대지 공동체 자체가 지닌 도덕적 지위를 인정해야 한다고 주장한다.', false, '싱어는 개체주의적 관점에서 인간 중심주의에서 벗어나, 쾌고 감수 능력을 가진 개체들을 도덕적 고려 대상으로 존중할 것을 주장한다. 대지 공동체의 도덕적 지위는 인정하지 않는다.'),
    (gen_random_uuid()::text, set_id, 70, '싱어', '싱어는 개체주의적 관점을 지양하고 인간 중심주의에서 벗어나야 한다고 주장한다.', false, '싱어는 개체주의적 관점에서 인간 중심주의에서 벗어나, 쾌고 감수 능력을 가진 개체들을 도덕적 고려 대상으로 존중할 것을 주장한다.'),
    (gen_random_uuid()::text, set_id, 71, '싱어', '싱어는 종의 차이만으로 도덕적 지위에 차별을 두어서는 안 된다고 주장한다.', true, '싱어는 종의 차이만으로 도덕적 지위에 차별을 두는 것을 종차별주의라고 비판한다. 쾌락을 늘리고, 고통을 최소화하는 것을 도덕적으로 보는 공리주의의 입장에서 싱어는 쾌고 감수 능력을 기준으로 도덕적 지위를 구별하는 것이다. 즉, 싱어는 쾌고 감수 능력을 지닌 존재는 모두 동등한 도덕적 지위를 지닌다고 본다.'),
    (gen_random_uuid()::text, set_id, 72, '싱어', '싱어는 쾌고 감수 능력이 있는 모든 존재에 대한 종차별주의는 부당하다고 주장한다.', true, '싱어는 종의 차이만으로 도덕적 지위에 차별을 두는 것을 종차별주의라고 비판한다.'),
    (gen_random_uuid()::text, set_id, 73, '싱어', '싱어는 고통을 느낄 수 있는 모든 생명체를 동일하게 대우해야 한다고 주장한다.', false, '동일 대우는 싱어 문항에서 함정으로 자주 나오는 소재이다. 싱어가 주장한 이익 평등 고려의 원칙은 각 존재가 공통으로 가지는 이익을 종 차이에 따라 차등을 두지 않고 똑같이 중요한 것으로 고려한다는 의미이다.'),
    (gen_random_uuid()::text, set_id, 74, '싱어', '싱어는 평등의 원리에 따라 인간과 모든 동물을 동일하게 대우해야 한다고 주장한다.', false, '동일 대우, 동등 대우는 싱어의 입장이 아니다. 싱어가 주장한 이익 평등 고려의 원칙은 각 존재가 공통으로 가지는 이익을 종 차이에 따라 차등을 두지 않고 똑같이 중요한 것으로 고려한다는 의미이며, 이익의 내용이나 정도가 다른 경우 구체적 처우는 달라질 수 있다.'),
    (gen_random_uuid()::text, set_id, 75, '싱어', '싱어는 인간은 생명체에 끼친 해악에 대한 보상적 정의의 의무를 지닌다고 주장한다.', false, '뒤에서 배울 테일러의 주장으로 적절한 선지이다. 싱어는 보상적 정의의 의무에 대해서는 주장한 바가 없다.'),
    (gen_random_uuid()::text, set_id, 76, '싱어', '싱어는 동물에게 해를 끼치는 행위가 정당화되는 경우가 있다고 주장한다.', true, '싱어는 공리주의자로서 어떠한 행동이 절대적으로 금지되는 경우는 없으며, 어떤 행동이 공리의 원리에 부합할 경우, 정당화될 수 있다고 본다. 가령, 싱어는 동물의 고통이 최소화되는 한에서 동물 실험이 허용될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 77, '싱어', '싱어는 자연을 경제적 관점에서 이용하는 것이 허용될 수 있다고 주장한다.', true, '싱어는 자연은 쾌고를 느낄 수 있는 어떤 한 개체가 아니기 때문에 싱어의 입장에서는 도덕적 고려 대상이 아니다. 또한 그는 공리주의자로서 자연을 경제적 관점에서 이용하는 것을 허용할 것이다. 하지만, 그 과정에서 도덕적 고려 대상인 인간과 동물에게 끼칠 이익과 고통을 함께 고려해야 한다.'),
    (gen_random_uuid()::text, set_id, 78, '싱어', '싱어는 이성적 능력을 기준으로 도덕적 지위가 결정되지는 않는다고 주장한다.', true, '도덕적 고려를 받아야 할 존재는 직접적인 도덕적 의무의 대상인 도덕적 지위를 지닌 존재이다. 싱어는 쾌고 감수 능력을 도덕적 지위 결정 근거로 보고, 도덕적 지위를 지닌 존재의 범위를 쾌고 감수 능력을 지닌 존재로 한정했다. 그런 존재에는 인간과 일부 동물이 속한다.'),
    (gen_random_uuid()::text, set_id, 79, '싱어', '싱어는 직접적인 도덕적 의무의 대상은 인간에만 한정되지 않는다고 주장한다.', true, '도덕적 고려를 받아야 할 존재는 직접적인 도덕적 의무의 대상인 도덕적 지위를 지닌 존재이다. 싱어는 쾌고 감수 능력을 도덕적 지위 결정 근거로 보고, 도덕적 지위를 지닌 존재의 범위를 쾌고 감수 능력을 지닌 존재로 한정했다. 그런 존재에는 인간과 일부 동물이 속한다.'),
    (gen_random_uuid()::text, set_id, 80, '싱어', '싱어는 인간 아닌 감각 없는 개체 중 도덕적 지위를 지닌 존재는 없다고 주장한다.', true, '도덕적 고려를 받아야 할 존재는 직접적인 도덕적 의무의 대상인 도덕적 지위를 지닌 존재이다. 싱어는 쾌고 감수 능력을 도덕적 지위 결정 근거로 보고, 도덕적 지위를 지닌 존재의 범위를 쾌고 감수 능력을 지닌 존재로 한정했다.'),
    (gen_random_uuid()::text, set_id, 81, '싱어', '싱어는 쾌고 감수 능력의 보유 여부에 의해 개체의 도덕적 지위가 결정된다고 주장한다.', true, '도덕적 고려를 받아야 할 존재는 직접적인 도덕적 의무의 대상인 도덕적 지위를 지닌 존재이다. 싱어는 쾌고 감수 능력을 도덕적 지위 결정 근거로 보고, 도덕적 지위를 지닌 존재의 범위를 쾌고 감수 능력을 지닌 존재로 한정했다.'),
    (gen_random_uuid()::text, set_id, 82, '싱어', '싱어는 도덕적 지위를 지닌 존재의 범위를 모든 생명체로 설정하는 것은 부적절하다고 주장한다.', true, '도덕적 고려를 받아야 할 존재는 직접적인 도덕적 의무의 대상인 도덕적 지위를 지닌 존재이다. 싱어는 쾌고 감수 능력을 도덕적 지위 결정 근거로 보고, 도덕적 지위를 지닌 존재의 범위를 쾌고 감수 능력을 지닌 존재로 한정했다.'),
    (gen_random_uuid()::text, set_id, 83, '싱어', '싱어는 동물에 대한 인간의 행위는 공리의 원리에 근거해야 한다고 주장한다.', true, '공리의 원리란 모든 행위에 관해 의해 그 행위에 영향받는 개별 존재의 행복을 증진 혹은 감소하느냐에 따라 좋다거나 혹은 나쁘다고 평가하는 원리이다. 싱어는 공리의 원리에 따라 동물을 도덕적으로 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 84, '싱어', '싱어는 공리의 원리는 동물을 도덕적으로 고려해야 할 근거가 아니라고 주장한다.', false, '공리의 원리란 모든 행위에 관해 의해 그 행위에 영향받는 개별 존재의 행복을 증진 혹은 감소하느냐에 따라 좋다거나 혹은 나쁘다고 평가하는 원리이다. 싱어는 공리의 원리에 따라 동물을 도덕적으로 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 85, '싱어', '싱어는 인간은 생명체를 해치지 않을 절대적 의무를 실천해야 한다고 주장한다.', false, '싱어는 쾌고 감수 능력이 없는 생명체에 대해서는 도덕적으로 고려할 것이 없다고 본다. 그리고, 쾌고 감수 능력이 있는 생명체에 대해서도 인간이 절대적 의무를 가진다고 보지는 않는다.'),
    (gen_random_uuid()::text, set_id, 86, '싱어', '싱어는 고통을 느끼는 모든 존재가 존속할 권리를 갖는 것은 아니라고 주장한다.', true, '싱어는 쾌고 감수 능력을 지닌 존재 중 미래에 대한 욕망을 가질 수 없는 존재의 경우는 생명권을 가질 수 없다. 즉, 싱어는 쾌고 감수 능력을 지닌 모든 존재의 동등한 생명권을 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 87, '싱어', '싱어는 인간에 대한 의무의 근거가 동물에 대한 의무를 정당화할 수 있다고 주장한다.', true, '싱어는 어떤 존재를 도덕적으로 고려해야 할 의무를 주장할 때, 그 근거로 그들의 쾌고 감수 능력을 꼽았다. 인간에 대한 의무의 근거는 쾌고 감수 능력이고, 쾌고 감수 능력이 동물에 대한 의무를 정당화하기 때문에 이 선지는 싱어 입장에 부합한다.'),
    (gen_random_uuid()::text, set_id, 88, '싱어', '싱어는 종이 다른 개체를 서로 다르게 대우하는 것이 정당화될 수 있다고 주장한다.', true, '서로 다른 이익 관심을 가진 개체를 서로 다르게 대우해야 한다고 보는 것은 싱어의 대표 주장이다. 싱어가 주장하는 것은 이익 평등 고려이지, 동일 등등 평등 대우가 아니다.'),
    (gen_random_uuid()::text, set_id, 89, '싱어', '싱어는 모든 동물에게 인간과 동등한 도덕적 지위를 부여하는 것은 옳지 않다고 주장한다.', true, '쾌고 감수 능력을 지닌 존재만의 동등한 도덕적 지위를 인정하는 싱어의 입장에서는 모든 동물에게 인간과 동등한 도덕적 지위를 부여하는 것은 옳지 않은 것이다.'),
    (gen_random_uuid()::text, set_id, 90, '싱어', '싱어는 어떤 존재가 생명을 지닌 개체가 아니어도 도덕적 지위를 가질 수 있다고 주장한다.', false, '싱어가 동의하지 않을 입장이다. 싱어는 생명을 지닌 개체 중 쾌고 감수 능력을 가진 개체가 도덕적 지위를 가질 수 있다고 본다. 생명을 지닌 개체가 아니면 쾌고 감수 능력도 가질 수 있는 가능성이 전혀 없기 때문에, 도덕적 지위를 가질 수 없다.'),
    (gen_random_uuid()::text, set_id, 91, '테일러', '테일러는 생태계의 선이 개체의 선보다 우선하는 것은 아니라고 주장한다.', true, '개체론자인 테일러의 입장에서는 개별 생명체만이 도덕적 고려 대상이며, 도덕적 행위자로서 인간은 개별 생명체의 고유한 선을 보호할 의무를 가진다. 테일러의 입장에서 개체의 선에 우선하는 생태계나 생명 공동체의 선은 존재할 수 없다.'),
    (gen_random_uuid()::text, set_id, 92, '테일러', '테일러는 생명 공동체 자체가 지닌 고유의 선을 고려해야 한다고 주장한다.', false, '개체론자인 테일러의 입장에서는 개별 생명체만이 도덕적 고려 대상이며, 생태계나 생명 공동체는 고유의 선을 가질 수 없다. 왜냐하면, 테일러에 따르면, 생명 공동체의 선은 통계적 개념으로, 개별 구성원의 선의 분포의 중간값에서 결정되는 것이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 93, '테일러', '테일러는 도덕적 고려의 대상을 인간으로 한정하지 말아야 한다고 주장한다.', true, '테일러는 인간만이 도덕적 고려의 대상이 될 수 있다는 인간 중심주의를 비판하고, 모든 생명체를 도덕적 고려의 대상으로 삼아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 94, '테일러', '테일러는 윤리적 고려의 대상을 무생물에게까지 확대하지 않는다고 주장한다.', true, '테일러의 생명 중심주의는 살아 있는 존재를 도덕적 존중의 대상으로 삼는다. 광물, 물 등 무생물은 생명체가 아니므로 고유한 선을 지니지 않으며, 고유한 선을 지니지 않은 대상에 대해서는 도덕적으로 고려할 것이 없다.'),
    (gen_random_uuid()::text, set_id, 95, '테일러', '테일러는 개체의 선에 우선하는 생명 공동체의 선은 존재할 수 없다고 주장한다.', true, '개체론자인 테일러의 입장에서는 개별 생명체만이 도덕적 고려 대상이며, 테일러의 입장에서 개체의 선에 우선하는 생태계나 생명 공동체의 선은 존재할 수 없다.'),
    (gen_random_uuid()::text, set_id, 96, '테일러', '테일러는 생명 공동체의 온전함이 개별 생명체의 존속보다 중요하다고 주장한다.', false, '개체론자인 테일러의 입장에서는 개별 생명체만이 도덕적 고려 대상이며, 도덕적 행위자로서 인간은 개별 생명체의 고유한 선을 보호할 의무를 가진다.'),
    (gen_random_uuid()::text, set_id, 97, '테일러', '테일러는 자연 자체의 선은 개체의 희생을 정당화하는 근거가 아니라고 주장한다.', true, '테일러는 자연 자체의 고유한 선이 있다고 보지 않을 뿐더러, 자연의 선, 예를 들면 자연 보호가 개체의 희생을 정당화한다고 보지도 않는다. 자연을 보호해야 한다면, 그것은 결국 개별 생명체 각각의 선을 존중하기 때문이지, 자연 자체의 선때문이 아니다.'),
    (gen_random_uuid()::text, set_id, 98, '테일러', '테일러는 생명체 각각이 지닌 고유한 선은 보호되고 증진되어야 한다고 주장한다.', true, '테일러의 핵심 주장 중 하나가 바로 모든 생명체가 지닌 고유한 선을 존중해야 한다는 것이다.'),
    (gen_random_uuid()::text, set_id, 99, '테일러', '테일러는 종의 차이만으로 도덕적 지위에 차별을 두어서는 안 된다고 주장한다.', true, '테일러의 입장에서는 곤충이든 식물이든 인간이든, 살아 있는 모든 존재에 도덕적 지위를 부여한다. 종이 다르다는 이유만으로 도덕적 지위를 차별하면 안 된다.'),
    (gen_random_uuid()::text, set_id, 100, '테일러', '테일러는 개체론적 관점에서 도덕적 고려 대상의 범주를 설정해야 한다고 주장한다.', true, '테일러는 종 단위나 생태계 전체보다는 개체에 초점을 둔 도덕 이론을 제시한다. 즉, 도덕적 고려의 단위가 개별 생명체라는 점이 그의 생명 중심주의의 특징이다.'),
    (gen_random_uuid()::text, set_id, 101, '테일러', '테일러는 인간이 생명 공동체에 개입하는 것이 정당화되는 경우가 있다고 주장한다.', true, '테일러는 불간섭의 의무를 통해 생명 공동체에 개입하지 않을 의무를 주장했다. 그렇지만 이러한 의무는 어떤 상황에서도 그런 행동을 결코 해서는 안 된다는 의미는 아니다. 그것은 우리의 의무를 무시하는 행동을 정당화하는 타당한 도덕적 이유 없이 그런 행동을 해서는 안 된다는 뜻이다.'),
    (gen_random_uuid()::text, set_id, 102, '테일러', '테일러는 인간이 어떠한 생명체보다도 본래적으로 우월한 존재는 아니라고 주장한다.', true, '테일러는 모든 생명체가 본래적(내재적) 가치와 도덕적 지위를 지니는 동등한 존재라고 본다.'),
    (gen_random_uuid()::text, set_id, 103, '테일러', '테일러는 도덕적 행위 능력이 있어야만 도덕적 존중의 대상이 되는 것은 아니라고 주장한다.', true, '테일러는 생명 중심적 관점에서 모든 생명체가 본래적 가치를 가진다고 본다. 따라서 도덕적 행위 능력과 상관없이 모든 생명체는 도덕적 존중의 대상이 된다.'),
    (gen_random_uuid()::text, set_id, 104, '테일러', '테일러는 쾌고 감수 능력은 어떤 개체가 도덕적 지위를 갖는지 판단할 때 고려해야 할 조건이 아니라고 주장한다.', true, '테일러의 생명 중심주의는 생명체는 모두 도덕적 지위를 지닌다고 본다. 식물처럼 쾌·고 감수 능력이 없다고 추정되는 존재도 예외 없이 존중받아야 한다.'),
    (gen_random_uuid()::text, set_id, 105, '테일러', '테일러는 비도구적 가치를 지닌 비이성적 존재를 수단으로 사용하는 것은 어떠한 경우에도 정당화될 수 없다고 주장한다.', false, '테일러는 모든 생명체가 본래적(내재적, 비도구적) 가치를 지닌다고 주장하지만, 실제 삶에서 필연적으로 일어나는 이해관계 충돌 때문에 생명체를 이용하는 것이 불가피할 수 있음을 인정한다. 다만 그 경우에도 언제나 해당 존재의 본래적 가치를 존중하며, 최소 잘못의 원칙이나 보상적 정의의 의무 등의 제약 하에서 정당화된다고 본다.'),
    (gen_random_uuid()::text, set_id, 106, '테일러', '테일러는 개체에 대한 도덕적 존중은 내재적 가치에 근거한다고 주장한다.', true, '테일러는 모든 생명체가 그 자체로 내재적 가치를 지니기 때문에 도덕적으로 존중받아야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 107, '테일러', '테일러는 인간을 목적이 아닌 수단으로만 대우해서는 안 된다고 주장한다.', true, '흔히 칸트가 제시한 인간 존엄성의 원리를 연상시키지만, 테일러의 입장에서도 도덕적 고려 대상을 단지 수단으로만 대우해서는 안 된다는 점은 유효하다. 테일러가 칸트의 목적으로서의 가치 개념을 수용한다는 점에서 그렇다.'),
    (gen_random_uuid()::text, set_id, 108, '테일러', '테일러는 인간 상호 간의 의무는 도덕적으로 정당화될 수 있다고 주장한다.', true, '생명 중심주의가 비인간 생명체까지 도덕 고려 범위를 확장했다고 해서, 인간이 서로서로 지는 의무(인간 상호 간의 의무)를 부정하는 것은 아니다. 인간끼리의 의무도 당연히 정당화된다.'),
    (gen_random_uuid()::text, set_id, 109, '테일러', '테일러는 인간에게는 생명 공동체에 대한 불간섭의 의무가 있다고 주장한다.', true, '테일러의 자연 존중의 네 가지 의무 중 불간섭의 의무에 대한 내용이다. 테일러는 불간섭의 의무를 통해 개별 유기체의 자유를 간섭하거나 생태계나 생명 공동체를 조작, 통제, 개조하지 말아야 한다고 주장했다.'),
    (gen_random_uuid()::text, set_id, 110, '테일러', '테일러는 인간에 대한 인간의 의무로 환원되지 않는 의무가 있다고 주장한다.', true, '테일러의 핵심은 인간-인간 간 의무와 별개로, 인간이 비인간 생명체에 직접적으로 부담하는 의무가 있다는 점이다. 즉, 사람끼리의 이익·권익 보장을 위해 생명체를 부수적, 간접적으로 고려할 의무가 아니라, 생명체 자체의 본래적(내재적) 가치로부터 비롯되는 직접적 의무가 있다는 것이다.'),
    (gen_random_uuid()::text, set_id, 111, '테일러', '테일러는 인간이 자연 전체에 대한 직접적 의무를 가진다고 본다고 주장한다.', false, '테일러는 개별 생명체를 도덕적 고려의 직접 대상으로 삼는 개체주의적 관점을 취한다. 자연 전체, 예컨대 생태계나 대자연 자체에 도덕적 지위를 부여하는 것은 레오폴드같은 생태 중심주의에서 흔히 볼 수 있는 주장이다.'),
    (gen_random_uuid()::text, set_id, 112, '테일러', '테일러는 인간과 식물은 내재적 가치를 지닌다는 점에서 동등하다고 주장한다.', true, '테일러에 따르면 모든 생명체는 각자 동등한 본래적(내재적) 가치를 지닌다. 인간이라고 해서 본질적으로 더 높은 본래적 가치나 도덕적 지위가 있는 것이 아니다.'),
    (gen_random_uuid()::text, set_id, 113, '테일러', '테일러는 인간은 생명체를 해치지 않을 절대적 의무를 실천해야 한다고 주장한다.', false, '테일러가 생명체를 해치지 않을 의무를 주장하기는 하지만, 그 의무는 무조건적으로 지켜져야 하는 절대적 의무는 아니다.'),
    (gen_random_uuid()::text, set_id, 114, '테일러', '테일러는 도덕적 행위 능력이 없는 존재는 모두 내재적 가치를 지닌다고 주장한다.', false, '도덕적 행위 능력이 없는 존재에는 무생물이 포함된다. 테일러는 무생물은 고유의 선이나 내재적 가치를 지니지 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 115, '테일러', '테일러는 삶의 주체인 동물의 권리를 의무론의 관점에서 존중해야 한다고 주장한다.', false, '삶의 주체라는 표현은 레건의 동물권 이론에서 등장하는 개념이다. 레건은 권리론적, 의무론적 입장에서 삶의 주체의 본래적 가치와 권리를 강조한다.'),
    (gen_random_uuid()::text, set_id, 116, '테일러', '테일러는 인간은 생명체에 끼친 해악에 대한 보상적 정의의 의무를 지닌다고 주장한다.', true, '테일러는 네 가지 기본 의무 중 하나로 보상적 정의의 의무를 제시한다. 인간이 어쩔 수 없이 다른 생명체에 해를 끼쳤다면(인간 생존이나 필수 활동) 그 피해를 보상하기 위해 노력해야 한다는 것이다.'),
    (gen_random_uuid()::text, set_id, 117, '테일러', '테일러는 인간에 대한 의무의 근거가 동물에 대한 의무를 정당화할 수 있다고 주장한다.', true, '테일러는 어떤 존재를 도덕적으로 고려해야 할 의무를 주장할 때, 그 근거로 그들의 내재적 가치를 꼽았다. 이 개념을 이 선지에 적용시키면, 인간에 대한 의무의 근거는 내재적 가치이고, 내재적 가치가 동물에 대한 의무를 정당화하기 때문에, 이 선지는 테일러 입장에 부합한다.'),
    (gen_random_uuid()::text, set_id, 118, '테일러', '테일러는 어떤 생명체의 존속은 그 생명체의 본래적 가치에 의해 정당화된다고 주장한다.', true, '테일러는 생명체의 선(생명 유지, 즉 존속)을 존중할 의무는 생명체가 본래적(내재적) 가치를 갖고 있기 때문에 성립한다고 본다.'),
    (gen_random_uuid()::text, set_id, 119, '테일러', '테일러는 수단으로만 이용되어선 안 되는 존재는 도덕적 의무의 대상이 될 수 있다고 주장한다.', true, '테일러는 모든 생명체가 본래적 가치를 지니며 수단으로만 이용되어선 안 된다고 본다. 또한 모든 생명체는 도덕적 의무의 대상이다.'),
    (gen_random_uuid()::text, set_id, 120, '테일러', '테일러는 인간이 아닌 생명체에 대한 해악 금지 의무는 그 생명체의 내재적 가치에 근거한다고 주장한다.', true, '생명체에 대한 해악 금지 의무는 그 생명체의 내재적(본래적) 가치에 근거한다.'),
    (gen_random_uuid()::text, set_id, 121, '레오폴드', '레오폴드는 동물을 자원으로 사용하는 것이 금지되지는 않는다고 주장한다.', true, '레오폴드는 대지 윤리가 인간에게 자원들(흙, 물, 식물, 동물 등)의 사용, 관리 혹은 변화를 금지할 수는 없지만, 대지 공동체를 구성하는 자연물이 사라지거나 멸종하지 않고 존속할 수 있어야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 122, '레오폴드', '레오폴드는 인간은 생태계에 간섭해서는 안 되는 의무를 지닌다고 주장한다.', false, '레오폴드는 불간섭의 의무를 주장하지 않고, 테일러가 불간섭의 의무를 주장한다.'),
    (gen_random_uuid()::text, set_id, 123, '레오폴드', '레오폴드는 인간은 토지를 단지 자원으로만 이용해서는 안 된다고 주장한다.', true, '레오폴드에 따르면 인간은 토지를 사랑과 존중의 대상으로 보아야 한다. 즉, 레오폴드는 토지를 수단이나 자원으로 이용할 수는 있지만, 생태학적 도덕 의식을 가지고 책임감 있게 사용해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 124, '레오폴드', '레오폴드는 동물에게 해를 끼치는 행위가 정당화되는 경우가 있다고 주장한다.', true, '레오폴드의 대지 윤리에서 행위의 옳고 그름은 단지 개별 동물에게 해를 끼치는지 여부가 아니라, 그 행위가 생명 공동체 전체의 온전성, 안정성, 아름다움을 유지하고 증진하는지에 따라 판단된다. 레오폴드는 생태계 전체의 유기적 관계와 균형을 위해서 개체를 사냥해야 하는 경우가 존재함을 인정한다.'),
    (gen_random_uuid()::text, set_id, 125, '레오폴드', '레오폴드는 자연을 경제적 관점에서 이용하는 것이 허용될 수 있다고 주장한다.', true, '레오폴드는 대지를 경제적 관점에서 이용할 수 있지만, 경제적 관점만이 아니라 윤리적 관점에서도 고찰해야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 126, '레오폴드', '레오폴드는 대지 공동체 자체가 지닌 도덕적 지위를 인정해야 한다고 주장한다.', true, '레오폴드는 토양, 물, 식물, 동물로 이루어진 공동체 자체가 도덕적으로 고려되어야 한다고 보았다. 한편, 테일러와 레오폴드의 생명 공동체는 정의가 약간 다르다는 것에 주의하자. 테일러의 생명 공동체는 생명체들의 공동체인데, 레오폴드는 이를 대지 공동체로 확장했다. 이는 대지의 무생물도 생명 공동체에 포함된다는 것이다.'),
    (gen_random_uuid()::text, set_id, 127, '레오폴드', '레오폴드는 인간 간의 의무를 넘어선 새로운 도덕 원리가 요청된다고 주장한다.', true, '레오폴드는 기존의 인간 중심적 윤리에서 벗어나 자연을 포함한 더 넓은 공동체에 대한 윤리 의식이 필요하다고 주장했다. 이는 곧 인간 간의 의무를 넘어선, 대지 공동체 전체에 대한 새로운 윤리이다.'),
    (gen_random_uuid()::text, set_id, 128, '레오폴드', '레오폴드는 인간은 동물 종에 대한 직접적 의무를 실천해야 한다고 주장한다.', true, '전일론은 전체로서의 자연환경, 종과 생태계의 보전에 초점을 맞추는 견해이다. 레오폴드는 전일론의 관점에서 종에 대한 의무, 자연 전체에 대한 의무를 주장한다.'),
    (gen_random_uuid()::text, set_id, 129, '레오폴드', '레오폴드는 자신 이외의 존재에 대한 도덕적 의무는 성립 불가능하다고 주장한다.', false, '레오폴드는 인간이 아닌 동식물이나 자연의 무생물, 자연 그 자체에 대한 도덕적 의무가 성립한다고 주장했다.'),
    (gen_random_uuid()::text, set_id, 130, '레오폴드', '레오폴드는 인간은 자연 전체에 대해 직접적인 도덕적 의무를 지닌다고 주장한다.', true, '전일론은 전체로서의 자연환경, 종과 생태계의 보전에 초점을 맞추는 견해이다. 레오폴드는 전일론의 관점에서 종에 대한 의무, 자연 전체에 대한 의무를 주장한다.'),
    (gen_random_uuid()::text, set_id, 131, '레오폴드', '레오폴드는 인간이 생명 공동체에 개입하는 것이 정당화되는 경우가 있다고 주장한다.', true, '레오폴드는 불간섭의 의무를 주장하지 않고, 테일러가 불간섭의 의무를 주장한다. 레오폴드는 정부에 의한 숲, 토지, 철새 관리 등을 예로 들며 자연 보전 활동에 대한 정부의 역할과 개인의 자연 보전 활동을 지지한다.'),
    (gen_random_uuid()::text, set_id, 132, '레오폴드', '레오폴드는 인간은 생명체에 끼친 해악에 대한 보상적 정의의 의무를 지닌다고 주장한다.', false, '테일러만의 입장에 해당한다. 테일러만이 보상적 정의의 의무를 주장한다. 보상적 정의의 의무는 우리가 어떤 생명체를 부당하게 대우했을 때, 깨어진 정의의 균형을 회복하기 위해 그 생명체에게 보상을 해야 하는 의무를 말하는 것이다.'),
    (gen_random_uuid()::text, set_id, 133, '레오폴드', '레오폴드는 생태계뿐만 아니라 개별 생명체도 도덕적 고려의 대상일 수 있다고 주장한다.', true, '레오폴드는 대지 공동체를 구성하는 각 개별 생명체도 도덕적 고려 대상으로 보았다.'),
    (gen_random_uuid()::text, set_id, 134, '레오폴드', '레오폴드는 어떤 존재가 생명을 지닌 개체가 아니어도 도덕적 지위를 가질 수 있다고 주장한다.', true, '레오폴드의 관점에서 토양, 물 같은 무생물적 요소도 대지 공동체를 구성하는 중요한 부분이다. 따라서 생명을 지니지 않아도 공동체의 일원으로서 도덕적 지위를 가질 수 있다.'),
    (gen_random_uuid()::text, set_id, 135, '레오폴드', '레오폴드는 비도구적 가치를 지닌 비이성적 존재를 수단으로 사용하는 것은 어떠한 경우에도 정당화될 수 없다고 주장한다.', false, '레오폴드는 대지 공동체가 내재적 가치를 가진다고 보지만, 이용 자체를 금지하지는 않는다. 레오폴드는 생명 공동체 전체의 온전성, 안정성, 아름다움을 유지하고 증진한다면, 개체를 수단으로 이용하는 것을 허용한다.'),
    (gen_random_uuid()::text, set_id, 136, '레오폴드', '레오폴드는 자연의 모든 존재가 도덕적 가치를 지닌다고 주장한다.', true, '레오폴드는 자연 전체와 그 구성원을 도덕적 고려 대상으로 보았다. 즉, 자연을 구성하는 모든 존재(동물·식물·토양·물 등)는 도덕적으로 고려받을 가치가 있는 존재라는 것이다.'),
    (gen_random_uuid()::text, set_id, 137, '레오폴드', '레오폴드는 윤리적 고려의 대상을 무생물에게까지 확대한다고 주장한다.', true, '레오폴드는 토양·물·돌 같은 무생물도 생태계의 일부로서 윤리적 고려의 대상으로 포함해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 138, '레오폴드', '레오폴드는 생태계의 선이 개체의 선보다 우선하는 것은 아니라고 주장한다.', false, '레오폴드는 전체론자이므로, 전체로서 생명 공동체를 개별 구성원보다 중요시, 우선시한다.'),
    (gen_random_uuid()::text, set_id, 139, '레오폴드', '레오폴드는 인간은 다른 모든 생명체보다 본질적으로 우월하지 않다고 주장한다.', true, '레오폴드는 대지 위의 모든 존재는 평등한 구성원이라고 보았다. 흙, 물, 식물, 동물, 인간을 포함하는 생명 공동체는 생명적 성질을 지니며, 인간은 생명 공동체의 지배자가 아니며, 대지 위의 모든 존재는 평등한 구성원이다.'),
    (gen_random_uuid()::text, set_id, 140, '레오폴드', '레오폴드는 생명체들의 가치보다 생명 공동체의 가치가 더 중요하다고 주장한다.', true, '레오폴드는 전체론자이므로, 전체로서 생명 공동체를 개별 구성원보다 중요시, 우선시한다. 대지 윤리는 생명 공동체 자체에 대한 존중을 촉구할 뿐만 아니라 그 공동체의 개별 구성원에 대한 존중을 공동체 전체의 통합성, 안정성 및 아름다움의 보전에 종속시키고 있다.'),
    (gen_random_uuid()::text, set_id, 141, '레오폴드', '레오폴드는 개체의 선에 우선하는 생명 공동체의 선은 존재할 수 없다고 주장한다.', false, '레오폴드는 전체론자이므로, 전체로서 생명 공동체를 개별 구성원보다 중요시, 우선시한다.'),
    (gen_random_uuid()::text, set_id, 142, '레오폴드', '레오폴드는 생명 공동체의 온전함이 개별 생명체의 존속보다 중요하다고 주장한다.', true, '레오폴드는 생태계의 온전성, 안정성, 아름다움을 핵심 가치로 제시했다. 필요하다면 일부 개체의 희생을 감수하더라도 공동체의 건강을 유지하는 것이 더 중요하다는 입장이다.'),
    (gen_random_uuid()::text, set_id, 143, '레오폴드', '레오폴드는 쾌고 감수 능력은 동물의 이익 고려를 위한 충분조건이라고 주장한다.', false, '어떤 동물이 쾌고 감수 능력이 있으면, 그 동물의 이익을 고려해야 한다고 보는 것은 싱어의 입장이다. 레오폴드는 쾌고 감수 능력을 동물의 이익 고려를 위한 조건으로 제시하지 않는다.'),
    (gen_random_uuid()::text, set_id, 144, '레오폴드', '레오폴드는 이성적 능력을 기준으로 도덕적 지위가 결정되지는 않는다고 주장한다.', true, '이성적 능력이나 사유 능력, 도덕적 행위 능력을 기준으로 도덕적 지위를 결정하는 것은 인간 중심주의적 입장이다. 레오폴드는 이성 여부와 무관하게 생태계의 모든 존재가 윤리의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 145, '레오폴드', '레오폴드는 사유 능력 여부로 어떤 존재의 도덕적 지위가 결정되지 않는다고 주장한다.', true, '이성적 능력이나 사유 능력, 도덕적 행위 능력을 기준으로 도덕적 지위를 결정하는 것은 인간 중심주의적 입장이다. 레오폴드는 이성 여부와 무관하게 생태계의 모든 존재가 윤리의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 146, '레오폴드', '레오폴드는 평등의 원리에 따라 인간과 모든 동물을 동일하게 대우해야 한다고 주장한다.', false, '레오폴드는 평등의 원리를 주장하지 않는다. 그리고 인간과 동물을 동일하게 대우한다기보다는, 생태계 속에서 각 존재가 지닌 상호의존성과 역할을 고려해 윤리적 책임을 가져야 한다고 보았다.'),
    (gen_random_uuid()::text, set_id, 147, '레오폴드', '레오폴드는 쾌고 감수 능력이 있는 모든 존재에 대한 종차별주의는 부당하다고 주장한다.', true, '종차별주의에 반대하는 것은 탈인간 중심주의의 공통점이라고 볼 수 있다. 왜냐하면 종차별주의는 인간에게 인간이라는 이유로 도덕적 지위를 부여하고, 인간이 아닌 존재는 인간이 아니라는 이유로 도덕적 지위를 부여하지 않고 차별하는 것을 말하는 것이기 때문이다.'),
    (gen_random_uuid()::text, set_id, 148, '레오폴드', '레오폴드는 도덕적 행위 능력 유무가 도덕적 고려 대상의 설정 근거는 아니라고 주장한다.', true, '이성적 능력이나 사유 능력, 도덕적 행위 능력을 기준으로 도덕적 지위를 결정하는 것은 인간 중심주의적 입장이다. 레오폴드는 이성 여부와 무관하게 생태계의 모든 존재가 윤리의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 149, '레오폴드', '레오폴드는 생태계 안정에 기여하더라도 무생물은 도덕적 고려 대상이 아니라고 주장한다.', false, '레오폴드는 토양·물·바위 등도 생태계의 필수 구성원으로 보고 윤리적 고려 대상으로 삼았다. 무생물이라 하더라도 대지 공동체의 구성원으로서 윤리적 배려에서 배제되어서는 안 된다는 입장이다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '갈퉁', '갈퉁은 폭력의 개념은 공인되지 않은 비합법적인 무력의 사용으로 한정된다고 주장한다.', false, '갈퉁의 입장에서는 합법적으로 승인된 무력이든 비합법적 무력이든, 심지어 무력이 아니든, 사람의 존엄성 생존 발달 자유 등을 제한하거나 해치는 것이라면 모두 폭력의 범주에 포함된다.'),
    (gen_random_uuid()::text, set_id, 2, '갈퉁', '갈퉁은 문화적 폭력은 구조적 폭력을 올바른 것으로 보이게 한다고 주장한다.', true, '갈퉁은 문화적 폭력이 구조적 폭력(빈곤, 차별 등)과 직접적 폭력을 당연하거나 정당한 것으로 보이게 만들기 때문에 더 위험하다고 보았다. 갈퉁은 주로 폭력이 문화적 폭력으로부터 구조적 폭력을 거쳐 직접적 폭력으로 번진다고 보았다.'),
    (gen_random_uuid()::text, set_id, 3, '갈퉁', '갈퉁은 빈곤, 인권 침해 등으로 인간 삶의 질이 저하되는 상태도 폭력이라고 주장한다.', true, '갈퉁은 물리적, 언어적 폭력으로 규정된 직접적 폭력뿐만 아니라, 구조적 및 문화적으로 행해지는 간접적인 폭력 또한 폭력으로 간주한다. 갈퉁은 이러한 직, 간접적인 폭력이 모두 종식되어야 진정한 평화를 성취할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 4, '갈퉁', '갈퉁은 직접적 폭력을 제거함으로써 인간 존엄 실현의 조건이 완비된다고 주장한다.', false, '갈퉁에 따르면 직접적 폭력의 제거만으로는 인간 존엄의 실현에 필요한 조건이 모두 갖춰졌다고 볼 수 없다. 즉 간접적 폭력까지 모두 제거되어야 한다는 것이다. 따라서 갈퉁은 인간 존엄이 직, 간접적 폭력 일체가 사라진 후, 혹은 사라지는 과정에서 점차 실현된다고 본다.'),
    (gen_random_uuid()::text, set_id, 5, '갈퉁', '갈퉁은 폭력의 예방 없이는 적극적 평화를 실현할 수 없다고 주장한다.', true, '갈퉁은 소극적 평화(예:전쟁 부재)를 넘어서, 구조적 문화적 폭력까지 해소된 상태를 적극적 평화로 규정하며, 이러한 평화를 이루기 위해서는 단순히 폭력을 막는 것이 아니라, 폭력이 일어날 가능성을 미연에 차단하는 예방적 처방이 필요하다고 본다.'),
    (gen_random_uuid()::text, set_id, 6, '갈퉁', '갈퉁은 직접적인 폭력의 제거가 간접적인 폭력의 제거보다 중요하다고 주장한다.', false, '갈퉁은 직접적 폭력과 구조적 폭력의 제거가 모두 중요하다고 본다. 왜냐하면, 직접적 폭력, 구조적 폭력, 문화적 폭력은 서로 강화되고 상호 연관되어 있기 때문이다.'),
    (gen_random_uuid()::text, set_id, 7, '갈퉁', '갈퉁은 모든 전쟁의 종식은 진정한 평화 실현의 필수 조건이라고 주장한다.', true, '갈퉁에게 진정한 평화란 직접적·구조적·문화적 폭력의 종식 혹은 그 과정에서 실현되는 것이다. 따라서 직접적 폭력인 전쟁의 종식은 진정한 평화를 실현하기 위해 반드시 필요한 조건이다.'),
    (gen_random_uuid()::text, set_id, 8, '갈퉁', '갈퉁은 모든 전쟁의 종식은 적극적 평화의 실현을 보장한다고 주장한다.', false, '전쟁 종식만으로 적극적 평화가 보장되는 것은 아니다. 전쟁이 끝나 직접적 폭력이 사라져도, 빈곤 차별 착취 등의 구조적 문화적 폭력이 여전히 남아 있을 수 있다.'),
    (gen_random_uuid()::text, set_id, 9, '갈퉁', '갈퉁은 국제 평화 개념은 국가 간에 전쟁이 없는 상태로 국한되어야 한다고 주장한다.', false, '갈퉁은 평화를 단순히 전쟁이 없는 상태(소극적 평화)에만 국한하지 않고, 구조적 문화적 폭력까지 없는 적극적 평화를 지향한다.'),
    (gen_random_uuid()::text, set_id, 10, '갈퉁', '갈퉁은 폭력의 사용은 어떠한 경우에도 허용될 수 없다고 주장한다.', true, '갈퉁은 평화는 평화적 수단으로만 달성해야 한다고 보며, 폭력을 수단으로 삼는 일은 어떠한 경우에도 허용되지 않는다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 11, '갈퉁', '갈퉁은 인명의 살상을 동반하는 어떠한 전쟁도 정의롭지 않다고 주장한다.', true, '군사적 물리적 폭력으로서의 전쟁은 갈퉁이 말하는 직접적 폭력의 대표 사례이다. 갈퉁은 평화를 달성하기 위한 전쟁도 용납하지 않으며, 평화는 오로지 평화적 수단으로만 달성해야 한다는 강경한 입장을 취한다.'),
    (gen_random_uuid()::text, set_id, 12, '갈퉁', '갈퉁은 평화를 위한 정의 전쟁은 도덕적 비판의 대상이 아니라고 주장한다.', false, '갈퉁은 정의 전쟁이라는 개념도 폭력을 정당화하기 어렵다고 본다. 즉 갈퉁은 평화를 달성하기 위한 전쟁도 용납하지 않는다.'),
    (gen_random_uuid()::text, set_id, 13, '갈퉁', '갈퉁은 진정한 평화는 인간 안보가 확장된 국가 안보를 통해 완성된다고 주장한다.', false, '갈퉁은 평화의 개념을 국가 안보 차원에서 인간 안보 차원으로 확장한다.'),
    (gen_random_uuid()::text, set_id, 14, '갈퉁', '갈퉁은 평화의 실현을 위해서는 정치 제도의 개선이 필수적이라고 주장한다.', true, '갈퉁에 따르면, 구조적 폭력은 정치 경제 사회 제도에서 비롯될 수 있으므로, 정치 제도 개선은 적극적 평화를 실현하는 필수 요건이 된다.'),
    (gen_random_uuid()::text, set_id, 15, '갈퉁', '갈퉁은 편견 극복을 위한 교육은 적극적 평화를 실현하는 방법이라고 주장한다.', true, '갈퉁은 문화적 폭력이 차별, 편견 등을 재생산한다고 지적하며, 이를 해소하기 위해서는 교육과 인식 변화가 필수적이라고 본다.'),
    (gen_random_uuid()::text, set_id, 16, '칸트', '칸트는 국제 사회의 평화를 유지할 수 있는 방법이 존재한다고 주장한다.', true, '칸트는 평화 연맹과 같은 국제기구를 통하여 국제 사회의 평화를 유지할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 17, '칸트', '칸트는 영구 평화를 위한 진정한 의미의 정치는 도덕에 충실해야 한다고 주장한다.', true, '칸트는 도덕 없는 정치가 영구 평화를 이룰 수 없다고 보며, 도덕적 입법과 정치가 결합해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 18, '칸트', '칸트는 세계 평화는 실제로는 불가능하나 정치적 의무로 설정해야 한다고 주장한다.', false, '칸트는 세계 평화가 실제로는 불가능하다고 간주해서는 안 된다고 본다. 칸트는 세계 평화가 달성하기 어려운 하나의 이상이지만 경험적으로 실행 가능하다고 전제하고 영구 평화를 추구해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 19, '칸트', '칸트는 타국의 내정에 대한 강제 개입은 평화를 위해서만 허용된다고 주장한다.', false, '칸트는 평화라는 명분으로도 타국 내정에 무력 개입하는 것을 금지해야 한다고 보며, 강제 간섭 자체가 평화 원리에 반한다고 본다. 칸트 입장에서는 국가도 도덕적 인격으로 대우받아야 한다.'),
    (gen_random_uuid()::text, set_id, 20, '칸트', '칸트는 영원한 평화를 위해 국가는 어떠한 국채도 발행해서는 안 된다고 주장한다.', false, '칸트는 분쟁과 관련한 어떠한 국채도 발행해서는 안 된다는 것이지, 모든 국채를 발행해서는 안 된다는 의미가 아니다. 칸트는 도로의 개선, 새로운 주거 마련, 흉년에 대비한 창고 매입 등을 위한 국채의 발행은 허용될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 21, '칸트', '칸트는 국가 간 신뢰를 불가능하게 하는 적대 행위를 해서는 안 된다고 주장한다.', true, '칸트는 비록 국가 간의 전쟁이 발발하더라도, 전쟁 기간 동안 장래의 평화 시기에 상호 신뢰를 불가능하게 할 것이 틀림없는 적대 행위를 해서는 안 된다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 22, '칸트', '칸트는 국가 간 적대 행위가 종식되어야 영원한 평화 실현이 가능하다고 주장한다.', true, '칸트는 전쟁이나 적대 상태가 계속된다면 영구 평화는 성립할 수 없으므로, 국가 간 적대 행위 중단은 평화를 지향하기 위한 필수적 전제라고 본다. 그러나 단순히 분쟁을 해소하는 것만으로는 영구 평화를 보장하는 것이 불가능하다.'),
    (gen_random_uuid()::text, set_id, 23, '칸트', '칸트는 국가 간 분쟁의 해소가 영원한 평화 실현의 충분조건은 아니라고 주장한다.', true, '칸트는 국가 간 분쟁 해소가 영구 평화의 충분조건은 아니라고 본다. 칸트에 따르면, 영구 평화 실현은 분쟁 해소를 넘어, 인류가 끊임없이 추구해야 할 과제에 해당한다.'),
    (gen_random_uuid()::text, set_id, 24, '칸트', '칸트는 국가 간 적대 행위 중단이 영구적 평화를 보장하는 것은 아니라고 주장한다.', true, '칸트는 국가 간 적대 행위 중단만으로는 영구 평화가 보장되지 않는다고 본다. 영구 평화 실현은 분쟁 해소를 넘어, 인류가 끊임없이 추구해야 할 과제에 해당한다.'),
    (gen_random_uuid()::text, set_id, 25, '칸트', '칸트는 전쟁은 국제 평화를 실현하기 위한 최후의 정치적 행위로서 정당화된다고 주장한다.', false, '칸트는 전쟁을 통해 정의나 평화를 실현한다는 사고방식을 부정하며, 평화는 궁극적으로 도덕적·법적 실천에 의해 마련되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 26, '칸트', '칸트는 평화의 실현을 위해서는 정치 제도의 개선이 필수적이라고 주장한다.', true, '칸트는 개별 국가가 공화적 체제를 갖추도록 정치 체제의 개선, 변화가 수반되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 27, '칸트', '칸트는 영구 평화를 위해 정치 체제의 변화가 수반될 필요는 없다고 주장한다.', false, '칸트는 개별 국가가 공화적 체제를 갖추도록 정치 체제의 개선, 변화가 수반되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 28, '칸트', '칸트는 개별 국가의 시민적 정치 체제는 공화적 체제를 갖추어야 한다고 주장한다.', true, '칸트는 개별 국가가 공화적 체제를 갖추도록 정치 체제의 개선, 변화가 수반되어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 29, '칸트', '칸트는 시민법 체제가 한 국가의 대내적 정치 제도를 지정할 수는 없다고 주장한다.', false, '칸트는 시민법 체제가 한 국가의 대내적 정치 제도를 지정한다고 본다. 칸트는 시민법을 통해 서로가 서로에게 영향을 끼치는 사람들 모두가 공민적 체제에 속해야 하며, 사람들이 시민법의 적용 아래에 있어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 30, '칸트', '칸트는 국가들의 통치 형태와는 상관없이 완전한 영구 평화는 가능하다고 주장한다.', false, '칸트는 국가의 통치 형태가 공화정이어야 한다고 본다. 일례로 전제 국가에서는 진정한 영구 평화가 실현되기 어렵다고 본다. 왜냐하면 전제 국가에서는 통치자 마음대로 전쟁을 시행할 수 있는 반면 공화정은 전쟁 시행 여부를 국민의 동의에 기반하여 결정한다.'),
    (gen_random_uuid()::text, set_id, 31, '칸트', '칸트는 강제력을 갖춘 평화 조약은 영구적 평화를 보장할 수 있다고 주장한다.', false, '칸트는 강제력을 갖춘 평화 조약만으로는 전쟁 상태가 근본적으로 종식되지 않는다고 보고, 공화적 체제, 국제 연맹 등 도덕적, 제도적 조건이 함께 갖춰져야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 32, '칸트', '칸트는 국제 연맹은 독립된 국가처럼 주권을 행사할 수 없다고 주장한다.', true, '칸트가 말하는 평화 연맹은 주권 국가들의 자발적 연합체로서, 독자적 주권을 갖는 단일 국가 형태가 아니다. 칸트는 여러 국가가 하나로 합쳐지는 단일 국가화에 반대하며, 개별 국가의 독립성과 주권을 존중하는 연맹을 제안한다.'),
    (gen_random_uuid()::text, set_id, 33, '칸트', '칸트는 국제 연맹은 국가와 같은 주권적 권력으로 기능해야 한다고 주장한다.', false, '칸트가 말하는 평화 연맹은 주권 국가들의 자발적 연합체로서, 독자적 주권을 갖는 단일 국가 형태가 아니다. 칸트는 여러 국가가 하나로 합쳐지는 단일 국가화에 반대하며, 개별 국가의 독립성과 주권을 존중하는 연맹을 제안한다.'),
    (gen_random_uuid()::text, set_id, 34, '칸트', '칸트는 세계 평화의 정착을 위해 개별 국가의 주권은 폐지되어야 한다고 주장한다.', false, '칸트가 말하는 평화 연맹은 주권 국가들의 자발적 연합체로서, 독자적 주권을 갖는 단일 국가 형태가 아니다.'),
    (gen_random_uuid()::text, set_id, 35, '칸트', '칸트는 평화 연맹의 수립 과정에서 국가 간 합병은 배제된다고 주장한다.', true, '칸트가 말하는 평화 연맹은 주권 국가들의 자발적 연합체로서, 독자적 주권을 갖는 단일 국가 형태가 아니다.'),
    (gen_random_uuid()::text, set_id, 36, '칸트', '칸트는 평화 연맹은 모든 전쟁의 영구적 종식을 목표로 한다고 주장한다.', true, '칸트는 전쟁이 국제 정의를 실현할 수 없다고 보며, 모든 전쟁의 종식을 요구한다. 평화 연맹은 모든 전쟁의 종식을 목표로 하며, 이러한 연맹이 점차 모든 국가에게로 확대되어야 한다는 것이 칸트의 입장이다.'),
    (gen_random_uuid()::text, set_id, 37, '칸트', '칸트는 전쟁은 국제 정의를 실현하기 위한 수단이 될 수 없다고 주장한다.', true, '칸트는 전쟁이 국제 정의를 실현할 수 없다고 보며, 모든 전쟁의 종식을 요구한다.'),
    (gen_random_uuid()::text, set_id, 38, '칸트', '칸트는 모든 전쟁의 종식은 진정한 평화 실현의 필수 조건이라고 주장한다.', true, '칸트는 전쟁이 국제 정의를 실현할 수 없다고 보며, 모든 전쟁의 종식을 요구한다.'),
    (gen_random_uuid()::text, set_id, 39, '칸트', '칸트는 국제적 사회 계약을 통해 연맹 체제를 단일 국가로 전환해야 한다고 주장한다.', false, '칸트는 연맹 체제를 단일 국가로 전환해야 한다고 보지 않는다. 칸트는 영구 평화를 위해서 이상적으로는 국제국가가 건설되어야 한다고 보지만, 현실적으로는 국제 연맹을 체결하는 것이 최선이라고 본다.'),
    (gen_random_uuid()::text, set_id, 40, '칸트', '칸트는 항구적 평화는 국가 간의 세력 균형으로 실현되어야 한다고 주장한다.', false, '칸트는 세력 균형이 영구적 평화를 보장해 주지 않는다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '칸트', '칸트는 세계 시민법은 보편적 우호 조건을 규정하는 데 국한되어야 한다고 주장한다.', true, '칸트는 세계 시민법이 보편적 우호 조건을 규정하는 데 국한되어야 한다고 보는데, 여기서 보편적 우호란 외국인에 대한 보편적 우호를 의미한다.'),
    (gen_random_uuid()::text, set_id, 42, '칸트', '칸트는 국가 간 평등한 관계에 기반을 둔 세계 시민법은 보편적 우호의 조건들에 국한되어야 한다고 주장한다.', true, '칸트는 각 국가들이 모두 도덕적 인격으로서 평등하다고 보며, 세계 시민법은 당연히 이에 기반한다고 본다.'),
    (gen_random_uuid()::text, set_id, 43, '칸트', '칸트는 이방인이 갖는 환대의 권리는 조건부적으로 보장된다고 주장한다.', true, '칸트는 기본적으로 외국인이 평화적으로 처신하는 한, 이들에게 적대적이어서는 안 된다고 본다. 이러한 환대권은 외국인이 평화적으로 처신하는 한 보장된다는 점에서 조건적인 권리이다.'),
    (gen_random_uuid()::text, set_id, 44, '칸트', '칸트는 국가는 모든 외국인에 대해 호의적으로 대할 필요는 없다고 주장한다.', true, '환대권은 외국인이 평화적으로 처신하는 한 보장된다는 점에서 조건적인 권리이다. 만일 평화적으로 처신하지 않는 외국인에 대해서는 호의적인 태도를 보일 필요가 없을 것이다.'),
    (gen_random_uuid()::text, set_id, 45, '칸트', '칸트는 세계 시민법은 이방인의 환대권과 영속적 체류권을 보장한다고 주장한다.', false, '환대권은 영속적인 체류권으로 확장될 수 없다. 즉 외국인이 다른 국가에 일시적으로 방문할 수는 있어도, 그것이 영속적으로 체류할 권리를 의미하지는 않는다는 것이다.'),
    (gen_random_uuid()::text, set_id, 46, '칸트', '칸트는 세계 시민법은 인권 보장이 아닌 영구 평화를 위한 것이라고 주장한다.', false, '세계 시민법은 개개인의 인권을 보장하는 규칙으로서, 영구 평화를 위한 것이기도 하다.');
    INSERT INTO "OxQuizSet"(id, title, thumbnail, "categoryId", difficulty, "totalQuestions", "isPopular", "createdAt")
  INSERT INTO "OxQuestion"(id, "oxQuizSetId", "order", section, question, answer, explanation) VALUES
    (gen_random_uuid()::text, set_id, 1, '싱어', '싱어는 원조 대상을 선정할 때 상대적 빈곤이 기준이 되는 것은 아니라고 주장한다.', true, '싱어는 일반적으로 상대적 빈곤이 아니라, 절대적 빈곤을 고려하여 원조 대상을 선정해야 한다고 보았다. 싱어는 다만 공리주의자이므로 상대적 빈곤을 고려할 때 절대적 빈곤을 더 잘 해결할 수 있는 경우가 존재한다면, 그러한 경우까지 전적으로 배제하는 것은 아니다.'),
    (gen_random_uuid()::text, set_id, 2, '싱어', '싱어는 원조를 행하지 않는 것이 비난의 대상이 될 수는 없다고 주장한다.', false, '싱어는 해외 원조를 하지 않았다고 해서 비난의 대상이 되지 않는 자선적 행위로 간주하는 통념에 대해 반대한다.'),
    (gen_random_uuid()::text, set_id, 3, '싱어', '싱어는 빈곤으로 고통받는 사람을 원조하지 않아도 되는 경우가 있다고 주장한다.', true, '싱어는 해외 원조를 보편적인 의무로 간주하나, 원조 대상이 절대 빈곤이 아니라 단지 상대적 빈곤으로 고통받는 사람은 해외 원조 의무의 대상이 아니다. 또한 원조 주체가 원조 능력이 부족한 경우도 있다.'),
    (gen_random_uuid()::text, set_id, 4, '싱어', '싱어는 원조는 도덕적 구속력이 배제된 개인적 선택의 문제라고 주장한다.', false, '싱어가 부정할 진술이다. 싱어는 원조를 도덕적 구속력이 배제된 개인의 선택 영역으로 보지 않는다. 싱어는 원조가 전 지구적인 의무이며, 만인이 공정하게 분담해야 할 책임이라고 본다.'),
    (gen_random_uuid()::text, set_id, 5, '싱어', '싱어는 자원이 풍부한 국가는 원조의 대상이 될 수 없다고 주장한다.', false, '싱어는 자원이 풍부한 국가 중에서도 원조의 대상이 될 수 있는 국가가 존재한다고 본다. 가령, 다수의 아프리카 국가들은 석유, 금, 다이아몬드, 희토류 등 자원이 풍부하지만, 대부분 국민들이 빈곤한 국가이다.'),
    (gen_random_uuid()::text, set_id, 6, '싱어', '싱어는 원조는 비용 대비 편익을 계산하여 이루어져야 한다고 주장한다.', true, '싱어는 공리주의자로서, 비용 대비 편익 계산을 해외 원조 시에도 고려해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 7, '싱어', '싱어는 원조 주체의 경제력에 대한 고려 없이 원조가 실행되어서는 안 된다고 주장한다.', true, '싱어는 공리주의자로서 관련자 모두의 이익을 고려하여 원조를 시행해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 8, '싱어', '싱어는 다른 나라에 빈곤한 사람들이 있다는 사실은 필연적으로 원조의 의무를 정당화한다고 주장한다.', true, '절대 빈곤으로 고통받고 있는 사람이 존재하므로, 사치품을 살 정도로 경제적으로 여유가 있는 시민들에게는 해외 원조의 의무가 부과된다.'),
    (gen_random_uuid()::text, set_id, 9, '싱어', '싱어는 원조의 대상은 지리적 근접성을 기준으로 결정되어야 한다고 주장한다.', false, '싱어는 국가의 경계나 지리적 근접성, 종교, 민족과 같은 요소를 넘어서 극단적 빈곤을 겪는 사람들이라면, 해외 원조의 대상이 될 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 10, '싱어', '싱어는 자국민에 대한 우선적 원조가 도덕적으로 정당한 경우도 있다고 주장한다.', true, '싱어는 자국민에 대한 우선적 원조가 도덕적으로 중요한 경우도 있다고 주장했다. 그러한 판단은 공리주의적 관점에서 비용 대비 편익 계산을 통해서 이뤄질 것이다. 만약 자국민을 원조하는 것이 타국민을 원조하는 것보다 공리주의적으로 타당할 경우에는 자국민에 대한 우선적 원조가 도덕적으로 타당할 수 있을 것이다.'),
    (gen_random_uuid()::text, set_id, 11, '싱어', '싱어는 모든 사람은 빈곤 해소를 위한 원조에 동등한 부담을 져야 한다고 주장한다.', false, '싱어는 모든 사람이 해외 원조에 동등한 부담을 지녀야 하는 것이 아니라고 본다. 예를 들어 가난한 나라의 절대 빈곤에 처한 사람들이 부유한 나라의 경제적 여유가 있는 사람들과 해외 원조에 대한 동등한 부담을 져야 하는 것이 아니다.'),
    (gen_random_uuid()::text, set_id, 12, '싱어', '싱어는 원조를 통해 방지할 해악보다 더 큰 희생이 발생한다면 원조가 중단될 수 있다고 주장한다.', true, '싱어는 공리주의자이므로 원조를 통해 방지할 해악보다 더 큰 희생이 발생한다면 원조는 중단될 수 있다고 본다. 가령, 원조 주체의 경제력이 충분하지 않음에도 불구하고 계속 원조를 시행한다면 원조 주체에게는 큰 희생이 따를 것이다.'),
    (gen_random_uuid()::text, set_id, 13, '싱어', '싱어는 원조 주체와 대상의 이익을 평등하게 고려해야 한다고 주장한다.', true, '싱어는 이익 평등 고려에 따라 해외 원조를 해야 한다고 주장한다. 그러므로 원조 주체와 대상의 이익을 평등하게 고려해야 한다. 이때 유의해야 할 것은 싱어가 원조 주체와 대상을 평등하게 대우해야 한다고 주장한 것은 아니라는 점이다.'),
    (gen_random_uuid()::text, set_id, 14, '싱어', '싱어는 원조는 국가 간 복지 수준의 조정을 목표로 해야 한다고 주장한다.', false, '싱어는 공리주의와 세계 시민주의의 관점에서 빈곤으로 고통 받고 있는 개인을 도와야 한다고 주장한다. 그런데, 국가 간 복지 수준을 조정하는 것은 그러한 목적에 부합할 수도 있지만, 부합하지 않을 수도 있으므로, 싱어가 해외 원조의 목적으로 설정할 수 없다.'),
    (gen_random_uuid()::text, set_id, 15, '싱어', '싱어는 원조의 결과로 모든 사람이 경제적 이익을 얻어야만 한다고 주장한다.', false, '싱어는 원조의 결과로 모든 사람이 경제적 이익을 얻어야만 한다고 주장하지 않았다. 인류 전체의 공리가 증가해야 한다고 주장했을 뿐이다. 가령 한 개인이 값비싼 사치품을 구매하는 대신 그 돈을 해외 원조하는 데 지출한다면, 그 개인의 입장에서 볼 때 경제적으로 손해를 입은 것이겠지만 인류 전체의 공리는 증가했을 것이다.'),
    (gen_random_uuid()::text, set_id, 16, '싱어', '싱어는 원조의 목적은 인류의 고통 감소와 행복 증진이라고 주장한다.', true, '싱어는 해외 원조의 목적을 인류 전체의 행복 증진이라고 보며, 집합적인 개념으로써의 인류 전체의 고통 감소와 행복 증진을 주장한다.'),
    (gen_random_uuid()::text, set_id, 17, '싱어', '싱어는 원조의 의무는 국경을 초월한 세계 시민적 의무라고 주장한다.', true, '싱어는 세계 시민주의적 관점에 입각한 전 지구적 차원의 원조를 강조한다. 가령 부유한 국가에 살고 있는 경제적으로 여유로운 시민은 국경을 초월하여 해외의 가난한 나라에 살고 있는 절대 빈곤에 처한 사람을 원조해야 할 의무가 있다.'),
    (gen_random_uuid()::text, set_id, 18, '싱어', '싱어는 원조 주체는 원조 결정 시 자기 이익을 고려해야 한다고 주장한다.', true, '싱어에게 원조의 핵심은 큰 희생 없이 해악을 줄일 수 있다면 돕는 것이 의무라는 점이다. 원조 주체가 큰 희생을 겪을 시에는 원조 의무가 없다는 것이 싱어의 입장이다.'),
    (gen_random_uuid()::text, set_id, 19, '싱어', '싱어는 특정 빈곤국에 대한 원조를 중단해야 하는 경우가 있다고 주장한다.', true, '싱어는 특정 빈곤국에 대해 원조가 중단되는 경우가 있다고 주장한다. 가령 공리주의자 싱어의 입장에서는, 원조를 통해 더 큰 희생이 발생한다면 원조가 중단될 수 있다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 20, '싱어', '싱어는 국가 간 부의 불평등이 그 자체로 부정의한 것은 아니라고 주장한다.', true, '싱어는 국가 간 부의 불평등이 그 자체로 부정의한 것은 아니라고 본다. 싱어는 국가 간 부의 불평등을 조정하기 위해 원조하는 것이 아니라 불평등하더라도 인류의 집합적인 이익이 증가한다면 공리주의 관점에서 원조를 시행해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 21, '싱어', '싱어는 사회 내 부조와 해외 원조 사이에 본질적인 차이는 없다고 주장한다.', true, '싱어는 물에 빠진 아이를 구하는 행위와 지구 반대편 굶주린 사람을 돕는 행위를 동일하게 본다. 즉 거리나 영역의 차이가 도덕적 의무를 약화시키지는 않는다고 주장한다. 이러한 의미에서 사회 내 부조와 해외 원조 사이에 본질적인 차이는 없는 것이다.'),
    (gen_random_uuid()::text, set_id, 22, '싱어', '싱어는 해외 원조는 자선이 아닌 당위의 차원에서 실시해야 한다고 주장한다.', true, '싱어는 해외 원조를 선택적 자선이 아닌 도덕적으로 반드시 이행해야 할 의무로 규정한다. 원조를 의무가 아니라 자선의 차원으로 바라보는 사상가는 노직이다.'),
    (gen_random_uuid()::text, set_id, 23, '싱어', '싱어는 원조는 보편적인 의무이지만 조건부적으로 시행될 수 있다고 주장한다.', true, '싱어는 원조의 의무가 공리주의 원칙에 따라 조건부적으로 시행될 수 있는 의무라고 본다. 이는 무조건적으로 원조를 해야하는 것이 아니라, 원조 주체가 원조를 할 수 있는 최소한의 여유가 되어야 한다는 것을 의미한다. 또한 싱어는 애초에 원조의 의무의 대상으로 성립하지 않는 경우가 있다고 보는데, 이는 빈곤자가 단지 상대적 빈곤으로 고통받는 경우와 원조의 효과 자체가 없는 경우이다.'),
    (gen_random_uuid()::text, set_id, 24, '싱어', '싱어는 절대 빈곤 해결을 위한 원조는 보편적 의무로 간주해야 한다고 주장한다.', true, '싱어는 절대 빈곤에서 비롯되는 심각한 고통을 막는 것이 도덕적 의무라고 보며, 이는 모든 사람에게 해당하는 보편적 요구 사항이라고 본다.'),
    (gen_random_uuid()::text, set_id, 25, '싱어', '싱어는 원조는 전 지구적 차원의 윤리적인 의무로 정당화될 수 없다고 주장한다.', false, '싱어의 주장과 정면으로 대치되는 명제이다. 싱어는 전 지구적 차원의 원조를 주장한다. 싱어는 국경이나 거리에 구애받지 않고, 절대 빈곤 해결을 위한 원조를 도덕적 의무로 삼아야 한다고 본다. 즉 싱어의 원조는 세계 시민주의적인 의무인 것이다.'),
    (gen_random_uuid()::text, set_id, 26, '싱어', '싱어는 모든 사람은 세계 모든 이의 복지에 동일한 책임을 져야 한다고 주장한다.', false, '싱어의 주장과 정면으로 대치되는 명제이다. 모든 사람이 세계 모든 이의 복지에 동일한 책임을 져야 한다고 보지 않는다. 또한, 철저한 공리주의 관점에 입각하여 모든 사람의 이익을 증가시키는 것이 아닌, 인류 전체의 이익을 증가시키는 가장 효율적인 원조를 시행해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 27, '싱어', '싱어는 공리의 원리에 따라 인류의 부가 균등할 때까지 원조해야 한다고 주장한다.', false, '싱어는 부의 균등을 해외 원조의 목적으로 보지 않는다. 싱어는 절대 빈곤의 해소와 불필요한 고통 감소를 위해 원조를 시행해야 한다고 보는 것이다.'),
    (gen_random_uuid()::text, set_id, 28, '싱어', '싱어는 공리 증진을 의도하지 않은 원조가 정당할 수 있다고 주장한다.', true, '싱어는 공리주의자로서, 행위의 도덕성을 그 결과로 판단한다. 즉 공리 증진을 직접적으로 의도하지 않은 원조라도, 그것이 인간의 고통을 줄이고 복지를 향상시키는 데 기여한다면 도덕적으로 정당화될 수 있는 것이다.'),
    (gen_random_uuid()::text, set_id, 29, '싱어', '싱어는 기아의 주된 원인은 전 세계 식량 총 생산량의 부족에 있지 않다고 주장한다.', true, '싱어는 오히려 세계가 충분한 양의 식량을 생산하고 있다고 본다. 그는 기아 문제의 원인이 가난한 나라에 대한 무관심에 있다고 주장하며, 기아로 고통받는 사람들의 이익을 동등하게 고려하여 원조를 통해 기아를 극복하고 인류 전체의 행복을 증진시켜야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 30, '싱어', '싱어는 원조의 목적은 인류 전체의 복지 증진이 아니라 정치 체제의 개선이어야 한다고 주장한다.', false, '싱어는 원조의 목적이 인류 전체의 복지 증진(최대 다수의 최대 행복)이므로, 이익 평등 고려 원칙에 따라 모든 사람의 이익을 동등하게 고려해야 한다고 주장한다. 따라서 싱어의 입장에 부합하지 않는 진술이다.'),
    (gen_random_uuid()::text, set_id, 31, '싱어', '싱어는 원조의 의무는 절대 빈곤에 상응하는 도덕적으로 중요한 다른 일을 희생할 것을 원조 주체에게 요구할 수 있다고 주장한다.', false, '싱어에게 원조의 의무는 원조 주체가 도덕적으로 상응하는 중요한 다른 일을 희생하지 않는 범위에서 시행되는 행위이다. 절대 빈곤에 상당하는 도덕적으로 중요한 것을 희생하는 것은 이러한 입장에 부합하지 않는다.'),
    (gen_random_uuid()::text, set_id, 32, '싱어', '싱어는 원조 대상의 고통을 방지하기 위해 원조 주체의 처지 개선이 유보될 수 있다고 주장한다.', true, '싱어에 따르면 원조 대상의 고통을 방지하기 위해, 즉 절대 빈곤을 해결하기 위해 원조 주체의 처지 개선은 유보될 수 있다. 즉 싱어는 경제적으로 여유로운 원조의 주체가 스스로의 처지를 더 좋게 만들기 위해 사치품을 사는 대신 더 많이 기부할 수 있다고 본다.'),
    (gen_random_uuid()::text, set_id, 33, '롤스', '롤스는 원조의 중단 지점을 두는 것은 원조 목적에 위배된다고 주장한다.', false, '롤스는 원조의 중단 지점을 두기 때문에, 옳지 않은 선지이다.'),
    (gen_random_uuid()::text, set_id, 34, '롤스', '롤스는 원조 대상국이 자국의 부정의를 교정하도록 도와야 한다고 주장한다.', true, '롤스는 원조 대상국의 부정의에 직접적으로 개입하는 것이 아니라 원조 대상 국가가 그들의 문제를 스스로 해결하도록 도와주는 것으로, 이 과정에서 원조 대상국에 대해 지나치게 간섭하는 것은 포함되지 않는다.'),
    (gen_random_uuid()::text, set_id, 35, '롤스', '롤스는 정의의 원칙에 따라 운영되는 국가는 원조의 대상이 아니라고 주장한다.', true, '롤스가 긍정할 진술이다. 롤스에게 정의의 원칙에 따라 운영되는 국가는 질서 정연한 사회를 의미한다. 롤스에게 질서 정연한 사회는 해외 원조 의무의 주체이지, 원조를 받는 대상이 아니다.'),
    (gen_random_uuid()::text, set_id, 36, '롤스', '롤스는 자원이 풍부한 국가는 원조의 대상이 될 수 없다고 주장한다.', false, '롤스는 자원이 풍부한 국가라 할지라도, 정치·문화적 체제에 결함이 있다면, 질서 정연한 사회가 되기에는 충분하지 않다고 본다. 롤스에 따르면 이러한 국가는 원조의 대상이 될 수 있다.'),
    (gen_random_uuid()::text, set_id, 37, '롤스', '롤스는 원조는 자원 분포의 우연성의 결과를 조정하려는 것이라고 주장한다.', false, '롤스는 자원이 풍부한 국가가 자원이 부족한 국가에 자원을 나누어주어야 한다고 주장하지 않는다. 즉 자원 분포의 우연성의 결과를 조정해야 한다고 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 38, '롤스', '롤스는 원조를 중단할 수 있는 명확한 목표를 규정해야 한다고 주장한다.', true, '롤스는 해외 원조에 있어 원조의 차단점이 존재한다고 본다. 롤스에 따르면 해외 원조는 고통받는 사회가 적정 수준의 기본 제도들을 갖추어 질서 정연한 사회가 될 때 종료된다.'),
    (gen_random_uuid()::text, set_id, 39, '롤스', '롤스는 사회 제도 개선을 목표로 한 원조는 빈곤 해소에 도움이 될 수 있다고 주장한다.', true, '롤스는 원조의 목적은 독재나 착취와 같이 사회 구조나 제도가 빈곤을 발생시키는 불리한 여건의 사회가 적정 수준의 문화를 형성하여 질서 정연한 사회가 되도록 돕는 것이다.'),
    (gen_random_uuid()::text, set_id, 40, '롤스', '롤스는 원조하는 나라는 원조받는 나라의 인권 개선을 위해 강제력을 행사할 수 있다고 주장한다.', false, '롤스는 원조를 시행하는 국가가 원조 대상국에게 강제력을 행사하는 것은 만민법이 배제하는 바이며, 강제력 사용은 고통받는 국가의 자유와 평등 확보라는 원조의 목적에 위배된다고 본다. 오히려 롤스는 인권을 강조하는 등의 권고나 충고의 방식을 통하여 원조 대상국의 통치자의 행동을 바꾸게 할 수 있어야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 41, '롤스', '롤스는 다른 나라에 빈곤한 사람들이 있다는 사실은 필연적으로 원조의 의무를 정당화한다고 주장한다.', false, '롤스는 고통받는 사회가 질서 정연한 사회로 전환되기 위함에 있어 원조의 의무가 존재하는 것이지, 단지 어떤 사람이 빈곤하다는 이유가 원조의 의무를 정당화하지는 않는다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 42, '롤스', '롤스는 경제적 불평등을 규제하는 원칙은 원조의 근거로 성립한다고 주장한다.', false, '롤스의 입장에서 경제적 불평등을 규제하는 원칙은 일반적으로 차등의 원칙을 의미한다. 롤스는 차등의 원칙을 포함한 국내적 정의에 적용되는 정의의 원칙을 해외 원조에는 적용하지 않는다.'),
    (gen_random_uuid()::text, set_id, 43, '롤스', '롤스는 천연자원이 부족한 빈곤국도 원조 대상에서 제외 가능하다고 주장한다.', true, '롤스는 한 사회의 정치 문화적 발전의 정도는 그 나라의 천연 자원 매장량과 무관하다고 보았다. 롤스에 따르면, 질서 정연한 사회 중에서도 천연 자원이 부족한 빈곤국이 있을 수 있다. 그러한 국가들은 빈곤할 수 있지만, 롤스의 해외 원조 의무의 대상은 아니다.'),
    (gen_random_uuid()::text, set_id, 44, '롤스', '롤스는 원조의 목적은 고통받는 사회에 자유를 확립하는 것이라고 주장한다.', true, '롤스의 원조의 의무는 고통받는 사회에 자유와 평등을 확립함으로써 그 사회가 질서 정연한 사회로 이행할 수 있도록 돕는 의무이다.'),
    (gen_random_uuid()::text, set_id, 45, '롤스', '롤스는 적정 수준의 제도 확립에 막대한 부가 꼭 필요한 것은 아니라고 주장한다.', true, '롤스는 한 사회의 정치 문화적 발전의 정도는 그 나라의 천연 자원 매장량과 무관하다고 보았다. 자원이 부족하다고 해서 질서 정연한 사회가 될 수 없는 경우는 거의 없다. 어떤 사회가 질서 정연한 사회가 되는 결정적 요인은 자원의 수준보다는 정치 문화이다.'),
    (gen_random_uuid()::text, set_id, 46, '롤스', '롤스는 공격적인 사회는 자원이 매우 부족해도 원조 대상이 아니라고 주장한다.', true, '롤스의 입장에서 볼 때 공격적인 사회는 질서 정연하지 않은 사회이지만 불리한 여건으로 고통받는 사회는 아니다. 롤스의 해외 원조 대상은 불리한 여건으로 고통받는 사회이다. 따라서 팽창적이고 공격적인 사회인 무법 국가는 원조의 대상이 아니다.'),
    (gen_random_uuid()::text, set_id, 47, '롤스', '롤스는 독재나 착취로 빈곤한 사회는 원조 대상이 될 수 없다고 주장한다.', false, '롤스는 고통받는 사회를 원조의 대상으로 삼는데, 고통받는 사회는 독재 혹은 착취와 같은 불합리한 사회 구조나 제도가 존재하는 사회이다.'),
    (gen_random_uuid()::text, set_id, 48, '롤스', '롤스는 원조 정책은 지구적 차등 원칙에 근거해야 한다고 주장한다.', false, '롤스는 차등의 원칙을 국내 사회 기본 구조에만 적용되는 원리로 보며, 국제 사회에서 국가 간 부의 불평등을 조정하기 위해 지구적 차등 원칙을 적용해야 한다고 주장하지 않는다.'),
    (gen_random_uuid()::text, set_id, 49, '롤스', '롤스는 국가 간 부의 격차 해소 후에는 원조 의무가 없다고 주장한다.', false, '롤스가 설정한 원조의 차단점은 부의 격차 해소가 아니라 고통받는 사회가 적정 수준의 정치·사회적 제도를 갖추는 지점이다. 국가 간 부 격차가 줄어드는 것은 원조 의무와 직접적인 관련이 없다.'),
    (gen_random_uuid()::text, set_id, 50, '롤스', '롤스는 원조의 목적은 인류 복지 수준의 균등화가 아니라고 주장한다.', true, '롤스에 따르면 해외 원조의 목적은 고통받는 사회가 질서 정연한 사회로 발전하도록 돕는 것이지, 인류의 복지 수준 평등을 달성하기 위함이 아니다. 애초에 인류 복지 수준을 평등하게 만드는 것은 불가능하다.'),
    (gen_random_uuid()::text, set_id, 51, '롤스', '롤스는 특정 빈곤국에 대한 원조를 중단해야 하는 경우가 있다고 주장한다.', true, '롤스는 원조 수혜국, 즉 고통받는 사회가 적정 수준의 기본 제도와 문화를 갖추게 되면 더 이상의 원조가 불필요하다고 보며, 원조를 중단해도 된다고 본다. 이것이 바로 롤스의 차단점 개념이다.'),
    (gen_random_uuid()::text, set_id, 52, '롤스', '롤스는 국가 간 부의 불평등이 그 자체로 부정의한 것은 아니라고 주장한다.', true, '롤스는 국제 사회에서 단순한 부의 차이만으로 정의 여부를 결정하지 않는다. 국가 간 부의 차이는 어느 정도 존재할 수 있으며, 질서 정연한 사회가 되기 위해 필요한 자원량 등은 각 사회의 역사적, 문화적 맥락 등에 따라 달라질 수 있다는 것이 롤스의 입장이다.'),
    (gen_random_uuid()::text, set_id, 53, '롤스', '롤스는 절대 빈곤 해결을 위한 원조는 보편적 의무로 간주해야 한다고 주장한다.', true, '기아나 기본적 생존조차 불가능한 수준의 절대 빈곤 상태는 그 사회가 합당한 정치·사회 체제를 갖출 기본적인 기반마저 결여된 상황일 것이므로 이런 절대 빈곤을 해소하는 원조는 롤스의 입장에서도 보편적 의무로 파악할 수 있다고 이해하면 된다.'),
    (gen_random_uuid()::text, set_id, 54, '롤스', '롤스는 원조 대상국 내부의 불평등 감소를 원조의 목적으로 삼는 것은 불가능하다고 주장한다.', false, '롤스에 따르면 원조 대상국 내의 불평등 감소는 원조의 목적으로 성립할 수 있다. 롤스의 원조의 대상이 되는 고통받는 사회 내에서는 극심한 경제적 불평등이 존재할 수 있고, 인권이 제대로 존중받지 못하므로 인권침해와 같은 불평등이 발생할 수 있기 때문이다.'),
    (gen_random_uuid()::text, set_id, 55, '롤스', '롤스는 원조의 목적은 합당하고 합리적인 제도의 실현과 보존에 있다고 주장한다.', true, '롤스는 원조의 목적이 고통 받는 사회를 질서 정연한 만민의 사회로 가입시키는 것에 있다고 본다. 이러한 것이 가능하려면 사회가 합당하고 합리적으로 조직되고 통치되어야 한다.'),
    (gen_random_uuid()::text, set_id, 56, '롤스', '롤스는 공적 정의관이 규제하지 않는 사회는 원조 대상이 될 수 없다고 주장한다.', false, '롤스는 공적 정의관이 규제하지 않는 사회 중 고통받는 사회는 원조 대상에 해당한다고 본다.'),
    (gen_random_uuid()::text, set_id, 57, '롤스', '롤스는 고통을 겪는 사회가 자국민 인권에 관심을 갖게 원조해야 한다고 주장한다.', true, '롤스는 원조의 궁극적 목적이 고통 받는 사회의 인권의 확립에 있다고 본다. 따라서 롤스는 질서 정연한 사회의 만민들이 인권을 제대로 확립하지 못하고 있는 고통 받는 사회가 자국민의 인권에 관심을 갖도록 하여, 자율성을 갖춘 질서 정연한 만민의 사회가 되도록 원조를 시행해야 한다고 주장한다.'),
    (gen_random_uuid()::text, set_id, 58, '롤스', '롤스는 고통받는 사회가 스스로 정치 문화를 개선하도록 원조해야 한다고 주장한다.', true, '롤스는 고통받는 사회에 온정주의적으로 간섭하지 말고, 그들이 스스로 제도를 개선하고 정치 문화를 발전시킬 수 있도록 도와야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 59, '롤스', '롤스는 원조의 목표를 달성하기 위해서는 국가 간 부의 재분배가 필수적이라고 주장한다.', false, '롤스는 원조의 목표를 달성하기 위해 국가 간 부의 재분배가 필요하다고 주장하지 않는다. 즉, 분배 정의의 원칙은 정의론에 의하여 사회의 기본 구조에 적용되는 개념이라고 이해하여야 한다.'),
    (gen_random_uuid()::text, set_id, 60, '롤스', '롤스는 원조는 원조 대상이 정치적 자율성을 가질 수 있도록 이루어져야 한다고 주장한다.', true, '롤스는 원조 대상인 고통 받는 사회는 정치적 자율성을 가지지 못한다고 본다. 따라서 롤스는 원조가 고통 받는 사회의 인권을 확립하는 목적으로 시행되어야 하며, 고통 받는 사회의 자유와 평등을 확립하여 정치적 자율성을 확보하도록 도움을 주어야 한다고 주장하는 것이다.'),
    (gen_random_uuid()::text, set_id, 61, '롤스', '롤스는 원조 대상 국가에게 인권을 강조하는 것은 원조의 목적 실현을 저해한다고 주장한다.', false, '롤스는 원조의 의무가 기본적 인권에 관한 원칙으로부터 도출되는 인도주의적 의무라고 본다. 기본적 인권에는 생명, 안전, 생존 등에 관한 권리가 포함될 수 있는데, 롤스는 기본권을 존중하며 만민을 관용해야 한다고 본다.'),
    (gen_random_uuid()::text, set_id, 62, '롤스', '롤스는 원조의 목적은 인류 전체의 복지 증진이 아니라 정치 체제의 개선이어야 한다고 주장한다.', true, '롤스는 원조의 목적이 인류 전체의 복지 증진이 아니라 정치 체제의 개선이어야 한다고 본다. 인류 전체의 복지 증진을 원조의 목적으로 삼는 사상가는 싱어이다.'),
    (gen_random_uuid()::text, set_id, 63, '롤스', '롤스는 정치 제도가 수립된 사회는 원조 대상에서 제외된다고 주장한다.', false, '롤스에 따르면, 정치 제도가 수립된 사회라고 할지라도 불리한 여건으로 고통받는 사회라면, 원조 대상에서 제외되지 않는다고 본다.');
